-- Poems batch 100
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('eeaa25f3-29ee-4272-9d73-9962b53675c9','和謝單推宋卿惠詩','黄公度','宋','宋诗','song-poetry','','[]','逃空每喜足音聞，之子相逢真可人。',64,'全唐诗/poet.song.117000.json','["逃空每喜足音聞，之子相逢真可人。", "知友無非大父行，求君須向古人倫。", "蠻烟傾蓋情如故，蜀繭題詩墨尚新。", "文采風流百不俗，更餘筆力挽千鈞。"]'),
('02cbcdb6-cf8a-4575-97a3-845399f17927','寄題方機宜稚川恕齋','黄公度','宋','宋诗','song-poetry','','[]','恕齋且袖經綸手，他日能容吏吐茵。',64,'全唐诗/poet.song.117000.json','["恕齋且袖經綸手，他日能容吏吐茵。", "四壁琴書供宴坐，一言佩服要終身。", "襟懷但令有餘地，刀筆從教不若人。", "想得清尊及閒暇，賓僚相對面生春。"]'),
('5b17830b-3d13-4fa2-b71b-6072f50b5215','官舍閒居','黄公度','宋','宋诗','song-poetry','','[]','朝市競紛華，山林甘寂寞。',110,'全唐诗/poet.song.117000.json','["朝市競紛華，山林甘寂寞。", "要之其間各有趣，飛鳥沖天魚縱壑。", "我本麋鹿姿，誤被簪紳縛。", "男婚女嫁苦逼人，薄宦天涯失身落。", "似吏非吏兮似隠非隠，謂强不强兮謂弱不弱。", "五斗紅腐可以療饑，一室琴書可以自樂。", "負暄捫虱度清晝，未覺嶺南官况惡。"]'),
('db285ff3-4ccd-4d6f-a4ff-e272f31810a7','謝傅參議彥濟惠笋用山谷韻','黄公度','宋','宋诗','song-poetry','','[]','北方九月霜，賓盤無生菜。',120,'全唐诗/poet.song.117000.json','["北方九月霜，賓盤無生菜。", "嶺南信地暖，窮冬竹萌賣。", "君念庾郎貧，繭栗供庖宰。", "中有歲寒姿，真時久不壞。", "前身渭川侯，千畝償宿債。", "珍可配天花，賤不數石芥。", "早薤與晚菘，奴僕望賓介。", "文園酒渴餘，想不厭姑嘬。", "預恐吹作竹，明日東風噫。", "急須驅兒童，傾筐携采采。"]'),
('f6852622-9c7b-4337-8629-439ad17c46f2','桂陽宰胡達信同年見贈三首次韻  其一','黄公度','宋','宋诗','song-poetry','','[]','場屋聲名識子初，氣吞楊孔况其餘。',64,'全唐诗/poet.song.117000.json','["場屋聲名識子初，氣吞楊孔况其餘。", "十年流落猶州縣，千里往來祇簡書。", "卧雨餐風從鞅掌，昂霄聳壑正權輿。", "割雞久屈屠牛手，洗眼天涯看詔除。"]'),
('9e04fd30-2434-46a2-8c73-5a580c3df73e','桂陽宰胡達信同年見贈三首次韻  其二','黄公度','宋','宋诗','song-poetry','','[]','誰能了了學癡兒，身世從教事事違。',64,'全唐诗/poet.song.117000.json','["誰能了了學癡兒，身世從教事事違。", "百不如人甘鷁退，朅來此地看鳶飛。", "低徊共受微官縛，早晚要須三徑歸。", "頼有故人相慰薦，霏霏玉屑坐生輝。"]'),
('fd8e3892-875d-4b86-831a-6471b3db39c6','桂陽宰胡達信同年見贈三首次韻  其三','黄公度','宋','宋诗','song-poetry','','[]','萬事人人咨伯始，他年文采動詞場。',64,'全唐诗/poet.song.117000.json','["萬事人人咨伯始，他年文采動詞場。", "軒墀喜色回天眄，鞍馬青春照地光。", "社燕賓鴻催日月，喬松翠竹飽風霜。", "丈夫勳業莫嫌晚，良驥由來老更驤。"]'),
('0f170195-d088-4490-aa4f-f4234c21539b','題綠陰堂','黄公度','宋','宋诗','song-poetry','','[]','萬里炎荒一草亭，微官挽我落南溟。',64,'全唐诗/poet.song.117000.json','["萬里炎荒一草亭，微官挽我落南溟。", "誰栽古木圍空翠，爲翦卑枝納遠青。", "風雨半天秋縮瑟，江湖滿地客伶俜。", "日長吏散無公事，欹枕看書門晝扃。"]'),
('2fbe2b06-960f-4ba7-bbea-1188b44dcd81','和鄭邦達主簿五絕  其一','黄公度','宋','宋诗','song-poetry','','[]','斗粟折腰真鄙夫，且圖一飽似侏儒。',32,'全唐诗/poet.song.117000.json','["斗粟折腰真鄙夫，且圖一飽似侏儒。", "淵明欲賦歸來引，未免絃歌預計謨。"]'),
('0df24ab8-53e7-44c3-8c1b-d1da13ccf60d','和鄭邦達主簿五絕  其二','黄公度','宋','宋诗','song-poetry','','[]','望重東京憲與香，自憐忝祖寸無長。',32,'全唐诗/poet.song.117000.json','["望重東京憲與香，自憐忝祖寸無長。", "高天厚地容螻蟻，乞與江湖作漫郎。"]'),
('00471bb6-5727-4fd2-a8cc-16a2371321d7','和鄭邦達主簿五絕  其三','黄公度','宋','宋诗','song-poetry','','[]','長倩抱關真碌碌，仲升吐策但平平。',32,'全唐诗/poet.song.117000.json','["長倩抱關真碌碌，仲升吐策但平平。", "頭顱四十已自揣，空負林宗裁鑒明。"]'),
('731943a9-87a2-45d4-92d3-05a70ce49462','和鄭邦達主簿五絕  其四','黄公度','宋','宋诗','song-poetry','','[]','風姿眇眇志堂堂，詩句驚人易數長。',32,'全唐诗/poet.song.117000.json','["風姿眇眇志堂堂，詩句驚人易數長。", "高士行看三府辟，可容枳棘困仇香。"]'),
('27d14584-a18a-4dd6-abaf-a1ef05499736','和鄭邦達主簿五絕  其五','黄公度','宋','宋诗','song-poetry','','[]','邂逅天涯一破顔，緇塵染素客途艱。',32,'全唐诗/poet.song.117000.json','["邂逅天涯一破顔，緇塵染素客途艱。", "休將俗眼輕游子，無數珠璣咳唾間。"]'),
('0f05a906-6269-47f6-9f46-3b2564314d50','賀陸鹽允濟二首  其一','黄公度','宋','宋诗','song-poetry','','[]','商飈送喜滿華軒，喬嶽鍾靈積慶門。',64,'全唐诗/poet.song.117000.json','["商飈送喜滿華軒，喬嶽鍾靈積慶門。", "天上台星對南極，人間佳節是中元。", "一時閩越看前輩，千載機雲見遠孫。", "香火祝公如衛武，他年勳業照乾坤。"]'),
('7fddf390-0101-4533-8b19-d305ab9dda67','賀陸鹽允濟二首  其二','黄公度','宋','宋诗','song-poetry','','[]','大手聊分八使車，腰叢六印益紆徐。',64,'全唐诗/poet.song.117000.json','["大手聊分八使車，腰叢六印益紆徐。", "圜扉鞠草刑無濫，萬竈熬波國有儲。", "航棧蠻琛紛絡繹，權衡選路不崎嶇。", "蒼生久鬰爲霖望，早晚徵書下玉除。"]'),
('f31a1972-5753-478a-a9e7-d2825b30658b','題潮陽石塔寺','黄公度','宋','宋诗','song-poetry','','[]','投檄真成出瘴鄉，籃輿漸喜到僧坊。',32,'全唐诗/poet.song.117000.json','["投檄真成出瘴鄉，籃輿漸喜到僧坊。", "長風解事吹江雨，乞與行人五月凉。"]'),
('67b3df23-4db0-4445-9d3e-4c51ac469218','與方稚川','黄公度','宋','宋诗','song-poetry','','[]','南來厭見跕飛鳶，之子相逢意凜然。',64,'全唐诗/poet.song.117000.json','["南來厭見跕飛鳶，之子相逢意凜然。", "未用天涯歎淪落，要知幕府盛才賢。", "清譚霏屑論交地，疊鼓喧江送別筵。", "帆腹漸肥人漸遠，離愁長在夕陽邊。"]'),
('6c1e7a4d-d6fc-4edf-8df4-75ca883a8227','與洪景伯','黄公度','宋','宋诗','song-poetry','','[]','快筆三江倒，宏材太室須。',72,'全唐诗/poet.song.117000.json','["快筆三江倒，宏材太室須。", "平生閲人久，所識似君無。", "嶺海非長策，乾坤頼壯圖。", "殷勤將壽斚，邂逅即亨衢。", "老驥心猶在，饑鷹寒易呼。", "何時殿門外，握手話江湖。"]'),
('948c5d36-7c86-47e0-827c-78229a6b877a','題師吳堂','黄公度','宋','宋诗','song-poetry','','[]','夫子賢堯舜，老彭嘗竊比。',240,'全唐诗/poet.song.117000.json','["夫子賢堯舜，老彭嘗竊比。", "郯子及師襄，下問曾不恥。", "河汾一書生，自謂聖復起。", "西京投閣士，敢與孟軻齒。", "古人取名廉，後人取名侈。", "誰知今人中，復見古君子。", "方君帥南越，千載少倫擬。", "燕居榜師吳，一謙具四美。", "隠之經石門，得名一杯水。", "伯始萬事優，可但清而已。", "官曹服公德，廉仁革貪鄙。", "民俗陶公化，淳厚勝姦宄。", "蠻獠畏公威，折箠制千里。", "老猾憚公明，束手敢干紀。", "三城有餘力，一堂仍舊址。", "裘带自清閒，賓僚多燕喜。", "惟昔開元相，勳業照青史。", "胸蟠活國計，試手曾向此。", "我公廊廟具，勞外亦久矣。", "尺一趣歸裝，高蹈廣平軌。"]'),
('cf2fc28c-f17d-4121-b2c6-8c96ed0d3840','題七星巖','黄公度','宋','宋诗','song-poetry','','[]','天上何時落斗星，化爲巨石羅翠屏。',64,'全唐诗/poet.song.117000.json','["天上何時落斗星，化爲巨石羅翠屏。", "洞拆三叉盤空曲，壁立萬仞穿青冥。", "客尋舊路不知處，龍去千載猶聞腥。", "欲訪僊子問真訣，巖扃寂寂水泠泠。"]'),
('32720414-8fa2-4ca0-8b2b-6d01ca237f06','赴南恩道間和楊體南三首  其一','黄公度','宋','宋诗','song-poetry','','[]','再歲大江濱，了無功可程。',48,'全唐诗/poet.song.117000.json','["再歲大江濱，了無功可程。", "行行看絕塞，錄錄更專城。", "不作安巢鳥，應慚出谷鶑。", "頼同草玄手，時抱一經橫。"]'),
('40ea336d-c481-4615-ac6f-2d36ded3100b','赴南恩道間和楊體南三首  其二','黄公度','宋','宋诗','song-poetry','','[]','身任東西南北居，心安到處即吾廬。',32,'全唐诗/poet.song.117000.json','["身任東西南北居，心安到處即吾廬。", "窮途俗眼休相薄，沮洳焉知無大魚。"]'),
('aeafba82-18f0-4a49-a64b-3df2b3d696ce','赴南恩道間和楊體南三首  其三','黄公度','宋','宋诗','song-poetry','','[]','白鷗應怪舊盟寒，斗粟低佪真强顔。',32,'全唐诗/poet.song.117000.json','["白鷗應怪舊盟寒，斗粟低佪真强顔。", "更度桑乾隔并土，不堪回首舊家山。"]'),
('bad23d33-4cce-4cb1-80ec-3d699629d2ef','邵監携詩相訪用集中閒居韻爲謝','黄公度','宋','宋诗','song-poetry','','[]','知君琢句用功深，屹立長城不受侵。',64,'全唐诗/poet.song.117000.json','["知君琢句用功深，屹立長城不受侵。", "紙上雲烟驚老眼，筆端風雨起予心。", "萬里初逢談衮衮，一尊相對樹陰陰。", "斯文入手豈易得，况復逃空喜足音。"]'),
('700ab117-4fbe-44b1-a8ad-a5a004603a9e','再用韻書懷','黄公度','宋','宋诗','song-poetry','','[]','行行漸入瘴鄉深，官事從人笑我侵。',64,'全唐诗/poet.song.117000.json','["行行漸入瘴鄉深，官事從人笑我侵。", "越俎代庖真有愧，逢場作戲本無心。", "賓僚暇日一杯酒，杖屨西園十畝陰。", "政爾無能落閒處，且從猿鳥覓知音。"]'),
('797d2e59-04ee-4a57-808d-3cdd0ef35d94','西園二首  其一','黄公度','宋','宋诗','song-poetry','','[]','清樾纔十畝，炎陬別一天。',48,'全唐诗/poet.song.117000.json','["清樾纔十畝，炎陬別一天。", "華堂依怪石，老木插飛烟。", "長夏絕無暑，乘風幾欲僊。", "心閒境自勝，底處覓林泉。"]'),
('814f548e-8b64-48f4-9790-eae89044261c','西園二首  其二','黄公度','宋','宋诗','song-poetry','','[]','意得壺觴外，心清杖屨間。',48,'全唐诗/poet.song.117000.json','["意得壺觴外，心清杖屨間。", "簿書休吏早，花鳥向人閑。", "舊隠在何許，倦遊殊未還。", "天涯頼有此，退食一開顔。"]'),
('69024432-f3f3-497e-af80-c8be13f0cde8','和邵觀復見贈','黄公度','宋','宋诗','song-poetry','','[]','詩才千丈清且嵬，筆力萬牛挽不回。',256,'全唐诗/poet.song.117000.json','["詩才千丈清且嵬，筆力萬牛挽不回。", "平生用心有根柢，丱角指南得天才。", "江西波瀾浩如海，一派流落天南垓。", "久謂升堂胔已嚌，可是持鼓門過雷。", "詩能窮人豈其理，人窮乃工於詩爾。", "不妨俗眼自青白，第恐獠音無正始。", "俛首誰能兄孔方，高談直欲妻法喜。", "眼高未伏下孔楊，渠肯碌碌數餘子。", "我無寸長班俊髦，狐裘之傍羞縕袍。", "所得虛名真畫餠，朅來窮海試鉛刀。", "書生習氣掃未盡，畫諾閉門思和陶。", "錐處囊中穎立見，君欲逃名何可逃。", "君家故侯青門東，人物於今有祖風。", "落拓一官姑吏隠，敏捷千首追詩翁。", "何者蹄涔留尺鯉，未辦斗水活蛟龍。", "丈夫功業不嫌晚，政恐夫君甘養蒙。"]'),
('de47cc2b-14a2-4908-a9fc-275ef06e0b2c','西園招陳彥招同飲','黄公度','宋','宋诗','song-poetry','','[]','稻粱未飽且紛紛，鴻鵠低徊雞鶩羣。',64,'全唐诗/poet.song.117000.json','["稻粱未飽且紛紛，鴻鵠低徊雞鶩羣。", "萬里歸心閩嶠月，十年旅夢瘴溪雲。", "隣諳好事頻賒酒，家不全貧肯賣文。", "未用天涯歎離索，一尊滿意說桑枌。"]'),
('7a4ca08b-9588-4097-a382-f2da0a5a227d','再用韻','黄公度','宋','宋诗','song-poetry','','[]','斗粟驅人墮世紛，卯申鳬鶩動成羣。',64,'全唐诗/poet.song.117000.json','["斗粟驅人墮世紛，卯申鳬鶩動成羣。", "桁楊閒卧吏休日，尊俎清譚士集雲。", "久矣蠻荒真下策，信哉鄒魯號多文。", "酒酣預約雞豚社，會見婆娑故國枌。"]'),
('afc3b4c8-1035-46e7-9ad5-7a50ca2e809e','鑷白','黄公度','宋','宋诗','song-poetry','','[]','昨夜庭梧滿意凉，秋風不貸鬢邊霜。',32,'全唐诗/poet.song.117000.json','["昨夜庭梧滿意凉，秋風不貸鬢邊霜。", "等閒鑷白了時節，書策縱橫日上廊。"]'),
('ee391fd4-a6b3-40ad-b4a0-fd5f62430f71','秋城晚望','黄公度','宋','宋诗','song-poetry','','[]','斷續悲笳起麗譙，冥冥晚色四山椒。',64,'全唐诗/poet.song.117000.json','["斷續悲笳起麗譙，冥冥晚色四山椒。", "隔江人散虛分米，十里津喧蜑趁潮。", "夕照含山心悄愴，西風動地鬢飄蕭。", "低頭自笑微官縛，東望滄溟歸路遥。"]'),
('14901bad-aafa-40dd-af6b-1da7fda61800','秋旱祈雨','黄公度','宋','宋诗','song-poetry','','[]','萬頃膏腴欲圻龜，禱祠曾不補毫釐。',64,'全唐诗/poet.song.117000.json','["萬頃膏腴欲圻龜，禱祠曾不補毫釐。", "朝廷無事政刑簡，天地何心嶺海饑。", "絕徼難逢霖雨手，隠憂先到老農眉。", "誰能鞭策卧龍起，乞與滂沱一解頤。"]'),
('4560ada9-ef36-492a-b3cb-f9085ecd46d6','賀鄭漕三首  其一','黄公度','宋','宋诗','song-poetry','','[]','當年畫省與成均，聯璧看君親弟昆。',64,'全唐诗/poet.song.117000.json','["當年畫省與成均，聯璧看君親弟昆。", "清世幾人兼五福，白頭相對備三尊。", "朝班猶識尚書履，時論同推通德門。", "早晚芝函趣歸騎，要令勳業照乾坤。"]'),
('05ed4007-2400-4be3-a7d1-739c5e78b31d','賀鄭漕三首  其二','黄公度','宋','宋诗','song-poetry','','[]','天子欲寬南顧憂，繡衣曾是舊人求。',64,'全唐诗/poet.song.117000.json','["天子欲寬南顧憂，繡衣曾是舊人求。", "山川不改元風采，父老能言昔政猷。", "襦褲疲民應枕奠，紀綱新度覺錢流。", "生靈一種同天地，雨露何偏十四州。"]'),
('1927b15b-eb94-4cca-876c-cc255ecbe899','賀鄭漕三首  其三','黄公度','宋','宋诗','song-poetry','','[]','東京望重兩儒先，經術傳家幾百年。',64,'全唐诗/poet.song.117000.json','["東京望重兩儒先，經術傳家幾百年。", "派別九僊緜慶胄，運逢千載毓真賢。", "鼎槐未即登三事，社櫟何知託二天。", "壽考祝公如衛武，願賡淇澳入詩篇。"]'),
('413d160f-b711-4f0c-8a15-ac0a375d76d5','體南先生戒途有日惠詩爲別三復黯然和韻奉送言不逮情  其一','黄公度','宋','宋诗','song-poetry','','[]','可但兒曹學未成，鄙心蔓草要鋤耕。',64,'全唐诗/poet.song.117000.json','["可但兒曹學未成，鄙心蔓草要鋤耕。", "勞君窮海坐賓館，爲我文壇作主盟。", "苜蓿闌干朝飯薄，圖書跌蕩夜譚清。", "便携琴劍東歸得，信有人間桑梓情。"]'),
('f520d654-8cb1-4bc3-ae44-f91d417c5d0b','體南先生戒途有日惠詩爲別三復黯然和韻奉送言不逮情  其二','黄公度','宋','宋诗','song-poetry','','[]','摶沙聚散苦匆匆，歲晚山寒吾道東。',64,'全唐诗/poet.song.117000.json','["摶沙聚散苦匆匆，歲晚山寒吾道東。", "萬木飄蕭催客老，一官去住任天公。", "情知今夕芳尊倒，魂斷長亭返照紅。", "却喜到家春正好，蠻烟洗盡見華風。"]'),
('e86095ea-de12-4543-9860-d78a62298f48','和章守三詠 包公堂','黄公度','宋','宋诗','song-poetry','','[]','華堂存繪事，昭代得儀刑。',48,'全唐诗/poet.song.117000.json','["華堂存繪事，昭代得儀刑。", "迹與莓苔古，名爭蘭茝馨。", "清風無遠近，喬木未彫零。", "今日斵泥手，依然瘦鶴形。"]'),
('ecf109a8-93d4-47e8-9dbd-e7a6da02fa56','和章守三詠 清心堂','黄公度','宋','宋诗','song-poetry','','[]','千里有餘刃，一堂聊賞心。',48,'全唐诗/poet.song.117000.json','["千里有餘刃，一堂聊賞心。", "庭虛延遠吹，簷敞受繁陰。", "休吏簾初下，忘懷機自沉。", "人間足塵土，無路到清襟。"]'),
('770a5ebb-63f0-4ce6-b263-06349b4b3fda','和章守三詠 披雲樓','黄公度','宋','宋诗','song-poetry','','[]','飛樓跨危堞，雲霧曉披披。',48,'全唐诗/poet.song.117000.json','["飛樓跨危堞，雲霧曉披披。", "形勝供臨眺，公餘來燕宜。", "江橫睥睨闊，山入綺疏奇。", "風月本無價，君侯况有詩。"]'),
('cb853953-822b-407f-915d-aa2866c8c65f','次韻弟師白至日及弄璋之什二首  其一','黄公度','宋','宋诗','song-poetry','','[]','時序鄉心破，烟波眼力催。',48,'全唐诗/poet.song.117000.json','["時序鄉心破，烟波眼力催。", "城頭烏信喜，海上鴈書來。", "一別壺山月，三看庾嶺梅。", "天涯椒桂酒，淚墮伯仁杯。"]'),
('617d72dc-9458-4d3f-a2a1-b98e7f11e7c6','次韻弟師白至日及弄璋之什二首  其二','黄公度','宋','宋诗','song-poetry','','[]','未辦謀生學計然，紛紛又落海西偏。',96,'全唐诗/poet.song.117000.json','["未辦謀生學計然，紛紛又落海西偏。", "癡心政爾了官事，坐嘯何能作散僊。", "霜雪半頭明鏡裏，江湖歸夢野鷗前。", "入懷雙鯉詩材健，醒眼三珠喜氣全。", "處處看雲眠白日，時時舉酒望青天。", "想應留客煮湯餠，弱柳犀錢細細穿。"]'),
('80b04c99-1107-471e-bc25-3c4753672044','立春日有感','黄公度','宋','宋诗','song-poetry','','[]','三見春歸人未歸，天涯依舊賦春詩。',64,'全唐诗/poet.song.117000.json','["三見春歸人未歸，天涯依舊賦春詩。", "一官得失不相補，萬事乘除只自知。", "年去年來供屈指，嶺南嶺北入支頤。", "柳眉桃臉競時節，難遣東風染鬢絲。"]'),
('3bd3b2ef-5769-42ff-9166-180f324985e4','春思','黄公度','宋','宋诗','song-poetry','','[]','紅入西園早，青歸平野多。',48,'全唐诗/poet.song.117000.json','["紅入西園早，青歸平野多。", "日長花欲睡，風軟幕微波。", "萬戶茅柴酒，一聲欵乃歌。", "天涯春漫好，無奈客愁何。"]'),
('ee414572-3a47-42ed-9506-0310a759b059','對瓶花獨酌','黄公度','宋','宋诗','song-poetry','','[]','紅紅白白兩銅瓶，軟飽相看眼倍明。',32,'全唐诗/poet.song.117000.json','["紅紅白白兩銅瓶，軟飽相看眼倍明。", "臠肉自能知鼎味，底尋酒海與花城。"]'),
('99a52e15-2eb8-490b-aa72-65933131fe9c','恩平燈夕憶上都舊遊呈座客','黄公度','宋','宋诗','song-poetry','','[]','千尺鰲山面紫宸，豪華曾見夾城春。',64,'全唐诗/poet.song.117000.json','["千尺鰲山面紫宸，豪華曾見夾城春。", "至今魂夢鈞天奏，投老宦遊窮海濱。", "隨分尊罍奉佳客，記時燈火照嚴闉。", "年來大覺歡情減，聊與風光作主人。"]'),
('3dcd8fad-c8ff-4698-82db-f832b258aa4b','方斛石菖蒲','黄公度','宋','宋诗','song-poetry','','[]','勺水回環含淺清，寸莖蒼翠冠崢嶸。',32,'全唐诗/poet.song.117000.json','["勺水回環含淺清，寸莖蒼翠冠崢嶸。", "扁舟浮玉山前過，想見江湖萬里情。"]'),
('7666ff31-6ca2-47fa-8f24-11a86eab1657','石博山','黄公度','宋','宋诗','song-poetry','','[]','誰琢翠嵐如許工，晴巒洶湧欲穿空。',32,'全唐诗/poet.song.117000.json','["誰琢翠嵐如許工，晴巒洶湧欲穿空。", "一塵不動心齋處，寸縷初飛鼻孔通。"]'),
('48c2e742-0279-4026-81d3-4ba28cee42ce','章運幹和綠陰堂用韻爲謝','黄公度','宋','宋诗','song-poetry','','[]','工拙相懸幾驛亭，敢將沮洳敵東溟。',64,'全唐诗/poet.song.117000.json','["工拙相懸幾驛亭，敢將沮洳敵東溟。", "百年事契心先許，千里神交眼倍青。", "嗜酒楊雄官拓落，耽詩杜甫瘦伶俜。", "何時握筆論今古，經苦勞君一啟扃。"]'),
('14f24792-5703-4ce0-b8b4-100c0a2bfa0d','自恩平還題嵩臺宋隆館二絕  其一','黄公度','宋','宋诗','song-poetry','','[]','四山如畫古端州，州在西江欲盡頭。',32,'全唐诗/poet.song.117000.json','["四山如畫古端州，州在西江欲盡頭。", "漫道江山解留客，老夫歸思甚東流。"]'),
('26a95658-ff97-4908-ab63-f1849b2d8402','自恩平還題嵩臺宋隆館二絕  其二','黄公度','宋','宋诗','song-poetry','','[]','松菊壺山手自栽，二年羈宦客嵩臺。',32,'全唐诗/poet.song.117000.json','["松菊壺山手自栽，二年羈宦客嵩臺。", "無端却被東風誤，又作恩平一夢回。"]'),
('f71a26fc-ee32-40bf-9462-e36736ecccc5','洪景盧賦素馨有遐陬不遇賞拔之嘆戲作反之','黄公度','宋','宋诗','song-poetry','','[]','不入東風桃李羣，結根遠在瘴江濆。',64,'全唐诗/poet.song.117000.json','["不入東風桃李羣，結根遠在瘴江濆。", "眼看南國添春色，天遣餘波及寶薰。", "淡泊直疑梅失素，清幽欲與蕙爭芬。", "上林託足雖無地，猶有香名萬里聞。"]'),
('f8d67035-30eb-44d0-ab8f-6460115d7b1e','和宋永兄圍棋青字韻因成五絕  其一','黄公度','宋','宋诗','song-poetry','','[]','翻劫解圍心有兵，謀生政要眼雙青。',32,'全唐诗/poet.song.117000.json','["翻劫解圍心有兵，謀生政要眼雙青。", "已收鵞陣烏巢幕，未放鷹揚鷗滿汀。"]'),
('e4472a71-c3c6-4402-9e4e-19b972505d4d','和宋永兄圍棋青字韻因成五絕  其二','黄公度','宋','宋诗','song-poetry','','[]','塊然木石本無情，底事紛紛如許爭。',32,'全唐诗/poet.song.117000.json','["塊然木石本無情，底事紛紛如許爭。", "天遣人間作仇敵，只緣黑白太分明。"]'),
('aa0436ef-1209-4281-9d4a-76e47a852d44','和宋永兄圍棋青字韻因成五絕  其三','黄公度','宋','宋诗','song-poetry','','[]','一勝一負乃常事，七縱七擒真妙機。',32,'全唐诗/poet.song.117000.json','["一勝一負乃常事，七縱七擒真妙機。", "九械難窺墨翟守，六奇終破白登圍。"]'),
('e5c93639-0f80-40a3-aba3-6581b24e2db9','和宋永兄圍棋青字韻因成五絕  其四','黄公度','宋','宋诗','song-poetry','','[]','哲匠觀旁嘿若喑，銜枚勇士用功深。',32,'全唐诗/poet.song.117000.json','["哲匠觀旁嘿若喑，銜枚勇士用功深。", "管中窺豹誰家子，技癢時時不自禁。"]'),
('b768ef9e-6fd4-49fc-93c5-9ae577e7b812','和宋永兄圍棋青字韻因成五絕  其五','黄公度','宋','宋诗','song-poetry','','[]','千里歸來兩鬢絲，清風永日對枯棋。',32,'全唐诗/poet.song.117000.json','["千里歸來兩鬢絲，清風永日對枯棋。", "紅塵萬事不到眼，此樂勿容兒輩知。"]'),
('89800b92-65bc-4ed3-aaa6-39603d457c6a','送陳景明尚書赴召四首  其一','黄公度','宋','宋诗','song-poetry','','[]','物望唐姚宋，才名漢董晁。',48,'全唐诗/poet.song.117000.json','["物望唐姚宋，才名漢董晁。", "力陳治安策，親際聖明朝。", "讜議裨宸極，高文燦斗杓。", "鵬程九萬里，一舉接扶摇。"]'),
('78613f47-77b4-4df8-af6c-3bd4e8944d2c','送陳景明尚書赴召四首  其二','黄公度','宋','宋诗','song-poetry','','[]','鼎軸今虛席，憂勤軫我皇。',48,'全唐诗/poet.song.117000.json','["鼎軸今虛席，憂勤軫我皇。", "蒼生思起謝，丹詔急徵黄。", "風欲回三代，恩難私一方。", "願公攄遠業，吾道倍輝光。"]'),
('be4250e1-446e-4ed5-aa39-ce111a20f419','送陳景明尚書赴召四首  其三','黄公度','宋','宋诗','song-poetry','','[]','鴈塔相先後，麟臺數往還。',48,'全唐诗/poet.song.117000.json','["鴈塔相先後，麟臺數往還。", "至今清夜夢，時共早朝班。", "歲月棲遲裏，雲泥指顧間。", "天涯瞻馬首，喜氣動衰顔。"]'),
('2ce12d9d-f8f9-486d-a2b9-7f4e8be52449','送陳景明尚書赴召四首  其四','黄公度','宋','宋诗','song-poetry','','[]','薄宦跕鳶城，歸來夢乍驚。',48,'全唐诗/poet.song.117000.json','["薄宦跕鳶城，歸來夢乍驚。", "壯圖空老大，朴學誤平生。", "有客嘲楊子，無人薦禰衡。", "鹽車逢伯樂，作意一長鳴。"]'),
('875c2641-4837-44d7-bf9b-cf872fcd53ef','次韻林梅卿尚書新塘之什','黄公度','宋','宋诗','song-poetry','','[]','翬翼東西勢欲翔，高懷卜築白雲鄉。',64,'全唐诗/poet.song.117000.json','["翬翼東西勢欲翔，高懷卜築白雲鄉。", "蝦鬚半捲山排闥，屬玉雙飛水拍塘。", "天上功名身未老，年來邱壑意何長。", "萬間廣厦須公辦，政恐徵書下建章。"]'),
('4eef7c61-23cc-4c75-987f-55951fab1b20','乙亥歲除漁梁村','黄公度','宋','宋诗','song-poetry','','[]','年來似覺道途熟，老去空更歲月頻。',64,'全唐诗/poet.song.117000.json','["年來似覺道途熟，老去空更歲月頻。", "爆竹一聲鄉夢破，殘燈永夜客愁新。", "雲容山意商量雪，柳眼桃腮領畧春。", "想得在家小兒女，地爐相對說行人。"]'),
('ab7ba72e-8342-41df-ac76-f33a79cc9de9','仙霞道中','黄公度','宋','宋诗','song-poetry','','[]','村村翁嫗賀年華，不道行人亦念家。',32,'全唐诗/poet.song.117000.json','["村村翁嫗賀年華，不道行人亦念家。", "可是浮名能挽我，杖藜元日度僊霞。"]'),
('cf189e0b-e588-43ee-baa5-e54dc61d4908','次師白弟元日韻','黄公度','宋','宋诗','song-poetry','','[]','且看時事愜心期，莫爲流年作許悲。',64,'全唐诗/poet.song.117000.json','["且看時事愜心期，莫爲流年作許悲。", "足慰羈愁緣鴈序，恐無奇策對龍墀。", "梅粧已覺香全減，柳線相將綠四垂。", "臘雪漸消春又到，人間底事不潛移。"]'),
('cf86e61b-3aed-4acc-ab6c-22c94ec60f9d','次李元泰見贈韻','黄公度','宋','宋诗','song-poetry','','[]','未遣枯桐逐竈煤，君今收拾到微才。',64,'全唐诗/poet.song.117000.json','["未遣枯桐逐竈煤，君今收拾到微才。", "東山謝傅爲時起，前度劉郎何處來。", "自喜餘年瞻日表，恐無奇策上雲臺。", "尊前不用悲流落，懷抱相逢且好開。"]'),
('b7d23e50-8485-42dd-b744-92b6947176ce','別陳景明二首  其一','黄公度','宋','宋诗','song-poetry','','[]','董晁大策無今古，曾據龍頭拜未央。',64,'全唐诗/poet.song.117000.json','["董晁大策無今古，曾據龍頭拜未央。", "天府带頒腰覺重，露門茗賜齒餘香。", "麻詞一掃千言就，玉節三持萬里强。", "自是中朝人第一，更將威信憺要荒。"]'),
('0caa7cee-1e2a-4b82-8a4b-ac37abea282c','別陳景明二首  其二','黄公度','宋','宋诗','song-poetry','','[]','冕旒目送出延英，鼓吹江喧引去程。',64,'全唐诗/poet.song.117000.json','["冕旒目送出延英，鼓吹江喧引去程。", "三夏日遲心自急，百年恩重命還輕。", "賈胡久矣傳詩句，蠻長依然識姓名。", "丹鼎刀圭應有在，願隨雞犬上蓬瀛。"]'),
('32d3d741-8043-45a8-ab85-2b04df594009','輓樂全宋丈二首  其一','黄公度','宋','宋诗','song-poetry','','[]','吾道初彫喪，斯文竟老成。',48,'全唐诗/poet.song.117000.json','["吾道初彫喪，斯文竟老成。", "一經貽子訓，萬石擅家聲。", "棠棣春陰重，芝蘭晚節榮。", "餘芳知未泯，奕世有簪纓。"]'),
('9facfb85-35ea-4177-84f9-cc76f78d626a','輓樂全宋丈二首  其二','黄公度','宋','宋诗','song-poetry','','[]','嘆息高人逝，儀形繪事傳。',48,'全唐诗/poet.song.117000.json','["嘆息高人逝，儀形繪事傳。", "耆年餘八十，遺行滿三千。", "朱紱沾新命，蒼松鬰故阡。", "春風笳吹咽，桃李亦凄然。"]'),
('1c5136b3-373b-40f2-bb1c-46fea30df1fe','輓朱師禹母二首  其一','黄公度','宋','宋诗','song-poetry','','[]','安室全貞操，刑家藹令儀。',48,'全唐诗/poet.song.117000.json','["安室全貞操，刑家藹令儀。", "乘龍推快壻，幹蠱有馨兒。", "未遂林烏報，俄纏風樹悲。", "汗青他日傳，不愧柏舟詩。"]'),
('9fd3e040-6861-4ad4-8b11-9d750ea5ca9e','輓朱師禹母二首  其二','黄公度','宋','宋诗','song-poetry','','[]','孝養空懷橘，嚴規想斷機。',48,'全唐诗/poet.song.117000.json','["孝養空懷橘，嚴規想斷機。", "影留生日面，棺掩嫁時衣。", "萱室言猶在，蘭陔事已非。", "九原行楚挽，桃李慘春暉。"]'),
('70ed02e5-a4cb-43ce-bf1f-56f00743a568','輓方有成教授','黄公度','宋','宋诗','song-poetry','','[]','生平勁節朱絲直，老去清規玉斗寒。',64,'全唐诗/poet.song.117000.json','["生平勁節朱絲直，老去清規玉斗寒。", "卜築空存新第宅，典刑不見舊衣冠。", "百年世事隨風燭，二紀才名獨冷官。", "謝砌餘芳知未泯，森森兒姪長芝蘭。"]'),
('9be51b49-e982-4eab-bfb7-23c54e8158c4','輓林惠州深父二首  其一','黄公度','宋','宋诗','song-poetry','','[]','吾道初彫喪，名公竟典刑。',48,'全唐诗/poet.song.117000.json','["吾道初彫喪，名公竟典刑。", "牧民沾漢璽，詔子有韋經。", "阻奉金鑾對，虛埋石槨銘。", "登門人已往，遺範儼丹青。"]'),
('2761404b-0ba9-4fac-b6a4-728e606c90b9','輓林惠州深父二首  其二','黄公度','宋','宋诗','song-poetry','','[]','昭代輕辭祿，高堂久擊鮮。',48,'全唐诗/poet.song.117000.json','["昭代輕辭祿，高堂久擊鮮。", "慶餘黄雀報，夢契白雞年。", "酹酒生芻外，歸魂宿草邊。", "傷生耆舊盡，執紼涕潸然。"]'),
('1d976021-baed-453d-9c67-5b7318ef659e','輓張直講聖行二首  其一','黄公度','宋','宋诗','song-poetry','','[]','末學知歸㝢，先生有典刑。',48,'全唐诗/poet.song.117000.json','["末學知歸㝢，先生有典刑。", "家貧甘半菽，身後只羣經。", "尊俎言猶在，瓊瑰夢已靈。", "林宗負全節，無愧冢中銘。"]'),
('69465f0a-bd3c-4297-9a76-b3dd80a62a1a','輓張直講聖行二首  其二','黄公度','宋','宋诗','song-poetry','','[]','故老復誰在，此邦嗟至今。',48,'全唐诗/poet.song.117000.json','["故老復誰在，此邦嗟至今。", "文章千古事，忠孝一生心。", "客散門庭寂，塵留几杖深。", "莆人頌遺愛，南望淚橫襟。"]'),
('e85378a2-7cfb-4479-b768-bd508f9ca453','輓蔡公南別駕二首  其一','黄公度','宋','宋诗','song-poetry','','[]','膴政漸遐俗，清風律懦夫。',48,'全唐诗/poet.song.117000.json','["膴政漸遐俗，清風律懦夫。", "人憐埋玉樹，誰復奠生芻。", "賦壽無三甲，傳家有二雛。", "經綸才不展，身世一長吁。"]'),
('3a28ff2f-141a-4d7a-a9f8-930f38e899e0','輓蔡公南別駕二首  其二','黄公度','宋','宋诗','song-poetry','','[]','往歲從新幕，逢君入瘴鄉。',48,'全唐诗/poet.song.117000.json','["往歲從新幕，逢君入瘴鄉。", "但知期白首，誰意熟黄粱。", "星屏塵埃合，銘旌道路長。", "幾經遺愛地，清淚濕甘棠。"]'),
('05bda4c8-fe5e-4b3e-85df-a48135d34ec4','輓歐陽夫人許氏二首  其一','黄公度','宋','宋诗','song-poetry','','[]','斷機貽子訓，截髮具賓盤。',48,'全唐诗/poet.song.117000.json','["斷機貽子訓，截髮具賓盤。", "異數行開邑，他鄉忽蓋棺。", "薤歌春日晚，萱樹北堂寒。", "蕭瑟青門道，萊衣淚不乾。"]'),
('69d18ac5-bbac-4af9-890d-d1fa304ca93e','輓歐陽夫人許氏二首  其二','黄公度','宋','宋诗','song-poetry','','[]','曹範梅峯下，安輿晉水傍。',48,'全唐诗/poet.song.117000.json','["曹範梅峯下，安輿晉水傍。", "百年虧上壽，五鼎富前喪。", "鸞鑑塵初合，龍龕木已蒼。", "平生足陰德，親受伯仁觴。"]'),
('348df8fe-7935-42da-841a-e2458be0c995','輓方仲及簽判二首  其一','黄公度','宋','宋诗','song-poetry','','[]','才華早歲妙中州，惠愛長存瘴嶺頭。',64,'全唐诗/poet.song.117000.json','["才華早歲妙中州，惠愛長存瘴嶺頭。", "陳迹他年循吏傳，遺文何日茂陵求。", "平生業履一經在，投老功名萬事休。", "惟有巋然峴山石，往來涕淚不勝流。"]'),
('3df5d462-c373-48be-a60d-444b9beb851e','輓方仲及簽判二首  其二','黄公度','宋','宋诗','song-poetry','','[]','年來羣盜滿南區，百指間關返舊廬。',64,'全唐诗/poet.song.117000.json','["年來羣盜滿南區，百指間關返舊廬。", "杖屨不辭還往數，尊罍猶想笑譚餘。", "音容忽忽成千古，身世悠悠竟六如。", "脩短窮通一無恨，可憐經濟盡丘墟。"]'),
('9b15db6c-a5e9-4595-97a3-f72381f46d4a','輓蔡子應郎中二首  其一','黄公度','宋','宋诗','song-poetry','','[]','德齒周元老，風流漢二疏。',48,'全唐诗/poet.song.117000.json','["德齒周元老，風流漢二疏。", "千鍾兒輩事，三徑野人居。", "獨行他年傳，生涯幾卷書。", "東山終不起，天意竟何如。"]'),
('634681a1-b123-4357-a5c9-58ecf2d0532b','輓蔡子應郎中二首  其二','黄公度','宋','宋诗','song-poetry','','[]','襲慶名臣胄，棲身世隠堂。',48,'全唐诗/poet.song.117000.json','["襲慶名臣胄，棲身世隠堂。", "憂時多鯁論，疾惡見剛腸。", "髣髴商楹奠，凄凉漢署香。", "老成無復見，雨泣路人傷。"]'),
('13c6e4af-4260-41ef-bc27-c05370d0cbbe','輓顧德將別駕','黄公度','宋','宋诗','song-poetry','','[]','襟懷淵海浩難量，仕路恩威見弛張。',64,'全唐诗/poet.song.117000.json','["襟懷淵海浩難量，仕路恩威見弛張。", "劇邑蒲鞭閑累月，潢池血劍肅如霜。", "朱門絕迹心常泰，銀艾橫腰鬢未蒼。", "學不康時年半百，可憐天道竟茫茫。"]'),
('cdf1bdda-96de-4f91-888f-cbbe31840ff8','輓吳君與大夫','黄公度','宋','宋诗','song-poetry','','[]','吳侯大雅姿，妙齡飽經術。',240,'全唐诗/poet.song.117000.json','["吳侯大雅姿，妙齡飽經術。", "場屋早蜚聲，囊錐穎立出。", "携書走帝閽，一第頷髭摘。", "夷途騁駿步，霄漢刷健翮。", "胸中萬餘卷，未試二三策。", "誰知廊廟具，反任州縣責。", "官小不自卑，直道酬平昔。", "愛民如愛子，憂國如憂室。", "愷悌疲俗蘇，廉介貪夫律。", "至今遺愛地，籍籍數嘉績。", "松菊動歸思，塵埃辭吏役。", "挂冠神武門，高卧揚雄宅。", "追念平生爲，秋毫一無失。", "桎梏謝軒冕，膏肓嗜水石。", "十載州府間，不見龐公迹。", "萬事同甑破，百年過箭疾。", "嗚呼老成人，忽忽就窀穸。", "豐碑存衆口，餘慶有佳息。", "於公雖無憾，豈不爲時惜。", "作詩遣哀情，詩成轉悽惻。"]'),
('e0dbae50-855a-448f-947c-26189e59148e','輓方宋賢四絕  其一','黄公度','宋','宋诗','song-poetry','','[]','少年挾策上皇都，晚歲論功向石渠。',32,'全唐诗/poet.song.117000.json','["少年挾策上皇都，晚歲論功向石渠。", "猶憶微才在天祿，鉛丹曾爲校遺書。"]'),
('dad1371e-9ec0-4b16-84a0-cd37bdc4b3b3','輓方宋賢四絕  其二','黄公度','宋','宋诗','song-poetry','','[]','千年忠孝歸圖畫，百卷風騷動冕旒。',32,'全唐诗/poet.song.117000.json','["千年忠孝歸圖畫，百卷風騷動冕旒。", "一尉南州成底事，可憐夜壑遽移舟。"]'),
('81b04799-02f9-4802-8a7f-aa78033eedbb','輓方宋賢四絕  其三','黄公度','宋','宋诗','song-poetry','','[]','管輅相無壬甲壽，鄭玄夢告己辰年。',32,'全唐诗/poet.song.117000.json','["管輅相無壬甲壽，鄭玄夢告己辰年。", "收書恨未齊東觀，作記虛傳上九天。"]'),
('df8077c7-1a5c-4c6d-b8c7-81cfe037c04a','輓方宋賢四絕  其四','黄公度','宋','宋诗','song-poetry','','[]','平生好尚流俗表，無數交遊氣槩中。',32,'全唐诗/poet.song.117000.json','["平生好尚流俗表，無數交遊氣槩中。", "未覺門前車轍少，阿戎清賞有渾風。"]'),
('32ac6fb7-e3d7-4e9c-adbc-785b4080c579','輓陳夫人卓氏二首  其一','黄公度','宋','宋诗','song-poetry','','[]','貴不改舊習，老猶遵幼儀。',48,'全唐诗/poet.song.117000.json','["貴不改舊習，老猶遵幼儀。", "安貧偕隠者，急義勝男兒。", "餘潤河九里，寧馨桂一枝。", "秋毫有遺恨，石窌剖封遲。"]'),
('d8de82c5-ec3b-443a-9a34-fd87f3d1a36a','輓陳夫人卓氏二首  其二','黄公度','宋','宋诗','song-poetry','','[]','蘋藻潔羞遺訓在，芝蘭奕葉慶源賒。',64,'全唐诗/poet.song.117000.json','["蘋藻潔羞遺訓在，芝蘭奕葉慶源賒。", "何人誄德須千字，他日塚傍應萬家。", "秋風摧謝忘憂草，古木悲啼反哺鴉。", "猶憶升堂初拜跪，依然象服儼笄珈。"]'),
('15599d91-1ce9-4f1b-9d6d-2adc34fdc5f5','輓林聞遠','黄公度','宋','宋诗','song-poetry','','[]','曾向文闈屈壯圖，羞將華髮傍戎車。',64,'全唐诗/poet.song.117000.json','["曾向文闈屈壯圖，羞將華髮傍戎車。", "平生自致千金産，投老相辜一卷書。", "有子克家追羯末，何人會葬盡嚴徐。", "青天白日佳城閉，宰木蕭蕭繐帳虛。"]'),
('abc33bf1-c417-4fcc-89ee-27a24e0a8370','輓趙若愚母','黄公度','宋','宋诗','song-poetry','','[]','孟母鄰兮陶母賓，祥麟威鳳各才名。',64,'全唐诗/poet.song.117000.json','["孟母鄰兮陶母賓，祥麟威鳳各才名。", "早持容德嬪天族，誰信艱勤老我生。", "雙鶴跰躚來弔客，一牛贔屭得佳城。", "人間毫髮有遺恨，五桂纔看一桂榮。"]'),
('b1ac7d74-058a-4365-8c87-a74f893df974','輓十一伯奉議四首  其一','黄公度','宋','宋诗','song-poetry','','[]','弓冶傳家學，才名觀國賓。',48,'全唐诗/poet.song.117000.json','["弓冶傳家學，才名觀國賓。", "譚經至白首，投老漫青綸。", "北去曾乘險，南歸益自珍。", "要知超悟處，縹帙有離塵。"]'),
('490fec96-0fd2-4603-8074-1c43767f19da','輓十一伯奉議四首  其二','黄公度','宋','宋诗','song-poetry','','[]','丘壑性所樂，詩書老自娛。',48,'全唐诗/poet.song.117000.json','["丘壑性所樂，詩書老自娛。", "譚惟聽兩部，貧不種千奴。", "歲月柯間蟻，功名水上鳬。", "平生五車讀，留得付諸孤。"]'),
('fece842e-0ca7-439f-8204-b9484d01895f','輓十一伯奉議四首  其三','黄公度','宋','宋诗','song-poetry','','[]','有子皆麟鳳，承家頼一夔。',48,'全唐诗/poet.song.117000.json','["有子皆麟鳳，承家頼一夔。", "朝班通籍日，綸誥錫封時。", "堂上蘭羞罷，人間風樹悲。", "生榮死不朽，猶恨未期頤。"]'),
('6bf92741-119d-452e-8d3f-115f375e3fe7','輓十一伯奉議四首  其四','黄公度','宋','宋诗','song-poetry','','[]','往者更聲律，公兮獨老成。',48,'全唐诗/poet.song.117000.json','["往者更聲律，公兮獨老成。", "餘波及猶子，作賦得虛名。", "瘴海三年別，靈巖一夢驚。", "歸來訪遺跡，心折涕縱橫。"]'),
('e8f193f0-b606-4407-8ec0-63290993b8bf','謁守浄禪師','黄公度','宋','宋诗','song-poetry','','[]','十方同聚會，箇箇學無爲。',24,'全唐诗/poet.song.117000.json','["十方同聚會，箇箇學無爲。", "此是選佛場，心空及第歸。"]'),
('5ec8c1be-3095-471c-9ec6-1f027209a0a1','岳陽樓','黄公度','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','後樂先憂記飽觀，茲樓今始得憑欄。',64,'全唐诗/poet.song.117000.json','["後樂先憂記飽觀，茲樓今始得憑欄。", "吐吞五水波濤闊，出納三光境界寬。", "黄帝樂聲喧廣宙，湘君山影浸晴瀾。", "江山何獨助張說，收拾清暉上筆端。"]'),
('31d9efb5-7db8-4855-9fb7-424a49b89d74','句  其一','黄公度','宋','宋诗','song-poetry','','[]','欲治之主不世出，大名之下難久居。',16,'全唐诗/poet.song.117000.json','["欲治之主不世出，大名之下難久居。"]'),
('54b5855b-802b-4660-b740-a695760073b2','句  其二','黄公度','宋','宋诗','song-poetry','','[]','依舊家山萬里，重新場屋三年。',14,'全唐诗/poet.song.117000.json','["依舊家山萬里，重新場屋三年。"]'),
('b5ebf53c-78b9-40be-b863-069ad04d9478','游虎丘巖偶題壁韻叶因分字聯句','余子侯','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.117000.json','["無正文。"]'),
('a4f29261-049f-41ac-b91a-d9f61afd3a2e','樂山禱雨','黄瑀','宋','宋诗','song-poetry','','[]','直上雲峰表，雲間謁洞天。',24,'全唐诗/poet.song.117000.json','["直上雲峰表，雲間謁洞天。", "自慚無善政，來此乞豐年。"]'),
('7eed06f2-a5ce-4b02-8efb-cc7bf26f00a2','留題授上人曲肱齋','汪澈','宋','宋诗','song-poetry','','[]','一室安巾鉢，穨然了性空。',48,'全唐诗/poet.song.117000.json','["一室安巾鉢，穨然了性空。", "曲肱忘世夢，行脚本家風。", "山靜人稀到，窗開意不窮。", "我來頻假寐，樂亦在其中。"]'),
('982955be-502b-4926-b624-0243312c621e','題瑞巖大澤塘','錢端禮','宋','宋诗','song-poetry','','[]','塵纓久欲濯滄浪，今日來遊大澤塘。',32,'全唐诗/poet.song.117000.json','["塵纓久欲濯滄浪，今日來遊大澤塘。", "水似我心心似水，更無一事可商量。"]'),
('77c73ae0-38cc-4a71-b721-d1fda932afff','留題授上人曲肱齋','錢端禮','宋','宋诗','song-poetry','','[]','架屋巾山最上頭，曲肱打睡百無憂。',64,'全唐诗/poet.song.117000.json','["架屋巾山最上頭，曲肱打睡百無憂。", "雲容獻狀留殘雨，海月橫陳有去舟。", "閑裏琴書緣好客，向來鐘鼓不驚鷗。", "會將一滴曹溪水，洗盡胸中萬斛愁。"]'),
('6d322a6c-4600-420d-98fe-f593c765d26f','題米元暉瀟湘圖','錢端禮','宋','宋诗','song-poetry','','[]','畫手自高前輩，雲山已屬吾曹。',28,'全唐诗/poet.song.117000.json','["畫手自高前輩，雲山已屬吾曹。", "若會瀟湘物色，便當醉讀離騷。"]'),
('6851f7b9-fa21-4e00-aed8-218034f08e1e','咏般若臺一首贈源□長□','錢端禮','宋','宋诗','song-poetry','','[]','□□雲收出遠林，兩山不隔□□鳴。',64,'全唐诗/poet.song.117000.json','["□□雲收出遠林，兩山不隔□□鳴。", "層臺迥出層霄外，霜□還同霜月平。", "修竹可人無俗韻，疏梅能事□僧清。", "寶□遍□虛空界，深夜猶聞梵唄聲。"]'),
('cb938913-7983-4828-8718-b3126dfe2244','賀熊克進九朝要略轉一官','李龜朋','宋','宋诗','song-poetry','','[]','翰苑前資漢碩儒，苦心何翅十年餘。',64,'全唐诗/poet.song.117000.json','["翰苑前資漢碩儒，苦心何翅十年餘。", "修成當代將來法，讀盡生平未見書。", "黄帊奏篇登御府，紫綸加秩下宸除。", "近臣已是聞天語，鸞鵲催歸定不虛。"]'),
('b169703d-7020-4985-907a-ea0cf4e42855','同謝子肅諸公飲巾山岊上人房','李龜朋','宋','宋诗','song-poetry','','[]','石磴行崎曲，緣雲入翠微。',48,'全唐诗/poet.song.117000.json','["石磴行崎曲，緣雲入翠微。", "山寒驚歲晚，渚綠認春歸。", "絕境爲誰設，清歡如此稀。", "軒窗生夜氣，簷角有星飛。"]'),
('80a324a5-3bd9-41ef-91a1-a499394b82a8','玉環山','曾覿','宋','宋诗','song-poetry','','[]','天寶胡塵暗兩京，禍從妃子笑中生。',32,'全唐诗/poet.song.117000.json','["天寶胡塵暗兩京，禍從妃子笑中生。", "玉環兩字真堪恨，好與青山別改名。"]'),
('34c9aa9b-0197-406b-a55c-f17ae56136d1','題楊補之雪梅圖','曾覿','宋','宋诗','song-poetry','','[]','筆端造化出天巧，寫出江南雪壓枝。',32,'全唐诗/poet.song.117000.json','["筆端造化出天巧，寫出江南雪壓枝。", "誰道春歸無覓處，橫斜全似越溪時。"]'),
('e2710e7a-98f3-4750-9053-93c7f47402fc','偈頌十五首  其一','釋寶印','宋','宋诗','song-poetry','','[]','徧地殘紅春去也，拍天漲綠興悠哉。',32,'全唐诗/poet.song.117000.json','["徧地殘紅春去也，拍天漲綠興悠哉。", "道人覓甚安心法，達磨當時带不來。"]'),
('4a89d407-2936-432b-91be-daaf93db1710','偈頌十五首  其二','釋寶印','宋','宋诗','song-poetry','','[]','六月初一，燒空赤日。',46,'全唐诗/poet.song.117000.json','["六月初一，燒空赤日。", "十字街頭，雪深一尺。", "掃除不暇，回避不及。", "凍得東村廖胡子，半夜著鞋水上立。"]'),
('fc99c2fd-2f18-4cbc-8a29-c7119f1a6351','偈頌十五首  其三','釋寶印','宋','宋诗','song-poetry','','[]','虎頭带角人難措，石火電光須密布。',32,'全唐诗/poet.song.117000.json','["虎頭带角人難措，石火電光須密布。", "假饒烈士薦應難，懵底如何善回互。"]'),
('9c8f8fb6-20cb-44b2-ab9c-a16068d7a2a0','偈頌十五首  其四','釋寶印','宋','宋诗','song-poetry','','[]','便是猶陪句，如何已涉言。',24,'全唐诗/poet.song.117000.json','["便是猶陪句，如何已涉言。", "須知言句外，聲色不相干。"]'),
('d13f2aa6-2258-4f72-8373-42daddb8d628','偈頌十五首  其五','釋寶印','宋','宋诗','song-poetry','','[]','前箭射人可，後箭射人深。',24,'全唐诗/poet.song.117000.json','["前箭射人可，後箭射人深。", "鍾先生沒後，此道少知音。"]'),
('da39b01e-e518-4c31-9e8c-2538fd1b20c9','偈頌十五首  其六','釋寶印','宋','宋诗','song-poetry','','[]','來也宮殿隨身，去也笙歌滿路。',28,'全唐诗/poet.song.117000.json','["來也宮殿隨身，去也笙歌滿路。", "侍者白頭如新，趙州傾蓋如故。"]'),
('1aa0c634-ed44-4de6-867a-e0d09731de7d','偈頌十五首  其七','釋寶印','宋','宋诗','song-poetry','','[]','佛高一丈，魔高一丈。',60,'全唐诗/poet.song.117000.json','["佛高一丈，魔高一丈。", "正覺山前，無風起浪。", "金山箇裏，佛魔俱喪。", "明星現時，且莫欺誑。", "無牛乳糜，有德山棒。", "爲甚如此，真法供養。"]'),
('09c02229-9bbf-4bef-892e-d4e845c44529','偈頌十五首  其八','釋寶印','宋','宋诗','song-poetry','','[]','雨足歛煙雲，山晴開錦綉。',96,'全唐诗/poet.song.117000.json','["雨足歛煙雲，山晴開錦綉。", "良哉信心人，知有向上竅。", "携家上崔嵬，法席爲宏開。", "五百阿羅漢，擲錫與浮杯。", "赴供如雲集，壽山增岌岌。", "次男慧性開，念念皆迪吉。", "徑山不覆藏，言外要承當。", "風雲重際會，歸去侍清光。"]'),
('0a720e75-2fef-4cfa-96ba-810e3cbfb200','偈頌十五首  其九','釋寶印','宋','宋诗','song-poetry','','[]','說法不勞三寸舌，參禪惜取兩莖眉。',32,'全唐诗/poet.song.117000.json','["說法不勞三寸舌，參禪惜取兩莖眉。", "玉欄干畔青青柳，最好人間二月時。"]'),
('88f4d9ea-548c-4e42-a593-9042f5224577','偈頌十五首  其一○','釋寶印','宋','宋诗','song-poetry','','[]','何似生，合取口，三世諸佛不知有。',28,'全唐诗/poet.song.117000.json','["何似生，合取口，三世諸佛不知有。", "日午打三更，面南看北斗。"]'),
('4a691137-4a5e-4641-829d-50164f3d3733','偈頌十五首  其一一','釋寶印','宋','宋诗','song-poetry','','[]','律身行業凜冰霜，接物機關走雷電。',32,'全唐诗/poet.song.117000.json','["律身行業凜冰霜，接物機關走雷電。", "七千餘指渴思漿，願爲重提正法眼。"]'),
('512d7e02-b15a-461e-8fe2-e5a5871e61a0','偈頌十五首  其一二','釋寶印','宋','宋诗','song-poetry','','[]','初三十一，中九下七。',20,'全唐诗/poet.song.117000.json','["初三十一，中九下七。", "衆眼難瞞，當機莫惜。"]'),
('7e44e462-9cad-4881-9e02-690a3bbc52e2','偈頌十五首  其一三','釋寶印','宋','宋诗','song-poetry','','[]','胡張三，黑李四。',48,'全唐诗/poet.song.117000.json','["胡張三，黑李四。", "不會禪，不識字。", "驀然相見閙籃頭，話盡平生各歸去。", "十日雨，五日風，謳歌鼓舞樂無窮。"]'),
('bd5bc09b-26ad-4f15-b502-a01b49f4daba','偈頌十五首  其一四','釋寶印','宋','宋诗','song-poetry','','[]','浮玉山頭留不住，相携夜過長蘆渡。',32,'全唐诗/poet.song.117000.json','["浮玉山頭留不住，相携夜過長蘆渡。", "識得諸方第一機，踏翻船子先歸去。"]'),
('1d667794-da9c-47e4-b53a-9998af2a034f','頌古三首  其一','釋寶印','宋','宋诗','song-poetry','','[]','千尺絲綸直下垂，錦鱗撥剌上鈎時。',32,'全唐诗/poet.song.117000.json','["千尺絲綸直下垂，錦鱗撥剌上鈎時。", "斜風細雨歌歸去，醉倒蓬窗百不知。"]'),
('7f0de0af-8817-4285-8226-7971108a4008','頌古三首  其二','釋寶印','宋','宋诗','song-poetry','','[]','水因有月方知靜，天爲無雲始覺高。',32,'全唐诗/poet.song.117000.json','["水因有月方知靜，天爲無雲始覺高。", "獨坐孤峯休更問，此時難著一絲毫。"]'),
('7e06eb8a-8cad-42f4-89ea-d1c429d2556e','頌古三首  其三','釋寶印','宋','宋诗','song-poetry','','[]','學佛人人被佛瞞，撥塵見得幾何般。',32,'全唐诗/poet.song.117000.json','["學佛人人被佛瞞，撥塵見得幾何般。", "狂風卷地雲吹散，獨立欄干宇宙寬。"]'),
('b161bdf1-ed61-4d08-8a8e-55500226f36b','偈二首  其一','釋寶印','宋','宋诗','song-poetry','','[]','日上月下，速如電轂。',66,'全唐诗/poet.song.117000.json','["日上月下，速如電轂。", "又是重新，一陽來復。", "湛不摇處，暖生寒谷。", "籬落梅華，枝枝粲玉。", "賀客街頭，亞肩疊足。", "借婆裙子拜婆年，不識本來真面目。"]'),
('2f8f5800-6c07-4ea5-aa31-cfd404d015f5','偈二首  其二','釋寶印','宋','宋诗','song-poetry','','[]','將心除妄妄難除，即妄明心道轉迂。',32,'全唐诗/poet.song.117000.json','["將心除妄妄難除，即妄明心道轉迂。", "桶底趯穿無忌諱，等閑一步一芙蕖。"]'),
('20883d8c-eafe-42ec-9f02-8b3f0cf63c7a','梅林分韻得澤字','釋寶印','宋','宋诗','song-poetry','','[]','江路歲崢嶸，酸風更蕭瑟。',120,'全唐诗/poet.song.117000.json','["江路歲崢嶸，酸風更蕭瑟。", "發興訪梅花，主盟得詩伯。", "孤芳有餘妍，初不带脂澤。", "香度竹籬短，影摇谿水碧。", "同時飲中仙，著我林下客。", "春槽沸滴紅，滿坐喧舉白。", "澆胸獨茗碗，臭味曾不隔。", "公今日邊去，陛下正前席。", "請看枝頭春，中有和羹實。", "反騷試與題，不礙心鐵石。"]'),
('cd8c8b43-1904-48c3-b26d-4f2d421fb684','頌古十八首  其一','釋寶印','宋','宋诗','song-poetry','','[]','有無語默謾徒勞，居士何曾動一毫。',32,'全唐诗/poet.song.117000.json','["有無語默謾徒勞，居士何曾動一毫。", "世祖功成三十六，雲臺爭似釣臺高。"]'),
('e92eaf9c-646a-484d-8e5f-63881cbe4d1d','頌古十八首  其二','釋寶印','宋','宋诗','song-poetry','','[]','手按吹毛豈易爲，兩堂要活死貓兒。',32,'全唐诗/poet.song.117000.json','["手按吹毛豈易爲，兩堂要活死貓兒。", "趙州上樹安身法，多少傍人眼搭𥉍。"]'),
('2b2717ae-ebae-47be-a1c2-9b5e7b5f5353','頌古十八首  其三','釋寶印','宋','宋诗','song-poetry','','[]','一箇形骸兩姓名，入泥入水可憐生。',32,'全唐诗/poet.song.117000.json','["一箇形骸兩姓名，入泥入水可憐生。", "回頭掣斷黄金鏁，肯向毗盧頂上行。"]'),
('f4aa5b06-2d8b-47e1-b79a-d1834b92aff8','頌古十八首  其四','釋寶印','宋','宋诗','song-poetry','','[]','豎起拂子封白紙，千里誰知有知己。',32,'全唐诗/poet.song.117000.json','["豎起拂子封白紙，千里誰知有知己。", "行人莫與路爲讎，四海五湖王化裏。"]'),
('b801f5c4-eba0-4444-a750-d53b2d142fb5','頌古十八首  其五','釋寶印','宋','宋诗','song-poetry','','[]','一橈提起定綱宗，直得乾坤大地空。',32,'全唐诗/poet.song.117000.json','["一橈提起定綱宗，直得乾坤大地空。", "只爲夾山輕放過，至今四海錯流通。"]'),
('d7c7f004-901a-4a2e-bcc2-c8a871e2c8eb','頌古十八首  其六','釋寶印','宋','宋诗','song-poetry','','[]','臨濟慣白拈，普化慣掣顛。',24,'全唐诗/poet.song.117000.json','["臨濟慣白拈，普化慣掣顛。", "一場好笑具，後世作三玄。"]'),
('4775dc43-f2c7-40fc-aaac-6046e166858c','頌古十八首  其七','釋寶印','宋','宋诗','song-poetry','','[]','全收全放不通風，點破將來已不中。',32,'全唐诗/poet.song.117000.json','["全收全放不通風，點破將來已不中。", "禮拜起來雖悟去，街頭笑倒李三翁。"]'),
('73889b28-92f9-405e-b3e8-596fe34dd687','頌古十八首  其八','釋寶印','宋','宋诗','song-poetry','','[]','山之峩峩，水之湯湯。',20,'全唐诗/poet.song.117000.json','["山之峩峩，水之湯湯。", "冷眼覷著，無處慚惶。"]'),
('8a3be876-0faa-433a-88e7-708e485ea026','頌古十八首  其九','釋寶印','宋','宋诗','song-poetry','','[]','忽然不然，如鋏如鉗。',20,'全唐诗/poet.song.117000.json','["忽然不然，如鋏如鉗。", "神仙秘訣，父子不傳。"]'),
('8f077521-0d9e-4c03-8768-64a7518b66d7','頌古十八首  其一○','釋寶印','宋','宋诗','song-poetry','','[]','不疑不徹不失，片片春風狼籍。',40,'全唐诗/poet.song.117000.json','["不疑不徹不失，片片春風狼籍。", "至今江北江南，游子徒勞外覓。", "休外覓，明如杲日黑如漆。"]'),
('c4356ac3-e604-4296-9d0a-cbae586c3397','頌古十八首  其一一','釋寶印','宋','宋诗','song-poetry','','[]','臨機一味放憨癡，其毒尤深棒喝時。',32,'全唐诗/poet.song.117000.json','["臨機一味放憨癡，其毒尤深棒喝時。", "堪笑人來誇敏手，得便宜是落便宜。"]'),
('ba0cc48b-0086-4113-9b90-70fbaa84eccb','頌古十八首  其一二','釋寶印','宋','宋诗','song-poetry','','[]','何必不必，金刀玉尺。',30,'全唐诗/poet.song.117000.json','["何必不必，金刀玉尺。", "甜者如檗，苦者如蜜。", "二十年來，無處雪屈。"]'),
('4a29bd93-a0d8-4276-ba82-dc1a34a17476','頌古十八首  其一三','釋寶印','宋','宋诗','song-poetry','','[]','李公要勸張公酒，却被張公罰一盃。',32,'全唐诗/poet.song.117000.json','["李公要勸張公酒，却被張公罰一盃。", "珠遶團團休錯會，還家拍手笑哈哈。"]'),
('7f448bbc-0bb0-4f9d-84f7-984670a7be05','頌古十八首  其一四','釋寶印','宋','宋诗','song-poetry','','[]','應口曹源一滴時，誰知依樣畫貓兒。',32,'全唐诗/poet.song.117000.json','["應口曹源一滴時，誰知依樣畫貓兒。", "袖中三尺龍泉劒，落盡髑髏人不知。"]'),
('7f35314a-2eda-4686-8a8f-e565d57608eb','頌古十八首  其一五','釋寶印','宋','宋诗','song-poetry','','[]','衲僧悟易要迷難，無限漁翁失釣竿。',32,'全唐诗/poet.song.117000.json','["衲僧悟易要迷難，無限漁翁失釣竿。", "點鐵成金猶自可，點金成鐵太無端。"]'),
('723351f0-477b-4792-a4ea-44818fd6a27e','頌古十八首  其一六','釋寶印','宋','宋诗','song-poetry','','[]','正月孟春猶寒，從頭萬種千般。',28,'全唐诗/poet.song.117000.json','["正月孟春猶寒，從頭萬種千般。", "昨夜虛空落地，和風搭在闌干。"]'),
('9d96d8e5-f8b3-4d2a-a0a1-8536d4356c16','頌古十八首  其一七','釋寶印','宋','宋诗','song-poetry','','[]','胡張三背手張弓，黑李四反身架箭。',32,'全唐诗/poet.song.117000.json','["胡張三背手張弓，黑李四反身架箭。", "直饒囓鏃古將軍，對面髑髏穿一穿。"]'),
('f432068d-a241-4f83-8149-ce0df61bfa69','頌古十八首  其一八','釋寶印','宋','宋诗','song-poetry','','[]','生鐵鑄就崑崙兒，眼耳鼻舌如泥塊。',32,'全唐诗/poet.song.117000.json','["生鐵鑄就崑崙兒，眼耳鼻舌如泥塊。", "西天此土謾紛紜，鐵眼銅睛看不破。"]'),
('14cf5798-c834-47c2-9f84-ac26a7f0c15f','寓宿洞霄','釋寶印','宋','宋诗','song-poetry','','[]','窈窕門前九鎖山，琮琤石角千層水。',64,'全唐诗/poet.song.117000.json','["窈窕門前九鎖山，琮琤石角千層水。", "白雲影裏閲羣仙，風斷木犀香未已。", "我從青城大面來，羽衣駕鶴欣相陪。", "五峯去此在咫尺，肯惜杖屨時徘徊。"]'),
('3bbc4747-f755-4362-8711-dfdcc2dc8790','句','釋寶印','宋','宋诗','song-poetry','','[]','滿屋掛碑光耿耿。',8,'全唐诗/poet.song.117000.json','["滿屋掛碑光耿耿。"]'),
('ba6f027f-8026-449c-84eb-3a2684b3f3c0','和洪容齋鎖院作','葉黯','宋','宋诗','song-poetry','','[]','文章萬言抵杯水，世上虛名徒爾耳。',160,'全唐诗/poet.song.117000.json','["文章萬言抵杯水，世上虛名徒爾耳。", "我常自笑一生癡，那更將癡笑羣子。", "大屋沈沈餘百年，到今所閲知幾士。", "看渠得失自偶然，其間悲喜從何起。", "君聞我言亦大笑，爲說萬事總如此。", "□□□□□□□，□□□□□□□。", "急須了却公家事，門外不知春有幾。", "□□□□□□□，□□□□□□□。", "□□□□□□□，飛雨時聞打窗紙。", "他年萬一復相從，未必從容今日似。"]'),
('26b30567-2e46-495e-88fe-d4cc705fe09e','送容齋自福倅滿歸  其一','葉黯','宋','宋诗','song-poetry','','[]','一門伯仲知誰似，四海文章正數君。',64,'全唐诗/poet.song.117000.json','["一門伯仲知誰似，四海文章正數君。", "何事與予如舊識，由來于世兩相聞。", "閑官各喜光陰賸，勝地空多物色分。", "忽復翩然從此去，便應變化上青雲。"]'),
('56e6eeee-c4e5-44c6-bf63-31f04f91619a','送容齋自福倅滿歸  其二','葉黯','宋','宋诗','song-poetry','','[]','此地相從驚歲晚，登臨況是客歸時。',64,'全唐诗/poet.song.117000.json','["此地相從驚歲晚，登臨況是客歸時。", "却將襟抱向誰可，正爾艱難唯子知。", "情到中年工作惡，別于生世易爲悲。", "梅花盡醉清江上，黯澹西風凍雨垂。"]'),
('1accb12b-795e-4c1d-8b4c-9eab0d95e118','霧','李靚','宋','宋诗','song-poetry','','[]','樹在溪無影，禽來鶻未知。',24,'全唐诗/poet.song.117000.json','["樹在溪無影，禽來鶻未知。", "愛花留潤與，避日卷陰移。"]'),
('387decae-a96c-4d2d-9b5c-c7164719094f','春寒','胡仔','宋','宋诗','song-poetry','','[]','小院春寒閉寂寥，杏花枝上雨瀟瀟。',32,'全唐诗/poet.song.117000.json','["小院春寒閉寂寥，杏花枝上雨瀟瀟。", "午窗歸夢無人喚，銀葉龍涎香漸銷。"]'),
('869adcd9-f53e-4d6e-aa2c-a7c893b1e3bb','詠黄白菊花','胡仔','宋','宋诗','song-poetry','','[]','何處金錢與玉錢，化爲蝴蝶夜翩翩。',32,'全唐诗/poet.song.117000.json','["何處金錢與玉錢，化爲蝴蝶夜翩翩。", "青絲網住芳叢上，開作秋花取意妍。"]'),
('3766c588-e483-4ffe-b48b-b740f29ff65d','對月用促句換韻格','胡仔','宋','宋诗','song-poetry','','[]','青玻璃色瑩長空，爛銀盤挂屋山東，晚凉徐度一襟風。',72,'全唐诗/poet.song.117000.json','["青玻璃色瑩長空，爛銀盤挂屋山東，晚凉徐度一襟風。", "天分風月相管領，對之技癢誰能忍，吟哦自恨詩才窘。", "掃寬露坐發興新，浮蛆琰琰拋青春，不妨舉盞成三人。"]'),
('c40bfa00-7702-4ff1-8f39-9009aa676c00','和人詠蠟梅絕句因紀其事','胡仔','宋','宋诗','song-poetry','','[]','新詩湔拂自蘇黄，想見當年喜色香。',32,'全唐诗/poet.song.117000.json','["新詩湔拂自蘇黄，想見當年喜色香。", "草木無情遇真賞，豈知千載有餘芳。"]'),
('08d6c503-e6e7-4d31-8601-e38c66f1db5c','題苕溪漁隠圖  其一','胡仔','宋','宋诗','song-poetry','','[]','溪邊短短長長柳，波上來來去去船。',32,'全唐诗/poet.song.117000.json','["溪邊短短長長柳，波上來來去去船。", "鷗鳥近人渾不畏，一雙飛下鏡中天。"]'),
('585ad417-ebca-473b-9cbb-dcd8303033b4','題苕溪漁隠圖  其二','胡仔','宋','宋诗','song-poetry','','[]','秋雲漠漠烟蒼蒼，蘆花初白蓮葉黄。',32,'全唐诗/poet.song.117000.json','["秋雲漠漠烟蒼蒼，蘆花初白蓮葉黄。", "釣船盡日來往處，南村北村秔稻香。"]'),
('b1c1ea4c-a2cf-4ebe-9917-e0df9ae75273','題苕溪漁隠圖  其三','胡仔','宋','宋诗','song-poetry','','[]','卷起綸竿撇櫂歸，短篷斜掩宿漁磯。',32,'全唐诗/poet.song.117000.json','["卷起綸竿撇櫂歸，短篷斜掩宿漁磯。", "日高春睡無人喚，撩亂楊花繞夢飛。"]'),
