('a71176ab-314e-4daa-9d42-40c57b117538','句  其二三','李縝','宋','宋诗','song-poetry','','[]','暗香都自著人來。',8,'全唐诗/poet.song.117000.json','["暗香都自著人來。"]'),
('4278dff1-3799-4426-b7d3-e48727959f2e','句  其二四','李縝','宋','宋诗','song-poetry','','[]','童初宮裏雨斑斑。',8,'全唐诗/poet.song.117000.json','["童初宮裏雨斑斑。"]'),
('2a244b69-98c9-48a2-aef3-fcf83874e1c3','句  其二五','李縝','宋','宋诗','song-poetry','','[]','淺笑微顰盡斷腸。',8,'全唐诗/poet.song.117000.json','["淺笑微顰盡斷腸。"]'),
('99e4bc5f-a453-4889-b82b-08af254668f7','句  其二六','李縝','宋','宋诗','song-poetry','','[]','行人將底酬春色。',8,'全唐诗/poet.song.117000.json','["行人將底酬春色。"]'),
('ce0bd556-a157-4c5f-8f19-9ed7a533e3d0','句  其二七','李縝','宋','宋诗','song-poetry','','[]','蜂撩蝶嬲不相饒。',8,'全唐诗/poet.song.117000.json','["蜂撩蝶嬲不相饒。"]'),
('dfbbc8b5-1f34-4ae3-a147-8d7044cc438b','句  其二八','李縝','宋','宋诗','song-poetry','','[]','芒鞵遠覓香來處。',8,'全唐诗/poet.song.117000.json','["芒鞵遠覓香來處。"]'),
('a12a1c2e-6ceb-4876-8eaa-c44849f8f44e','句  其二九','李縝','宋','宋诗','song-poetry','','[]','駝裘幾折犯寒花。',8,'全唐诗/poet.song.117000.json','["駝裘幾折犯寒花。"]'),
('1d6d75d4-a468-492b-a4dd-250df0feabf5','句  其三○','李縝','宋','宋诗','song-poetry','','[]','何人月下此幽尋。',8,'全唐诗/poet.song.117000.json','["何人月下此幽尋。"]'),
('56cb8d27-6e87-47c8-b615-9e72ef3bf948','句  其三一','李縝','宋','宋诗','song-poetry','','[]','江頭千樹玉模糊。',8,'全唐诗/poet.song.117000.json','["江頭千樹玉模糊。"]'),
('6306fca4-b07c-4fa4-a2aa-fa2eb98f95b0','句  其三二','李縝','宋','宋诗','song-poetry','','[]','可憐風味故依然。',8,'全唐诗/poet.song.117000.json','["可憐風味故依然。"]'),
('91d333dc-9299-494c-ba0e-cd0ab04096ed','和王丞絕勝亭','員興宗','宋','宋诗','song-poetry','','[]','時序一轉轂，乾坤雙旅亭。',192,'全唐诗/poet.song.117000.json','["時序一轉轂，乾坤雙旅亭。", "此日即昨日，春過秋崢嶸。", "如何萬象間，寓我七尺形。", "忽憶縣以西，遠覽目屢經。", "前峰一鼇伏，遥巘千螺青。", "是窮天外勝，誰託世上名。", "翩翩佳公子，語秀含餘清。", "來此集賓客，溪山兩鍾情。", "亭如栖烟樹，客乃委浪萍。", "共此一時勝，遐哉萬古城。", "長歌白雲遏，落日金盃傾。", "我至將無時，庶以娛瞻聽。", "三嵎此其一，松柏爭敷榮。", "地靈瑩骨秀，不受紅塵攖。", "今朝動清興，有人踏皇扃。", "勝絕定何如，同起爲蒼生。"]'),
('60d33f36-0c1d-4492-9aee-3864f7f6ff39','遊城西李氏園李仁甫謝伯堅同會席中得當字','員興宗','宋','宋诗','song-poetry','','[]','吾生會如寄，俯仰歲月荒。',144,'全唐诗/poet.song.117000.json','["吾生會如寄，俯仰歲月荒。", "安得無盡境，寓樂窮時觴。", "朅來古城隅，露坐蔭石牀。", "皎皎月在野，山光映低昂。", "諸公飲文字，歌黛何由將。", "環客者誰歟，青青在吾傍。", "此君有令質，簡潔韻自長。", "一掃塵土想，化作冰雪腸。", "歲寒知幾何，衆木誰能霜。", "獨此抱身正，有耻踰平當。", "高度竟凜凜，不以外物攘。", "此會定清真，此懷爲君忘。"]'),
('01aac801-9717-4b2a-8793-91a91678b0f6','春遊分韻得雨字','員興宗','宋','宋诗','song-poetry','','[]','疎疎來往舟，續續後前雨。',48,'全唐诗/poet.song.117000.json','["疎疎來往舟，續續後前雨。", "湖光不自持，春色遽如許。", "日車忍停輪，塔鈴幸無語。", "沖懷宇宙寬，空濛我當取。"]'),
('6554cbe9-0fbb-4d18-a5c2-c5dfa34a9d87','諸公飲海棠下因賦韋陶體二首  其一','員興宗','宋','宋诗','song-poetry','','[]','相與飲花下，飲極人自歌。',60,'全唐诗/poet.song.117000.json','["相與飲花下，飲極人自歌。", "有酒不共盡，奈此春光何。", "翻愁白日短，勿厭紅樹多。", "樹多尚云可，紅落無停柯。", "萬象懸悲端，歸卧山之阿。"]'),
('ede1f7e7-a369-48dd-abac-7dd257d4c01e','諸公飲海棠下因賦韋陶體二首  其二','員興宗','宋','宋诗','song-poetry','','[]','雨露下澤澤，衆卉含新滋。',60,'全唐诗/poet.song.117000.json','["雨露下澤澤，衆卉含新滋。", "彼美海外棠，嫣然自繁枝。", "枝繁不忍折，與春作容姿。", "春容無定好，紛落青門道。", "故山菖蒲花，九節石上老。"]'),
('6683db6a-da5e-48e5-becf-9408d8689bb4','遺任子淵省元六首  其一','員興宗','宋','宋诗','song-poetry','','[]','山花亂紛葩，崇蘭度輕馥。',48,'全唐诗/poet.song.117000.json','["山花亂紛葩，崇蘭度輕馥。", "謂言抱正身，何以堪衆目。", "離披委叢萃，萬物困幽獨。", "美人尋當來，紉之佩空谷。"]'),
('7fbd8973-a0f5-4610-a308-dbfd9dd4f398','遺任子淵省元六首  其二','員興宗','宋','宋诗','song-poetry','','[]','平生數任李，異質苦同調。',60,'全唐诗/poet.song.117000.json','["平生數任李，異質苦同調。", "饑作一飽營，詞欲四裔照。", "蟲魚慎勿箋，皇墳可敷奧。", "我亦玩世者，畸言期久要。", "斯人竟天遊，出語仍奇妙。"]'),
('60f59b92-0560-4f67-b80c-cce981126b18','遺任子淵省元六首  其三','員興宗','宋','宋诗','song-poetry','','[]','何勞話前三，俱共入不二。',48,'全唐诗/poet.song.117000.json','["何勞話前三，俱共入不二。", "耕耕我村田，自免荆棘累。", "因茲等用舍，已作舟不繫。", "枯風掩我情，零露泫我淚。"]'),
('ea78c7eb-c076-469b-8308-7953a4e13cc2','遺任子淵省元六首  其四','員興宗','宋','宋诗','song-poetry','','[]','妙想語不周，中夜興抱膝。',60,'全唐诗/poet.song.117000.json','["妙想語不周，中夜興抱膝。", "憶昨親蛟蜃，風浪身惻惻。", "天意增吳濤，滄江渺何極。", "君舟且勿理，南首快所歷。", "何如西樓觀，蕉花紅正滴。"]'),
('add13c03-b903-404a-8302-855b9700416e','遺任子淵省元六首  其五','員興宗','宋','宋诗','song-poetry','','[]','我有二三子，文字粲彪炳。',60,'全唐诗/poet.song.117000.json','["我有二三子，文字粲彪炳。", "一說爲波臣，或傳近華省。", "豈徒異榮寂，又墮生滅境。", "懸知羣物攝，大類任毛穎。", "不如洗故習，長笑天地永。"]'),
('acdf2eef-6e5f-4546-87c6-52e176ed0ccf','遺任子淵省元六首  其六','員興宗','宋','宋诗','song-poetry','','[]','我興一枯枿，空此歲月度。',48,'全唐诗/poet.song.117000.json','["我興一枯枿，空此歲月度。", "公幹仍多難，病亦沉綿屢。", "象犀竟誰攬，漫衝江海霧。", "誰說官異人，我才止堪簿。"]'),
('df7a2187-3866-418f-bf47-1743af9ab048','送李省元周輔','員興宗','宋','宋诗','song-poetry','','[]','舟亦不肯駐，人亦不肯息。',96,'全唐诗/poet.song.117000.json','["舟亦不肯駐，人亦不肯息。", "君有浩蕩志，我带憔悴色。", "欣然別我去，吾寧旅終極。", "念昔始知子，氣度流輩百。", "元祐明公孫，對面想宿昔。", "馮翁口吃吃，遇子亦賓客。", "悼徃懷今茲，俯見江漢窄。", "一官家萬里，悵恍凍饑逼。"]'),
('0825add9-bb37-4fe2-92c9-e8eaed388283','管寧','員興宗','宋','宋诗','song-poetry','','[]','幼安湖海士，氣杳秋空雲。',48,'全唐诗/poet.song.117000.json','["幼安湖海士，氣杳秋空雲。", "遠目隘九州，誰識中領軍。", "真命寒柏獨，逸氣崇蘭熏。", "超遥首陽山，夫子猶二君。"]'),
('fc8df5ee-82cf-4a81-9c10-36855aa51c1a','阮籍','員興宗','宋','宋诗','song-poetry','','[]','我愛阮嗣宗，天懷達而放。',60,'全唐诗/poet.song.117000.json','["我愛阮嗣宗，天懷達而放。", "理觴墮沉冥，出語輒清曠。", "駕言窮所之，途窮涕亦浪。", "伊人已真契，誰謂失之蕩。", "夷庚得神超，世以多岐喪。"]'),
('47a17e3e-8091-4cdd-8f95-26125bb22fce','李巽巖四望樓','員興宗','宋','宋诗','song-poetry','','[]','青青十二樓，萬瓦浮雲稜。',288,'全唐诗/poet.song.117000.json','["青青十二樓，萬瓦浮雲稜。", "居者誰氏子，酒肉堆丘陵。", "一一閒峨眉，捨此不爲登。", "清夢幾時回，何曾舍虛凝。", "本欲了萬境，竟爲景所繩。", "我友子真子，士以古誼徵。", "載書來上都，結朿車不勝。", "插架備小築，且以觴賓朋。", "或人指之笑，謂此不能宏。", "有如短尾航，又如朿翅鷹。", "團疑戀殻龜，局類遭寒蠅。", "卑卑形覆缶，短短射依堋。", "行行頻壁礙，倚倚難軒憑。", "風立苦打頭，月坐傷橫肱。", "寒足籠擁掩，炎軀甑炊蒸。", "俯首忽見地，閉目可數層。", "何當攬星辰，惟堪掛用繒。", "君子促改辦，不爾陋可憎。", "我興聽是說，諸友無乃稱。", "交從二十年，我能識其膺。", "彼腹椰子大，千卷貯亦曾。", "體作黄冠樸，言乃水雲僧。", "豈其八尺高，而能礙晨興。", "瞻想西南北，衆萬皆環緪。"]'),
('b424586c-6d92-4a29-a680-43ffa54765c3','平等寺','員興宗','宋','宋诗','song-poetry','','[]','萬籟久已息，幽鳴竟天和。',48,'全唐诗/poet.song.117000.json','["萬籟久已息，幽鳴竟天和。", "川靈如有知，野鳥時驚柯。", "明月照我衣，我起聊自歌。", "無酒今可觴，如此良夜何。"]'),
('cb0f548a-e6ea-4930-b77e-691847ad3d27','即事','員興宗','宋','宋诗','song-poetry','','[]','我本不即世，世網以維之。',60,'全唐诗/poet.song.117000.json','["我本不即世，世網以維之。", "維之意何傷，俯仰百念衰。", "清真寓天壤，誠盡復誰欺。", "情忘物自遣，深虞未忘時。", "平生寄筆墨，幽解畧自茲。"]'),
('ebe83163-cdd0-401a-a5ea-aaf544b43063','述古','員興宗','宋','宋诗','song-poetry','','[]','道渾語不枯，意盡文自止。',48,'全唐诗/poet.song.117000.json','["道渾語不枯，意盡文自止。", "思成繭抽緒，渙若風行水。", "恭惟古先民，吾今亦如此。", "誰歟章句繪，碌碌寄餘子。"]'),
('a38bf832-c501-40d2-a22d-49cc9ab044d8','自荆入沌至鄂凡十日沌中','員興宗','宋','宋诗','song-poetry','','[]','長蘆衝短蘆，挽船如挽車。',144,'全唐诗/poet.song.117000.json','["長蘆衝短蘆，挽船如挽車。", "一縷江摇天，縈带千里餘。", "時焉忽斷岸，依依見幽居。", "試問居者誰，此地家焉如。", "居者顧我笑，官何問之愚。", "一生宅莽蒼，豈覺城市娛。", "出戶舟爲步，入戶羹爲魚。", "田牧我有時，牛羊與之俱。", "但願秔稻豐，俯仰無所須。", "山河總白日，城市仍丘墟。", "我興愧其言，勞生嘆囚拘。", "因笑永民鼠，人大長狙狙。"]'),
('5de94c9f-32f0-41c1-acd7-7ea327014cb8','送校理梁同年子輔守彭門','員興宗','宋','宋诗','song-poetry','','[]','衆萬欣有託，我興渺無依。',144,'全唐诗/poet.song.117000.json','["衆萬欣有託，我興渺無依。", "軻雄去則久，道論何其衰。", "味薄成抱惡，時趨化心低。", "豈謂杳莽中，有子相嬉嬉。", "君乃柏下苓，我乃松間絲。", "河關兩值遇，綢繆竟天姿。", "直我我即敬，曉我我自思。", "如何萬里舟，忽去不可維。", "頻變覺情易，人遠中自移。", "持杯動孤影，秋風又凄其。", "去日懸幾許，重來傍衰遲。", "渾渾皓首交，願言固來茲。"]'),
('fdb35712-7901-4e6e-bdfd-b3aa73a0c24c','送關國錄守簡州','員興宗','宋','宋诗','song-poetry','','[]','生世事憂喜，擾擾合與分。',288,'全唐诗/poet.song.117000.json','["生世事憂喜，擾擾合與分。", "合即海上鷗，分乃風中雲。", "分合懸有定，誰能預戚忻。", "心空等行脚，得酒且策勳。", "念昔求見子，相看每相羣。", "夤緣再值遇，天南話鄉枌。", "朝聲並屋喧，夜飲竟面醺。", "我遇不易振，但知祖皇墳。", "君言時作我，神機謝耡耘。", "如何日蹙唧，蹙唧向我云。", "自來越上吟，五別西山芹。", "緬然動中懷，羈心爲之焚。", "辭殫起後慮，徃勇稽前聞。", "歸思溢浩浩，江流泛沄沄。", "君鞭先我著，我其敢後君。", "蜀遠誰肯顧，萬里乘華勛。", "國恩自丘山，彼此當勤勤。", "况復坐紅日，椒桂來奇芬。", "人生行樂爾，妙寄窮天垠。", "却寫分外慮，太空鼓蠅蚊。", "君行不作癡，我將理吾軍。", "漸營卓錐地，遺書收放紛。", "故家通社臘，與子同朝曛。", "斯言不自領，請移北山文。"]'),
('b576229a-8a3a-41e9-90df-f50ec9e04f81','宜賓別楊同年','員興宗','宋','宋诗','song-poetry','','[]','江行駭湍濤，文字無暇尋。',168,'全唐诗/poet.song.117000.json','["江行駭湍濤，文字無暇尋。", "滿聽舟人歌，胸中垢穢侵。", "宜賓夷獠鄉，繫纜日欲沉。", "倉卒拜年契，外堂聞韶音。", "雞肥爲予烹，酒美亦共斟。", "語笑不知夕，蟾蜍滿衣襟。", "首陳兵戰謀，西北敵可擒。", "次論月蝕詩，獨採仝愈心。", "未憎輕簿走，竊譽希山林。", "儒學規矩奇，約繩固所欽。", "誓將革愚魯，庶異柴與參。", "會淺別又長，情重愁愈深。", "願終保壯節，勿作澗松吟。", "天子思太平，此非久滯淫。"]'),
('704002ec-a158-4d09-8641-a2dfc50d054c','哭待制許先生','員興宗','宋','宋诗','song-poetry','','[]','平生一靈臺，機智得深屏。',48,'全唐诗/poet.song.117000.json','["平生一靈臺，機智得深屏。", "出使星移天，歸朝月生嶺。", "上書肺肝露，不事頰舌逞。", "事狀嚴歷歷，九原忽蘇醒。"]'),
('3cd32e6d-2ea8-4b0f-b619-aebda11c88df','夢邴徵君','員興宗','宋','宋诗','song-poetry','','[]','我夢窮躋攀，滑滑泥掩胯。',108,'全唐诗/poet.song.117000.json','["我夢窮躋攀，滑滑泥掩胯。", "我自摩天嶺，而轉風木榭。", "有客冠甚峩，見之驚已乍。", "邴姓原其名，風流蔑曹謝。", "賓我復坐我，豐草殊可藉。", "英言有深吐，微論亦高駕。", "與原濶千祀，待我仍管華。", "斯人竟天遊，神尻不暫卸。", "願言赴汗漫，同予觀物化。"]'),
('2b54cb1d-00ae-4263-a6cd-69c1581e5b23','題山月水月二亭','員興宗','宋','宋诗','song-poetry','','[]','山月照我形，水月澡我神。',192,'全唐诗/poet.song.117000.json','["山月照我形，水月澡我神。", "對月淚已波，尚想亭之人。", "高懷寓玄照，清晤逃時紛。", "老我竟誰憐，歲月空崢嶸。", "寒光注夜夜，瓊樹舒冥冥。", "而子於是間，逸抱回天真。", "我時走浩蕩，乾坤渺虛營。", "文字掛衆陋，一縱不可循。", "子起笑謂言，世念違紅塵。", "忘言亦忘默，第飲千盃醇。", "藉我月下草，枕我亭邊雲。", "遊將躡天去，寸步逶迤親。", "故人今何許，白日仍西傾。", "悼徃迹已邁，趨交意彌屯。", "尚爾一徑迷，烟草空亭亭。", "何當三千秋，歸鶴驚四鄰。"]'),
('58bf48ab-a5d3-41c2-a20f-cae223e981a1','挽二叔通直','員興宗','宋','宋诗','song-poetry','','[]','知公經術富，少小足奇尚。',180,'全唐诗/poet.song.117000.json','["知公經術富，少小足奇尚。", "堂堂蘭茁芽，願言契新賞。", "蕭條度風霜，汴西鞍馬上。", "暫行幾羊腸，世路蛛自網。", "綠衣一秋荷，而能脫塵鞅。", "聖言得微奧，理明詞亦暢。", "有文不带酸，餘味甚熊掌。", "其中殆天全，識解自超曠。", "事佛當晚年，精神著內朗。", "禪談水月澄，逸韻天風爽。", "我昔尚童子，門戟過雙敞。", "而公見之喜，單辭幸相廣。", "勵我多苦心，寒庖對珍享。", "山花草然然，胡爲歲月往。", "瑞蘭期遠插，庶以慰黄壤。"]'),
('2c6448ff-0dd8-4d56-bb5f-9fbe93ae428a','州以隆名誠盛事也父老歡喜一詞僕亦感且慰因賦詩以志其盛','員興宗','宋','宋诗','song-poetry','','[]','青峰高隆隆，赤縣垂世世。',48,'全唐诗/poet.song.117000.json','["青峰高隆隆，赤縣垂世世。", "俯仰或百年，興衰寄一字。", "有人紀國勳，今日起天意。", "父老歡不徹，衢歌傳盛事。"]'),
('6760fa1f-39cc-4d83-9bca-0a3872db0ef2','詠鷄頭','員興宗','宋','宋诗','song-poetry','','[]','桃李妍衆目，取次紅綠插。',72,'全唐诗/poet.song.117000.json','["桃李妍衆目，取次紅綠插。", "練練湖中姿，佳菓鬚作鐵。", "名字勝且高，意亦倣鷄舌。", "黧面君莫侮，滿腹珠璣列。", "昔者靈沼會，賦就蘇子轍。", "只今風味遠，是說非密說。"]'),
('399f46f1-6a72-4197-92d9-0379ca083d03','詠蛤蜊','員興宗','宋','宋诗','song-poetry','','[]','君起西南思，爲予疊前篇。',72,'全唐诗/poet.song.117000.json','["君起西南思，爲予疊前篇。", "我興樂東南，珍烹口同然。", "佳哉有蛤氏，商略依舜泉。", "馬刀形則古，瓦屋蟲能天。", "入手意便韻，况余謝葷羶。", "何必逢麴車，爲君口流涎。"]'),
('6b8caedc-0c03-44ee-829c-e43e9f905fb7','詠江鰩','員興宗','宋','宋诗','song-poetry','','[]','鮮鮮眼中瑶，玉柱出珍抱。',72,'全唐诗/poet.song.117000.json','["鮮鮮眼中瑶，玉柱出珍抱。", "吾家天萬里，識君恨不早。", "携來定雪兒，中膏非外槁。", "不知何物尤，醉臉茲一掃。", "平生珠爲鄰，冰盤仗幽討。", "或言比丹荔，同傳韓非老。"]'),
('313963f2-baa8-4c75-a27d-815828f1d2e2','賀雨','員興宗','宋','宋诗','song-poetry','','[]','歲若大旱作霖雨，禱而雨兮旱不苦。',352,'全唐诗/poet.song.117000.json','["歲若大旱作霖雨，禱而雨兮旱不苦。", "誠之一字與天參，往古聖賢珍此語。", "歲星在蜀二十年，觸處豐登多黍稌。", "世不少惜蹂踐之，枉使寶稼棄如土。", "况復縱恣相憑凌，氣焰熏天遽如許。", "三綱五常淪且斁，以故傷和逢癉怒。", "旱魃爲災熾袢暑，撲鹿陽烏乘九數。", "火雲釜甑蒸肉山，不奈炎官云我所。", "公方憂民心瘉瘉，掃除熱瘴還清楚。", "却憶曾侍玉帝旁，授以金科行按部。", "辦獄更過顔魯公，一路傳呼御史雨。", "不聞匹婦且銜冤，西蜀向安誰敢侮。", "和以致祥應止止，喜見太平舊官府。", "肅時若是號休徵，甘澤霑霈來以敘。", "石燕漫飛商羊舞，穴處那能問狐鼠。", "巫覡罷散鼓笛閒，龍德欲歸江海去。", "爲言西成祀田祖，飽食不驕民樂聚。", "昔何戚嗟今怡悅，力回造化公爲主。", "濯濯厥靈玉不焚，伊格皇天歸宰輔。", "燄燄無若雨反風，燮理陰陽且封魯。", "禦災捍患世亦希，可但明時繼前古。", "願言霖雨思賢佐，鎸入堅珉作詩譜。"]'),
('a5530875-7895-4b1a-b347-792ef128761f','遊漢嘉明月湖次宇文子重韻','員興宗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君不見天台賀季真，鑑湖一曲光泠泠。',162,'全唐诗/poet.song.117000.json','["君不見天台賀季真，鑑湖一曲光泠泠。", "又不見錢塘林處士，西湖千載成高名。", "千頃菰蒲抹岸白，幾樹寒梅踈影橫。", "呼吸湖光映湖綠，兩公便謂得此生。", "吾僚胸次本丘壑，中有林賀之高情。", "銀盤夜色清鏡動，便欲邀汝成三人。", "旋喜叵羅金在眼，肯議仙桂來無根。", "前時六濁皆運出，招此不夜歸重城。", "未蒙濡沫到惡客，先苦詩句來繽紛。", "思君對洗同一靜，大勝狂歌歸四明。"]'),
('2abc9d3e-2205-4284-8082-02ac9471e267','紫雲洞','員興宗','宋','宋诗','song-poetry','','[]','君不見茂州長史文章翁，生平姓字懸天東。',281,'全唐诗/poet.song.117000.json','["君不見茂州長史文章翁，生平姓字懸天東。", "英言撼帝帝不從，建隆以來無此忠。", "今焉棲神寓玄躬，道在翳嘶峰外之高峰。", "是間真趣排天胸，指顧可了荆岱嵩。", "邇年秋練春光融，離離渡漢舒溟濛。", "狀殊宋車非越龍，亦非石壁浮青紅。", "望之雲遠討其蹤，類風飄煙欺霧濃。", "直排閶闔貫紫宮。", "父老語我昭我聾，疑是先生不掩之精雄。", "自爾支拄瓊崖中，要把英爽飛摩空。", "有如韓王結襦騰騰化異氣，亦如衛生食昴疊疊欺長虹。", "誠於斯民有願力，此段奇特將無同。", "先生英名無有盡，乃雲無心洞無窮。", "或云礱鑿發天秘，不知的的勝事符阿戎。", "勸君不必崑閬通，五雲之祥由李宗。", "君家種義昭玄穹，可隸黄字驅青童。", "掃灑願勿俗子容，斗酒爲嗔王無功。"]'),
('ea2e418b-c6d1-4afa-9490-3a58b2d6b5f6','瑞芝','員興宗','宋','宋诗','song-poetry','','[]','君不見翳嘶路轉重行行，玉几有洞含餘清。',227,'全唐诗/poet.song.117000.json','["君不見翳嘶路轉重行行，玉几有洞含餘清。", "跨鼇棲魂正爾所，合沓萬古遺忠名。", "洞口雲騰紫羃羃，洞外草茁未英英。", "從來精爽自難沒，地不愛寶天敷榮。", "嘉祥一書世則瑞，而况君家二者并。", "請原昨日盃酒事，公子沃客金盃傾。", "有童有童跪再拜，云得異本由天成。", "主人于于衆客笑，春入四座歡縱橫。", "夜如何其不忍去，翦燭細看枝瓊瓊。", "有同魏縣玉三幹，大似漢宮金九莖。", "巖間義氣埋不得，宛轉再露乾坤情。", "公子世猷亦有相，他山之石何由生。", "願言勿隠東郭几，穩出卧護南陽城。", "天邊瑞蓋兩旌節，我相公子非癯卿。"]'),
('523fcb3b-cb01-45d4-b65e-b2d0707d35d5','歌兩淮','員興宗','宋','宋诗','song-poetry','','[]','君不見北風吹淮風浪黑，鐵馬千羣凝一色。',391,'全唐诗/poet.song.117000.json','["君不見北風吹淮風浪黑，鐵馬千羣凝一色。", "當時廟論孰經濟，將相無言潛動魄。", "或云南紀當何憂，今代諸葛身姓劉。", "陸下喚取守淮甸，彼有勝算踰干矛。", "登時詔語從天墜，汜爲先鋒錡制置。", "併遣健士付阿權，等是兩淮兵馬地。", "豈期將潰兵川流，翻手忽忽無十州。", "前時冠劍錯準擬，此事吐口貽人羞。", "幸哉天禍不終極，至尊避殿憂思集。", "樞臣督戰侍臣謀，上則倚公叅贊職。", "征鞍此日去皇皇，所過騎士多羸傷。", "不見何人出聲鼓意氣，但見十十五五坐路傍。", "公趣下馬詢衆語，衆共來前致辭苦。", "平時節使驅爲奴，逐逐無聊戰無主。", "而今側身墮兩失，官騎已亡難再得。", "誠令軍政日月懸，我有微軀人不惜。", "公聞瑟縮涕潸然，汝曹寄命真可憐。", "朝今清明萬乘聖，權已殛死家南遷。", "若等是行能奮死，朝建勳名暮朱紫。", "官今付我誥如山，節使察使皆在此。", "軍家聞此逐蹄輪，喜氣酣酣如遇春。", "當時戰死身昧昧，今日分付當其人。", "兵官來見同聽命，適有時張王戴盛。", "分麾列伍擺布畢，髣髴平戎萬全陣。"]'),
('958ff99b-937f-45fe-9409-5cf35f8b97a9','永嘉水','員興宗','宋','宋诗','song-poetry','','[]','鄭侯興言水于溫，厥災茫昧數莫源。',384,'全唐诗/poet.song.117000.json','["鄭侯興言水于溫，厥災茫昧數莫源。", "于時頑秋後中元，淫虹曳曳妖暈噴。", "夜星不呈墨微垣，鬰律撼怒排天根。", "擺磨雜嶽濤飛軒，豁驚瞥悚勢蕩渾。", "凶颶埽寬震虛垠，瀿傾瀆裂軸轉坤。", "腷膊萬馬來聲喧，衆鼓駭駭闐箎塤。", "湠漫沏送無回沄，陰旄威纛空飛騫。", "嬰鮐漂沛趨冥門，带不不屬隳巾褌。", "啾呶直上聲天冤，元驅鬼紲俱奔奔。", "肉不擁掩張髀臀，母識子死翁號孫。", "凌耶厲耶千山髠，而况下數鷄鼠豚。", "濘淖飛濺疑翻盆，岸津水溽沸鵰猿。", "目材耳井其能存，我知其端義可援。", "無乃水伯真少恩，翹翹抉抉兇凌屯。", "手擘三山巨靈翻，大漚幕島叢旗㠾。", "天吳不仁閃雙湲，主張龍孽龜魚黿。", "牙眼怖鰐翼厲鯤，唅呀擺掉齒腭反。", "禹手不胼息兩跟，四載難乘駐厥轓。", "漢家循河昔墊昏，側身以蔽太守尊。", "淛東之東孰於藩，赤子魚頭浸莫言。", "帝階修修闢重閽，媕娿欺天樹幽怨。", "沉家十萬忍不論，誰歟廣騷些其魂。", "幸哉皇明煦朝暾，羅金走帛恩丘園。", "我咨溫人爲周爰，河魁之應顛崑崙。"]'),
('ff87a460-95a2-446d-b92a-61985b63ea73','遊九頂清音亭次宇文子重韻','員興宗','宋','宋诗','song-poetry','','[]','君不見昔賢聲名渺雲邊，追慕茫茫千百載。',165,'全唐诗/poet.song.117000.json','["君不見昔賢聲名渺雲邊，追慕茫茫千百載。", "東山遺墨不塵埃，南海碑辭尚光彩。", "是公胸懷冰鏡清，當時玉署厭殘更。", "惟餘清夢到古寺，因爲亭宇加修名。", "亭邊古洞可治易，何必竹溪師六逸。", "清音不斷山不磨，人間衮衮成今昔。", "徃日中都朋黨興，賢者皆思御李膺。", "元祐諫紙今最重，此亭返不蒙知音。", "我聞膠西黄樓賓主列，賦就價喧君弟轍。", "彼樓雖已陷幽都，名號猶爲人記別。"]'),
('e723d294-7a15-41bd-b6e7-f14084f12d5d','菜食','員興宗','宋','宋诗','song-poetry','','[]','員子一寒世無有，愛簇生盤如愛酒。',64,'全唐诗/poet.song.117000.json','["員子一寒世無有，愛簇生盤如愛酒。", "菠薐鐵甲幾戟唇，老莧緋裳公染口。", "駢頭攢玉春試筍，掐指探金暮翻韮。", "達官堂饌化溝坑，我誦菜君人解否。"]'),
('5c63c942-7fc4-4782-b8b9-031f45563917','酬新安仁孝主簿','員興宗','宋','宋诗','song-poetry','','[]','汴水奔流天子都，海涵百谷來羣儒。',200,'全唐诗/poet.song.117000.json','["汴水奔流天子都，海涵百谷來羣儒。", "黑笠白袍紛盈衢，清才落筆各有徒。", "人人懷矛戈戟殳，文陣未戰磨以須。", "我方整旅備不虞，坐驚縶微黨援孤。", "聞君烈烈真丈夫，外視宮室呈廉隅。", "於時委身願投壺，亦既見止心則愉。", "聯翩折趐同嗟吁，奈何西歸不得俱。", "地遠天高成異區，尺書相問藥困痡。", "繼之詩句非常模，字妙羲獻堪僕奴。", "幽懷感深長鬰紆，魚目安可酬驪珠。", "古今窮達猶摴蒱，慎無致意榮且枯。", "六經且務評精粗，一朝良媒聘閭娵，神房山館魁衆姝。"]'),
('3f7168e1-4288-4cc2-a17a-bf03d37a1d63','哭友人故校書王君夷仲','員興宗','宋','宋诗','song-poetry','','[]','天台插天天一色，先生乃在山之側。',163,'全唐诗/poet.song.117000.json','["天台插天天一色，先生乃在山之側。", "擁書萬卷日逍遥，戶外絕無塵土客。", "自跡詩書分戰場，垂垂六甲皆科郎。", "治言說盡萬物理，亦有苦語原天荒。", "保寧之軍憤苛取，大夫回回軍吏苦。", "公來約束仗忠信，健兒三千膽如鼠。", "倦遊俯仰栖瀛洲，吏非散仙矧肯留。", "金門間作林下語，對之使我銷百憂。", "人皆病心公病膝，歸卧輕舟江月夕。", "君不見書劍只今誰訪君，靈鷲蕭蕭墓三尺。"]'),
('93ccc3ff-91ff-4280-a58d-6eb570950bb5','贈呂德璋道人','員興宗','宋','宋诗','song-poetry','','[]','世綱連天天地窄，君乃對人眼青白。',64,'全唐诗/poet.song.117000.json','["世綱連天天地窄，君乃對人眼青白。", "口占道論餘五千，身徃仙山尋八百。", "趙侯精靈足詩態，員子慚愧今詞伯。", "不須對月人自三，他年共作滄浪客。"]'),
('802a2daa-a0b3-44cf-9663-bf6dd75c5ce2','別眉山源上人','員興宗','宋','宋诗','song-poetry','','[]','我生喜際招提客，欲宜漚幻了塵色。',131,'全唐诗/poet.song.117000.json','["我生喜際招提客，欲宜漚幻了塵色。", "偶然揮斥仍六極，無相光中豈南北。", "上人得我慰寂寞，相與含笑了一默。", "生死奪機無瞬息，禪談鶻落霜後翼。", "中間鵠鵠露白黑，我欲角角急不得。", "終朝爲子寫胸臆，回首江山忘鄉國。", "相看一夢非空質，山風吹衣馬去櫪。", "君不見九華雖墮名利場，逢人也解吞荆棘。"]'),
('03ddf475-31b0-4ec4-9423-a6489b3e8f62','贈雲上人','員興宗','宋','宋诗','song-poetry','','[]','君不見昔日中巖印元發，聲名宇縣何煌煌。',195,'全唐诗/poet.song.117000.json','["君不見昔日中巖印元發，聲名宇縣何煌煌。", "層冰瑩骨語秀靜，松風入齒詩清狂。", "有時健筆賦巖石，天地萬象隨低昂。", "儒流稽首頌舌相，徃徃謂带花木香。", "自從別我無消息，江鰐無情江浪黑。", "至今夾岸楓林青，歲老迷魂招不得。", "古來英才多薄命，杳杳湘潭絲五色。", "世間妙質便恐無，使我哀吟纏八極。", "豈料嘉川餘舊遊，雲來雲來開我愁。", "時吐芳鮮恣吞嚼，軟語髣髴從湯休。", "勞生乾坤我已倦，飲半一嘯滄浪舟。", "三峨聯子憩寂寞，下視華屋皆山丘。"]'),
('46864a23-ec16-4409-a087-984738fe50ba','挽喻夫人','員興宗','宋','宋诗','song-poetry','','[]','太丘落日東郊昏，蘭風桂露啼幽痕。',80,'全唐诗/poet.song.117000.json','["太丘落日東郊昏，蘭風桂露啼幽痕。", "年周九十笑語溫，衝頭雪矣花仍存。", "仙裾拂拂始倚門，扶挾何必煩諸孫。", "二鶵前起慰心魂，喻宗老人五院尊。", "衆口咽矣遍地恩，柔則之餘六四坤。"]'),
('f7f72f21-a3e5-4d2e-a1eb-75412b5cd4b1','送崔子淵登第西歸','員興宗','宋','宋诗','song-poetry','','[]','少日家鄰社，生年說二崔。',48,'全唐诗/poet.song.117000.json','["少日家鄰社，生年說二崔。", "諸孫接高第，吾子更長才。", "意逐歸鴻急，身疑社燕回。", "再逢却持酒，同上望鄉臺。"]'),
('63cad8fc-dba8-4ca5-8ed4-22a058f2ca11','春日過僧舍','員興宗','宋','宋诗','song-poetry','','[]','青春了無事，挈客上伽藍。',48,'全唐诗/poet.song.117000.json','["青春了無事，挈客上伽藍。", "遥指翠微樹，來尋尊者庵。", "不須談九九，何必論三三。", "且坐吃茶去，留禪明日叅。"]'),
('cd75130c-7098-404f-bea2-d3917662dcbb','海波','員興宗','宋','宋诗','song-poetry','','[]','上妙空王殿，靈神不敢窺。',48,'全唐诗/poet.song.117000.json','["上妙空王殿，靈神不敢窺。", "乾坤捧兜率，日月遶須彌。", "八柱真如宰，三山自不奇。", "海鯨吞巨浪，只要十分詩。"]'),
('e884e525-d202-4b38-92d2-f402859d3645','秋興','員興宗','宋','宋诗','song-poetry','','[]','商君寧暫駐，日轂不停翻。',48,'全唐诗/poet.song.117000.json','["商君寧暫駐，日轂不停翻。", "白鳥歸何處，黄花又一番。", "異鄉曾蝶夢，今日伴鼇山。", "幽事仍關目，巖雲相對還。"]'),
('0822c89a-26d2-438b-a7e7-e2232d73001b','挽喻朝奉','員興宗','宋','宋诗','song-poetry','','[]','九十老生涯，緋衣落照斜。',48,'全唐诗/poet.song.117000.json','["九十老生涯，緋衣落照斜。", "長安三度客，蜀縣半庭花。", "飯素匙抄雪，麻頭韈带沙。", "秋風空色相，飛入梵王家。"]'),
('1a0a1b7b-475f-4c6f-a5d7-83d9430fc55a','挽夔路帥韓徽猷  其一','員興宗','宋','宋诗','song-poetry','','[]','先聲一鶚天，萬點蜀山懸。',48,'全唐诗/poet.song.117000.json','["先聲一鶚天，萬點蜀山懸。", "天子留英閣，君王問進賢。", "玉書遺二冊，金馬獨三年。", "胄子文書活，花間愧管弦。"]'),
('8a7e5176-bba6-4ba9-87d4-8e20e9ef453a','挽夔路帥韓徽猷  其二','員興宗','宋','宋诗','song-poetry','','[]','敵舫浪花翻，瞿塘動暗關。',48,'全唐诗/poet.song.117000.json','["敵舫浪花翻，瞿塘動暗關。", "君因漢戈甲，守固蜀江山。", "軫域澧渝接，樓船灧澦閒。", "如何寧邑事，不屬邇臣刪。"]'),
('2343bd9a-dc2a-400d-aee8-c6fd23fc57cc','挽夔路帥韓徽猷  其三','員興宗','宋','宋诗','song-poetry','','[]','若試遷都策，山東自不灰。',48,'全唐诗/poet.song.117000.json','["若試遷都策，山東自不灰。", "政刑仍玉雪，議論亦風雷。", "瑞竹雙光斷，靈襟一夢摧。", "而今夔子國，廟貌日悠哉。"]'),
('51c21d1d-5277-4a49-886e-43479629d451','挽待制許先生  其一','員興宗','宋','宋诗','song-poetry','','[]','尚憶西方守，輸忠北斗邊。',48,'全唐诗/poet.song.117000.json','["尚憶西方守，輸忠北斗邊。", "疲氓千里裕，破竈萬家煙。", "桃李不言處，虎狼今滿廛。", "傳聞澈泉淚，半在蜀南偏。"]'),
('72527fc6-9f88-4f23-952f-8a431370276b','挽待制許先生  其二','員興宗','宋','宋诗','song-poetry','','[]','宣室來何暮，都門價已喧。',48,'全唐诗/poet.song.117000.json','["宣室來何暮，都門價已喧。", "皂囊說二六，白髮任三千。", "國老躬爲地，羣飛哭刺天。", "門扃許見否，真氣閟元泉。"]'),
('5440469e-a94b-4f24-a0d2-fd82b560c282','挽待制許先生  其三','員興宗','宋','宋诗','song-poetry','','[]','衛幕昔年開，西英續續來。',48,'全唐诗/poet.song.117000.json','["衛幕昔年開，西英續續來。", "諸公叅牧政，愧我忝書臺。", "徃事風流盡，於今志念灰。", "侯芭萬感集，空抱報恩顋。"]'),
('caab54e0-8a46-468f-bd90-4f6950fff847','哭劉夷叔  其一','員興宗','宋','宋诗','song-poetry','','[]','迥迥江湖興，乾坤墮渺茫。',48,'全唐诗/poet.song.117000.json','["迥迥江湖興，乾坤墮渺茫。", "近傳行在信，爲報故人亡。", "蓮社今誰繼，詩壇竟不昌。", "無家成句法，佇立泣斜陽。"]'),
('95e280a0-b68b-4158-8bbc-c676db741df2','哭劉夷叔  其二','員興宗','宋','宋诗','song-poetry','','[]','何人言曠遠，吾子了希微。',48,'全唐诗/poet.song.117000.json','["何人言曠遠，吾子了希微。", "幸有青雲志，如何白骨歸。", "空江流蜀恨，哀雁帖雲飛。", "若箇情親者，滄洲有願違。"]'),
('ae1f1f62-3654-4dad-b08e-72804e6f9b41','哭黄省元貢  其一','員興宗','宋','宋诗','song-poetry','','[]','故國地靈處，人文天意深。',48,'全唐诗/poet.song.117000.json','["故國地靈處，人文天意深。", "公從捫膝子，句亦掉頭吟。", "白雪雙歌斷，歸雲無路尋。", "祈招渾簡遠，我念正愔愔。"]'),
('f578968a-a763-412f-b578-69c5bef76176','哭黄省元貢  其二','員興宗','宋','宋诗','song-poetry','','[]','惜昔豺狼路，喧卑燕雀羣。',48,'全唐诗/poet.song.117000.json','["惜昔豺狼路，喧卑燕雀羣。", "誰歟非楚咻，何者避秦人。", "黄卷中如律，青雲斷後塵。", "幼安湖海趣，百世不荆榛。"]'),
('9edbe112-3ed0-4f56-98c5-3ea11f3b31a6','挽范通直','員興宗','宋','宋诗','song-poetry','','[]','羈遊不記春，書劍老風塵。',48,'全唐诗/poet.song.117000.json','["羈遊不記春，書劍老風塵。", "爲問長頭事，無踰四乳人。", "青衫經濟念，白髮苦吟身。", "尚想忠文舊，天涯淚滿巾。"]'),
('95bda56a-467b-45ab-a417-79175fca6899','壽虞丞相  其一','員興宗','宋','宋诗','song-poetry','','[]','今年輔相得真儒，和氣融融慶曆初。',64,'全唐诗/poet.song.117000.json','["今年輔相得真儒，和氣融融慶曆初。", "一柱擎天隆廟社，三邊無地著兵車。", "功名入手歸談笑，操畧隨時自卷舒。", "萬歲千秋臣主願，未饒兩紀說中書。"]'),
('061eb4a5-3d03-45a7-9b62-bc72cbee7435','壽虞丞相  其二','員興宗','宋','宋诗','song-poetry','','[]','敬捧仙家九醖觴，試將窺管述鉛黄。',64,'全唐诗/poet.song.117000.json','["敬捧仙家九醖觴，試將窺管述鉛黄。", "功名采石乾坤大，議論襄城日月長。", "收拾元勳歸鼎鼐，扶持公道起膏粱。", "敵人正爾咨年貌，莫放青青鬢染霜。"]'),
('736bb52d-74e1-479e-802b-5523e2b5bd76','壽虞丞相  其三','員興宗','宋','宋诗','song-poetry','','[]','海上三神絕地維，巨鼇移著劍峰西。',64,'全唐诗/poet.song.117000.json','["海上三神絕地維，巨鼇移著劍峰西。", "山高自昔翔鸞鳳，人傑於今拔象犀。", "夢說已知箕尾近，生申還與嶽嵩齊。", "他年要作封留地，便覺峨眉氣象低。"]'),
('cfcdfe7f-76ac-49e0-899a-632640a2493e','壽虞丞相  其四','員興宗','宋','宋诗','song-poetry','','[]','命圭相印錫元勳，天子龍飛第八春。',64,'全唐诗/poet.song.117000.json','["命圭相印錫元勳，天子龍飛第八春。", "昨夜老人推甲子，明朝寶牒換庚寅。", "壺中日月胚胎久，掌上乾坤把握新。", "二十四年黄閤樣，坐看霜雪到松筠。"]'),
('3de2b2cd-6268-47e0-99b8-81dc28c7bc82','壽虞丞相  其五','員興宗','宋','宋诗','song-poetry','','[]','中使傳聲出禁闈，曉庭烏鵲繞簷飛。',64,'全唐诗/poet.song.117000.json','["中使傳聲出禁闈，曉庭烏鵲繞簷飛。", "天香暗度金虬暖，詔墨遥迎彩鳳歸。", "四海每年歌詠滿，兩宮傳賀古今稀。", "殷勤更有南星極，長伴文昌拱太微。"]'),
('6de7fedc-781c-422e-bab8-2374f7b65bc2','壽虞丞相  其六','員興宗','宋','宋诗','song-poetry','','[]','三邊騎火照桃林，髀骨渾驚歲月深。',64,'全唐诗/poet.song.117000.json','["三邊騎火照桃林，髀骨渾驚歲月深。", "衮繡東征非有意，衣冠南渡不甘心。", "人皆穩步金懸印，公爲捐軀雪滿簪。", "將相勳名千古事，試將全傳細推尋。"]'),
('4587759d-6151-4a88-9f16-35dcbb08ba89','壽虞丞相  其七','員興宗','宋','宋诗','song-poetry','','[]','吐握勤勞只自卑，人希賓退欲歸時。',64,'全唐诗/poet.song.117000.json','["吐握勤勞只自卑，人希賓退欲歸時。", "一編燈火重簾靜，萬里關河夢枕欹。", "周召成名須保義，蕭曹何事盡規隨。", "維新造化今將始，魚躍鳶飛物物宜。"]'),
('0c17984f-e26f-4806-9d32-d5940c664888','壽虞丞相  其八','員興宗','宋','宋诗','song-poetry','','[]','千齡期運到如今，古佛更生願力深。',64,'全唐诗/poet.song.117000.json','["千齡期運到如今，古佛更生願力深。", "鼎鑄萬方陶冶地，燈傳一點聖賢心。", "全機徑度曹溪水，大地同霑傅野霖。", "從此不須憂歲旱，桑麻處處樹陰陰。"]'),
('dbb67d0a-24c3-43d8-b89a-ed3b8fd390c8','壽虞丞相  其九','員興宗','宋','宋诗','song-poetry','','[]','黄道初開御幄新，山呼動地聽絲綸。',64,'全唐诗/poet.song.117000.json','["黄道初開御幄新，山呼動地聽絲綸。", "人間喜見新丞相，江上猶呼舊舍人。", "此事十年爭屈指，於今四海在洪鈞。", "調元別有無邊手，付與江山自在春。"]'),
('d5783f3a-e107-4d4d-9fbd-98b8c5b3eee1','壽虞丞相  其一○','員興宗','宋','宋诗','song-poetry','','[]','冠裳初集大明宮，祗倚堂堂廟柱雄。',64,'全唐诗/poet.song.117000.json','["冠裳初集大明宮，祗倚堂堂廟柱雄。", "門外問年驚潞國，陣前克敵記萊公。", "肯穿豹尾趨南極，羣向螭頭拜下風。", "轉物工夫渾不動，折衝端在笑談中。"]'),
('79d52026-e321-43b7-a910-c1f8ca9a9ece','壽虞丞相  其一一','員興宗','宋','宋诗','song-poetry','','[]','凌煙漫說古丹青，玉立堂堂聳大庭。',64,'全唐诗/poet.song.117000.json','["凌煙漫說古丹青，玉立堂堂聳大庭。", "仗內留班隆體貌，端門扈從看儀形。", "槐陰匝地中書靜，榆塞無憂外戶扃。", "乞與八荒安穩地，河沙一一是修齡。"]'),
('892a1e41-9652-42fb-95b0-8b2c44248a98','壽虞丞相  其一二','員興宗','宋','宋诗','song-poetry','','[]','此生恩地更何之，教育偏深未第時。',64,'全唐诗/poet.song.117000.json','["此生恩地更何之，教育偏深未第時。", "舉世盡知牛馬走，從公看到鳳凰池。", "應憐弱質含春淺，豈是陽和變杏遲。", "願上君臣千萬壽，白頭東閣賦新詩。"]'),
('d3830a8d-7704-44c8-b9f4-463277681965','次韻送鄧祭酒  其一','員興宗','宋','宋诗','song-poetry','','[]','雪態垂垂鬢兩邊，官身底事厭蓬旋。',64,'全唐诗/poet.song.117000.json','["雪態垂垂鬢兩邊，官身底事厭蓬旋。", "秋風蒓鱠歸張子，春草池塘賦惠連。", "詩卷清思出冰玉，扁舟活計任湖天。", "南山得去初心遂，冷笑襄陽孟浩然。"]'),
('6bbb47f5-2bc1-4435-9101-a24a5c078577','次韻送鄧祭酒  其二','員興宗','宋','宋诗','song-poetry','','[]','欲去未去重湖邊，贈公一言公即旋。',64,'全唐诗/poet.song.117000.json','["欲去未去重湖邊，贈公一言公即旋。", "念無三徑作陶令，好繼七人追少連。", "官路行持荷葉橐，清罇且趁菊花天。", "懸知投老護四印，到處南綦心嗒然。"]'),
('aed87bad-e897-4acb-82c9-3cacdb0e3160','次韻送鄧祭酒  其三','員興宗','宋','宋诗','song-poetry','','[]','我家西土官南邊，學省愁卧思言旋。',64,'全唐诗/poet.song.117000.json','["我家西土官南邊，學省愁卧思言旋。", "羨公散吏一龍小，去卜真隠三龜連。", "賢哉復有大夫歎，倦矣羞題刺史天。", "作惱岷峨限牛斗，夢魂相值意翛然。"]'),
('db76fa96-2532-4408-88be-067002804e64','次韻送鄧祭酒  其四','員興宗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去去不憂豺虎邊，陽關幾作絮飛旋。',64,'全唐诗/poet.song.117000.json','["去去不憂豺虎邊，陽關幾作絮飛旋。", "揮金將對父老語，鋤豆勿遣根株連。", "閉目時教風掃地，沉心大似水涵天。", "西湖淡粧君念否，十客何時十指然。"]'),
('b05e9ad5-2724-469a-b003-a3d8ac706e1e','知郡前日見過顧念雨霪不止蓋苗而未穟頻雨者嘉生之祥也繼此真可以止矣因賦二篇拜呈  其一','員興宗','宋','宋诗','song-poetry','','[]','東田水决西田流，十日雨汁少日休。',64,'全唐诗/poet.song.117000.json','["東田水决西田流，十日雨汁少日休。", "勿厭唾金夜縷縷，準擬炊玉秋浮浮。", "我欣清腸免牛吼，坐快赤子非魚頭。", "社鬼豚蹄政浪得，使君端是監河侯。"]'),
('15df3184-6e7a-4bb8-a3ff-b88d575c3c95','知郡前日見過顧念雨霪不止蓋苗而未穟頻雨者嘉生之祥也繼此真可以止矣因賦二篇拜呈  其二','員興宗','宋','宋诗','song-poetry','','[]','欲墮之雨天垂垂，三山容態無定姿。',64,'全唐诗/poet.song.117000.json','["欲墮之雨天垂垂，三山容態無定姿。", "隴邊風回香作餌，頭上雲黑疑催詩。", "粘壁蝸牛心得計，沸天蚊豹口何施。", "請占錦繡紋開後，勿把琉璃鍾自持。"]'),
('7b253613-24e4-4b40-bb05-596bfea07599','用子文韻呈李參議彥澤  其一','員興宗','宋','宋诗','song-poetry','','[]','行殿青冥天盡頭，草間祇解老伊周。',64,'全唐诗/poet.song.117000.json','["行殿青冥天盡頭，草間祇解老伊周。", "中吳誰命虎牙將，重趙幾成牛後羞。", "君去忘家勿忘國，我悲非劍亦非緱。", "動容乞予功名地，不作西南斗樣州。"]'),
('8678f071-1a62-40a4-b8da-090e0f8b62aa','用子文韻呈李參議彥澤  其二','員興宗','宋','宋诗','song-poetry','','[]','驅車翻蓋電非追，有客有客公門馳。',64,'全唐诗/poet.song.117000.json','["驅車翻蓋電非追，有客有客公門馳。", "雙鴻西至一書墮，五馬南邊三峽遲。", "况值神傾意豁士，無愁歲暮日斜時。", "張眸指注話鄉國，爲說兩川猶漏巵。"]'),
('c4891ebc-6d5b-4d4a-8117-31da91511694','賀陽帥  其一','員興宗','宋','宋诗','song-poetry','','[]','使節西來快舊遊，淳和一洗蜀鵑愁。',64,'全唐诗/poet.song.117000.json','["使節西來快舊遊，淳和一洗蜀鵑愁。", "文章星斗三千帙，號令風雷六十州。", "北虜竚瞻司馬相，南夷祇畏卧龍侯。", "願君翻出調元手，萬億春兮萬億秋。"]'),
('09a81a1d-8de5-41ad-85c0-e33a77ad144f','賀陽帥  其二','員興宗','宋','宋诗','song-poetry','','[]','西掖北門明辯餘，道家豈與法家殊。',64,'全唐诗/poet.song.117000.json','["西掖北門明辯餘，道家豈與法家殊。", "父爲鴻漸子鵬舉，兄是龍駒弟鳳雛。", "金版六韜回地軸，玉衡七政總天樞。", "誰知左相兵刑外，草就歌詩頌有虞。"]'),
('5fb201a0-2991-44a3-9a19-f3101a073c36','雲安贈張殿直','員興宗','宋','宋诗','song-poetry','','[]','旅愁不放上雙眉，倚杖長吟李杜詩。',64,'全唐诗/poet.song.117000.json','["旅愁不放上雙眉，倚杖長吟李杜詩。", "虎膽狼心須畏伏，鳳肌鶴骨恣詼奇。", "章非索海無成日，句想穿天有得時。", "珍重公孫才力健，著鞭努力看追隨。"]'),
('d03788a8-9cf1-4e55-9cf7-3fd569aac301','送張郎中出守潼川','員興宗','宋','宋诗','song-poetry','','[]','亭築休休未作難，晚因觀物遂觀瀾。',64,'全唐诗/poet.song.117000.json','["亭築休休未作難，晚因觀物遂觀瀾。", "不賒日月霑新渥，肯對星辰戀舊官。", "龜策幽幽餘處索，牛頭衮衮靜中看。", "杜鵑口血老臣淚，勿信東川甫也歎。"]'),
('0c55948d-a992-4992-8179-40786000d125','與利州守  其一','員興宗','宋','宋诗','song-poetry','','[]','一襟和氣敵春陽，教本寬仁鎮益昌。',64,'全唐诗/poet.song.117000.json','["一襟和氣敵春陽，教本寬仁鎮益昌。", "未問禁中留召畢，且欣劍外得龔黄。", "奔馳蜀道三千遠，控制秦關百二强。", "况是太平今有象，邊城處處樂耕桑。"]'),
('e5599917-53db-41a4-8f7b-a5576e7616f7','與利州守  其二','員興宗','宋','宋诗','song-poetry','','[]','劍關雲棧蜀西頭，公在平川最上流。',64,'全唐诗/poet.song.117000.json','["劍關雲棧蜀西頭，公在平川最上流。", "五百里中爲甸服，一千年裏作賢侯。", "城烏想爾齊師遁，邊馬從他魏使愁。", "燕寢凝香無所事，姓名料想覆金甌。"]'),
('682e79e1-6eec-4d19-b789-5e2eb46b5b0c','與利州守  其三','員興宗','宋','宋诗','song-poetry','','[]','夙稱無盡老先生，况復鄉賢繼踵榮。',64,'全唐诗/poet.song.117000.json','["夙稱無盡老先生，况復鄉賢繼踵榮。", "和氣四時調玉燭，德輝千里照金城。", "羣歌太守來何暮，細數長安去幾程。", "仰察帝心應有在，時分台曜近周京。"]'),
('6edf2c48-0249-4fbe-a2d7-0c084c073378','和何知郡子文跨鼇觀燈','員興宗','宋','宋诗','song-poetry','','[]','山中勝踐蜀中稀，炯炯鼇頭吐火齊。',64,'全唐诗/poet.song.117000.json','["山中勝踐蜀中稀，炯炯鼇頭吐火齊。", "牛斗下流明夜徑，蟾輪飛窟墮山西。", "諸公泛泛千觴穩，我夢蘧蘧一蝶迷。", "異日端門千仗散，也能擁首聽朝鷄。"]'),
('55627467-1851-4dba-b214-cb6c1da701ac','送喻志夫登第西歸','員興宗','宋','宋诗','song-poetry','','[]','羨翁詩禮飽丘園，况有諸孫名義傳。',64,'全唐诗/poet.song.117000.json','["羨翁詩禮飽丘園，况有諸孫名義傳。", "得雨蛟龍勢逐逐，接翰鳬鳳聲聯聯。", "靈明入地含一笑，癡客問天今九年。", "合沓高名吉人後，會題影響疊前篇。"]'),
('e3c1c38e-bce9-464f-becc-9dfc41495e4c','遊西林寺','員興宗','宋','宋诗','song-poetry','','[]','寺外青驄擁月題，寺中笑語逐雲低。',64,'全唐诗/poet.song.117000.json','["寺外青驄擁月題，寺中笑語逐雲低。", "不知春色老不老，來訪禪林西復西。", "心地虛明簷外竹，舌聲長廣眼前溪。", "幽尋寓我清凉境，何必羈愁念故棲。"]'),
('fad35a8e-d0c5-4989-a0f2-d4a56cfde8c1','遊湖','員興宗','宋','宋诗','song-poetry','','[]','湖光無礙雨溟濛，且任蘭橈去路通。',64,'全唐诗/poet.song.117000.json','["湖光無礙雨溟濛，且任蘭橈去路通。", "珍重羣仙三日約，忍教春色二分空。", "人言羈思鷗前破，天遣清樽我輩同。", "笑指城闉倦歸思，晚晴對起舞雩風。"]'),
('8f519347-41bc-4af2-a3a2-1ef743223ee5','壽李巽岩','員興宗','宋','宋诗','song-poetry','','[]','烏衣巷陌盡清閒，鸞鶴飄然任往還。',64,'全唐诗/poet.song.117000.json','["烏衣巷陌盡清閒，鸞鶴飄然任往還。", "九棘三槐前魯國，一椿五桂老燕山。", "姓名玉笈琅函上，班次珠宮貝闕間。", "數百年來傳洛學，儘從尹喜望秦關。"]'),
('419319db-cc88-4c34-acc3-cc610a8b444c','壽張母','員興宗','宋','宋诗','song-poetry','','[]','楚玉騷頭雲錦裳，天然智術自成章。',64,'全唐诗/poet.song.117000.json','["楚玉騷頭雲錦裳，天然智術自成章。", "仙娥宮裏香風遠，慈姥巖前慧日長。", "良夜北陰循軌革，清秋西母薦壺觴。", "願言桐桂皆蕭呂，葉數宏開八九行。"]'),
('819f397c-9767-4f37-8fa2-db3252961c61','六月初雨中渡西湖因至道人庵燒佛香略憩靈隠與鄉僧同啜茶乘晚以歸  其一','員興宗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','獵獵風欹袖，垂垂雨打船。',24,'全唐诗/poet.song.117000.json','["獵獵風欹袖，垂垂雨打船。", "最憐荷似屋，不障水如天。"]'),
('0ad091d0-8b10-478b-92fb-aa02b4a055cf','六月初雨中渡西湖因至道人庵燒佛香略憩靈隠與鄉僧同啜茶乘晚以歸  其二','員興宗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','溪頭斷續雨，松下送迎僧。',24,'全唐诗/poet.song.117000.json','["溪頭斷續雨，松下送迎僧。", "世境不到處，心融意自澄。"]'),
('fc7b3167-71c5-4056-8b3a-93a201dc69c9','六月初雨中渡西湖因至道人庵燒佛香略憩靈隠與鄉僧同啜茶乘晚以歸  其三','員興宗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久困塵埃夢，暫隨香火緣。',24,'全唐诗/poet.song.117000.json','["久困塵埃夢，暫隨香火緣。", "栖鴉急殘照，我亦踏歸船。"]'),
('c0f62381-5a46-4487-a41a-970e7f68abcb','燕居','員興宗','宋','宋诗','song-poetry','','[]','今我非故我，行禪坐亦禪。',24,'全唐诗/poet.song.117000.json','["今我非故我，行禪坐亦禪。", "送風當八面，一鉢老三川。"]'),
('5ff48ae2-e7d4-4364-8f16-04805b1308b0','新灘險惡不可前遂出乘灘下舟作詩送灘上舟','員興宗','宋','宋诗','song-poetry','','[]','水面數千里，頼公託此身。',24,'全唐诗/poet.song.117000.json','["水面數千里，頼公託此身。", "如何阻惡灘，與我爲參辰。"]'),
('083b6388-1640-493d-a965-cb24e03d43a0','代舟答','員興宗','宋','宋诗','song-poetry','','[]','我實假衆力，送君遊蠻荆。',24,'全唐诗/poet.song.117000.json','["我實假衆力，送君遊蠻荆。", "灘危不可前，徒有濟川名。"]'),
('c795a36d-11ac-49f9-b81d-0c2d82bee4fc','再送舟','員興宗','宋','宋诗','song-poetry','','[]','公非不通險，任重載者淺。',24,'全唐诗/poet.song.117000.json','["公非不通險，任重載者淺。", "此去荷責輕，又得先歸便。"]'),
('c9e8fc3f-6f87-41b8-8ec4-6d9aff5b416a','舟再答','員興宗','宋','宋诗','song-poetry','','[]','此去責雖輕，恐爲商賈資。',24,'全唐诗/poet.song.117000.json','["此去責雖輕，恐爲商賈資。", "細瓷枉壓我，使我成徇私。"]'),
('59b3a603-1655-46f7-851d-9f6b3f3addc0','木樨花二首  其一','員興宗','宋','宋诗','song-poetry','','[]','承露珠微微，弄態金淺淺。',24,'全唐诗/poet.song.117000.json','["承露珠微微，弄態金淺淺。", "秋風一披拂，清意忽作遠。"]'),
('c02279c9-39c1-4108-838e-2899ddfbc18a','木樨花二首  其二','員興宗','宋','宋诗','song-poetry','','[]','山空花更幽，日透香自永。',24,'全唐诗/poet.song.117000.json','["山空花更幽，日透香自永。", "只欠欹月梅，同汝弄疎影。"]'),
('8af2758a-8a95-47e0-bde1-2d9cd50606fd','和何知郡子文冬日即事','員興宗','宋','宋诗','song-poetry','','[]','甲觀吾何事，丁年歲又周。',24,'全唐诗/poet.song.117000.json','["甲觀吾何事，丁年歲又周。", "霜餘一尊在，梅過百花羞。"]'),
('67f021a1-ab68-422b-b5b0-c12b45e43962','上許大卿  其一','員興宗','宋','宋诗','song-poetry','','[]','因嗟零落栖遲客，舊注聱牙詰屈書。',32,'全唐诗/poet.song.117000.json','["因嗟零落栖遲客，舊注聱牙詰屈書。", "脚踏紅塵愧泉石，身無清夢到蓬壺。"]'),
('cd9a77ee-51d0-4e58-9275-cc998979912c','上許大卿  其二','員興宗','宋','宋诗','song-poetry','','[]','晴霧青冥馬首來，道逢雙劍倚天開。',32,'全唐诗/poet.song.117000.json','["晴霧青冥馬首來，道逢雙劍倚天開。", "北軒賦就含經緯，斗覺靈光氣象推。"]'),
('87517f96-69d9-4fa8-917d-545f026507ac','病中春盡言懷','員興宗','宋','宋诗','song-poetry','','[]','萬象無涯春有涯，愁腸幾逐夢魂賒。',32,'全唐诗/poet.song.117000.json','["萬象無涯春有涯，愁腸幾逐夢魂賒。", "解吟整整堂堂句，勝看紅紅白白花。"]'),
('0a916fb4-52d7-482f-a92d-0bc4ca3cbc7e','往省隴阡遭雨有感','員興宗','宋','宋诗','song-poetry','','[]','村煙漸稀村徑失，山雨或過山花泣。',32,'全唐诗/poet.song.117000.json','["村煙漸稀村徑失，山雨或過山花泣。", "此身浩浩幾轉蓬，此口離離當掛壁。"]'),
