('2a5cac87-756c-47fa-aeec-0d0e752b7d6e','隆州  其四','員興宗','宋','宋诗','song-poetry','','[]','語我馮公有味哉，巨靈恰續斷鼇回。',32,'全唐诗/poet.song.117000.json','["語我馮公有味哉，巨靈恰續斷鼇回。", "從今東道君公貴，免喚西州市令來。"]'),
('6c6ca800-3453-4fef-904a-dec2de308ae9','贈休上人','員興宗','宋','宋诗','song-poetry','','[]','碧眼不輸巖下電，清詩迸出隴頭瀧。',32,'全唐诗/poet.song.117000.json','["碧眼不輸巖下電，清詩迸出隴頭瀧。", "何須更下牢關鐵，出沒無心月在江。"]'),
('f7a6802a-8ca7-4448-9072-18542f49e0e0','挽歸潁川喻夫人','員興宗','宋','宋诗','song-poetry','','[]','夫人不訝容髮暮，八十解將盃酒度。',32,'全唐诗/poet.song.117000.json','["夫人不訝容髮暮，八十解將盃酒度。", "不見歲寒今浩亭，花開花落悲行路。"]'),
('f0f0ee4a-52aa-4701-8a5c-f6efea2e97a1','清賢堂','員興宗','宋','宋诗','song-poetry','','[]','夫子宦遊三十年，乞身歸老舊林泉。',64,'全唐诗/poet.song.117000.json','["夫子宦遊三十年，乞身歸老舊林泉。", "須知朝路抽簪後，不要鄉人負弩前。", "儒素生涯圖史富，官清門戶子孫賢。", "羨君此去渾無事，滿眼青山劍外天。"]'),
('a9a53da6-e836-4a50-87ef-496dabab6c03','天府','員興宗','宋','宋诗','song-poetry','','[]','淵淵西土，惟天之府。',183,'全唐诗/poet.song.117000.json','["淵淵西土，惟天之府。", "昔際大吏，以貙以虎。", "不寬如之何，民亦仇止。", "不儉如之何，人亦悴止。", "有羨其輸，有豐其橐。", "左公右卿，則覬我得。", "厥佐聯聯，乃翼乃前。", "嗟我君子，則噤不言。", "戾極而傾，疾用不寧。", "既殛既鉏，伊我皇明。", "皇曰西土，惟我有痌。", "其守自今，惟寬儉是庸。", "格其難頑，慰其嚬呻。", "皇言載恩，侯心載仁。", "孰是遠斯，而不率馴。", "瞻彼江梁，我民我阜。", "惟皇之德，惟侯之守。", "敢耻于詞，以詔不朽。"]'),
('0c226be9-595b-4452-8aa2-711c8988c405','將軍樹','員興宗','宋','宋诗','song-poetry','','[]','細馬輕裘緩緩歸，一樽原野亦光輝。',32,'全唐诗/poet.song.117000.json','["細馬輕裘緩緩歸，一樽原野亦光輝。", "如今更訝將軍樹，土木如何衣錦衣。"]'),
('d6cd0398-f252-42c0-92b2-8870d5717a94','清風洞  其一','員興宗','宋','宋诗','song-poetry','','[]','晚衝白鳥幾飛迴，夜度清猿一嘯哀。',32,'全唐诗/poet.song.117000.json','["晚衝白鳥幾飛迴，夜度清猿一嘯哀。", "洞閟何人獲幽踐，可須高李共登臺。"]'),
('5103f2fc-068e-47dc-8d32-f788346985a5','清風洞  其二','員興宗','宋','宋诗','song-poetry','','[]','萬壑森寒如潑水，也復蕭蕭吹醉耳。',32,'全唐诗/poet.song.117000.json','["萬壑森寒如潑水，也復蕭蕭吹醉耳。", "飛乘何處覓蓮萊，試喚茶顛玉川子。"]'),
('ffe94c3e-cdef-4890-a6d6-98bf814719c3','朝霞洞  其一','員興宗','宋','宋诗','song-poetry','','[]','欲落未落天疎星，東方作矣絳樓明。',32,'全唐诗/poet.song.117000.json','["欲落未落天疎星，東方作矣絳樓明。", "人間但眩長春洞，此地真如不夜城。"]'),
('43fd3626-8147-4c27-a2e8-78616f9444b5','朝霞洞  其二','員興宗','宋','宋诗','song-poetry','','[]','何事杯深若邀月，端有空明供眼纈。',32,'全唐诗/poet.song.117000.json','["何事杯深若邀月，端有空明供眼纈。", "朝霞□合當朝餐，絕勝石髓堅如鐵。"]'),
('bfcccb37-2cfb-4538-9727-dcb0212b68c9','尋春','陳豐','宋','宋诗','song-poetry','','[]','盡日尋春不見春，杖藜踏破幾山雲。',32,'全唐诗/poet.song.117000.json','["盡日尋春不見春，杖藜踏破幾山雲。", "歸來試把梅花看，春在梅稍已十分。"]'),
('a0b43360-240d-4883-b383-9604914d4816','春夜','徐蕆','宋','宋诗','song-poetry','','[]','斜光月映紗窗小，美蔭雲連翠竹高。',32,'全唐诗/poet.song.117000.json','["斜光月映紗窗小，美蔭雲連翠竹高。", "花露染成香地暖，隔簾輕吹晚騷騷。"]'),
('27d38355-cca3-48eb-b911-6f6da2a9ef17','漾花池','徐蕆','宋','宋诗','song-poetry','','[]','咽咽聲殘吐水龍，玉爐煙斷寶樽空。',32,'全唐诗/poet.song.117000.json','["咽咽聲殘吐水龍，玉爐煙斷寶樽空。", "窗前盡日無人到，只有荷花滿意紅。"]'),
('e3f01934-4874-48ec-b209-e6de7f9ffa61','題顔魯公祠','蔡柟','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','太師駡賊眼欲裂，由來大剛不獲闕。',64,'全唐诗/poet.song.117000.json','["太師駡賊眼欲裂，由來大剛不獲闕。", "堂堂忠義八十年，與賊共生寧共滅。", "泰山可摧地可陷，不可奪者公之節。", "姦邪盧杞知不知，舌舐忠臣頭上血。"]'),
('228ed7e1-4b10-4116-87f2-5ec39711e567','詠軍山','蔡柟','宋','宋诗','song-poetry','','[]','遠岫迴環碧四圍，一峰清絕萬峰低。',32,'全唐诗/poet.song.117000.json','["遠岫迴環碧四圍，一峰清絕萬峰低。", "浮雲復作人間雨，天上長晴世不知。"]'),
('7748d19b-089a-461c-a2a8-54e9364bbce3','題秋雨堂','蔡柟','宋','宋诗','song-poetry','','[]','太宗之治萬國新，梯山航海來珠珍。',96,'全唐诗/poet.song.117000.json','["太宗之治萬國新，梯山航海來珠珍。", "當時寶藏盡充溢，暇日從容延近臣。", "君無驕吝臣不諂，博哉仁言吾所聞。", "乃知不能正君者，雖有議論徒紛紛。", "至今華堂扁秋雨，衮衮積善歸雲仍。", "誰能歲晚事斯語，堂中主人丞相孫。"]'),
('2e4fe4e9-e178-46d1-bcca-d9064b7c0a3a','題廣昌縣平西臺','蔡柟','宋','宋诗','song-poetry','','[]','層臺跨青空，溪水出其側。',132,'全唐诗/poet.song.117000.json','["層臺跨青空，溪水出其側。", "千峰競神秀，萬里無限隔。", "王侯賢令尹，心匠巧經畫。", "平生不凡處，眼高四海窄。", "坐令荆棘場，化作山川國。", "登臨有勝集，而我非佳客。", "聽候妙談兵，四座皆辟易。", "冰霜繞牙齒，韜略貫胸臆。", "迺知杜元凱，不特有傳癖。", "風塵猶澒洞，早試平戎策。", "當沉峴山銘，更效燕然勒。"]'),
('569682b6-9118-415f-9cef-9fadcd26bbbd','題崇覺寺','蔡柟','宋','宋诗','song-poetry','','[]','溪雲障微陰，竹風消午暑。',108,'全唐诗/poet.song.117000.json','["溪雲障微陰，竹風消午暑。", "行窮紫翠間，金榜開梵宇。", "殘僧四五輩，衣破貌淳古。", "碧筒𣂏寒泉，屋角掛飛雨。", "高堂儼遺像，丹青爛圭且。", "當時立廊廟，兄弟皆接武。", "誰知百世士，今作一丘土。", "石麟卧斜陽，斷碣枕庭廡。", "悟此笑世人，微榮何足數。"]'),
('03a1fcc5-a84a-4aee-9c8f-aaa6f5e224a2','登稽古閣晚眺','蔡柟','宋','宋诗','song-poetry','','[]','簷外川原迥，煙中草樹微。',48,'全唐诗/poet.song.117000.json','["簷外川原迥，煙中草樹微。", "山城暮吹角，客子淚沾衣。", "歲月經身老，行藏與願違。", "歸禽带落日，渺渺背人飛。"]'),
('a49c2409-4e79-43d5-ae32-68b6f246f2cc','泊釣臺','蔡柟','宋','宋诗','song-poetry','','[]','高臺百尺凌雲碧，維舟夜久霜月白。',128,'全唐诗/poet.song.117000.json','["高臺百尺凌雲碧，維舟夜久霜月白。", "癭木窣窣摇枯藤，寒瀨潺潺落蒼石。", "先生退隠知幾年，漢家鐘鼎徒凌煙。", "高風千古磨不盡，山水照映長明鮮。", "我來俯仰慚羈旅，衝寒愁怕玄冬暮。", "此身不負白鷗盟，暫此遲留亦何預。", "起來搔首江茫茫，孤篷却逐雁隨陽。", "人生遊行豈易得，惟有此夕難相忘。"]'),
('7f77c889-31f6-4117-a403-6307a2a7cd1f','詠新荷','蔡柟','宋','宋诗','song-poetry','','[]','朱欄橋下水平池，四面無風柳自垂。',32,'全唐诗/poet.song.117000.json','["朱欄橋下水平池，四面無風柳自垂。", "疑是水仙吟意懶，碧羅箋卷未題詩。"]'),
('69727e43-5913-487c-a528-4536bcd56e8d','瀘江亭','虞允文','宋','宋诗','song-poetry','','[]','映水林巒影顛倒，濟川舟楫勢崢嶸。',32,'全唐诗/poet.song.117000.json','["映水林巒影顛倒，濟川舟楫勢崢嶸。", "東行萬里欲乘興，更待一篙春水生。"]'),
('6f960917-b3ac-4f5f-b6a7-db571db473d8','以筆墨送周子允發策玉堂','劉儀鳳','宋','宋诗','song-poetry','','[]','腹囊英物吐長虹，翰墨區區有底功。',32,'全唐诗/poet.song.117000.json','["腹囊英物吐長虹，翰墨區區有底功。", "也要同盟作旗鼓，三山直上一帆風。"]'),
('350f1572-c830-4574-b0d4-70e1770d8126','詠范志玄','劉儀鳳','宋','宋诗','song-poetry','','[]','誰家遊冶郎，闖首窺幽闥。',48,'全唐诗/poet.song.117000.json','["誰家遊冶郎，闖首窺幽闥。", "但見臉如花，不知心似鐵。", "一夕變其軀，雪姿映雲髮。", "昔爲桃李姿，今作松篁節。"]'),
('57017c17-0631-4558-9668-9445dc16b2fc','飲王龜齡瑞白堂秉燭觀跳珠分韻得珠字','劉儀鳳','宋','宋诗','song-poetry','','[]','別來世故朝昏殊，相與言之汗模糊。',160,'全唐诗/poet.song.117000.json','["別來世故朝昏殊，相與言之汗模糊。", "兩翁得酒促坐席，感深念極氣欲蘇。", "籜龍亦解作水供，細繹尋丈如渴烏。", "衣巾生秋背毛豎，金石相印環佩趨。", "江山豪壯旁尊俎，醉中頻貫纍纍珠。", "此時一事復掛口，爲樂未竟成喑嗚。", "夔州憂民困湯火，潤澤有志無坦途。", "眼前焦熬十萬戶，欠伸戲笑皆霑濡。", "自操量鼓入官廩，不輸一錢分水符。", "讀書功名無表畔，久矣俗吏輕吾儒。"]'),
('7b651985-faa3-431a-8d19-03f630649827','自歸州陸行至夔州  其一','劉儀鳳','宋','宋诗','song-poetry','','[]','戶口村無幾，犁鋤力不堪。',48,'全唐诗/poet.song.117000.json','["戶口村無幾，犁鋤力不堪。", "林荒樗櫟壽，月黑虎狼貪。", "幽絕雲眠穩，清閒谷飲甘。", "故山深未極，壤斷蓋茅庵。"]'),
('c46dfe22-97d3-47e1-af0c-f59c3f9e3758','自歸州陸行至夔州  其二','劉儀鳳','宋','宋诗','song-poetry','','[]','曠野無人宿，危亭犯雨過。',48,'全唐诗/poet.song.117000.json','["曠野無人宿，危亭犯雨過。", "嶺雲堆屭贔，剎海現兜羅。", "酒觸秋懷壯，天留暮色多。", "不勝行役苦，裁入竹枝歌。"]'),
('0dad09d5-f894-4d72-a206-e21d05c32d12','句','劉儀鳳','宋','宋诗','song-poetry','','[]','嘉陵從東來，水上山突兀。',24,'全唐诗/poet.song.117000.json','["嘉陵從東來，水上山突兀。", "松竹相蔽虧，煙霞互明滅。"]'),
('63c77bd7-1223-4e85-a352-fc4a5da89cfc','和曾幾留客亭  其一','沈度','宋','宋诗','song-poetry','','[]','汩汩多塵事，長懷鳩杖遊。',48,'全唐诗/poet.song.117000.json','["汩汩多塵事，長懷鳩杖遊。", "每因門可款，豈爲醉相留。", "靜契竹林勝，幽非草樹秋。", "公今國耆艾，砥柱屹中流。"]'),
('42c42561-ac0b-4a9c-a1a8-8d5d7274bb0e','和曾幾留客亭  其二','沈度','宋','宋诗','song-poetry','','[]','持節推仍世，林園記昔遊。',48,'全唐诗/poet.song.117000.json','["持節推仍世，林園記昔遊。", "深藏事幽討，長轡詎淹留。", "已見山無盜，欣同歲有秋。", "時容一嘯詠，竊比晉名流。"]'),
('f2dd4d54-5ac6-42b6-97a4-306a4a16c4c5','贈陳常翁','謝天民','宋','宋诗','song-poetry','','[]','一經教子足三冬，議論孤高有孟公。',64,'全唐诗/poet.song.117000.json','["一經教子足三冬，議論孤高有孟公。", "學到內融多樂地，心無外慕自春風。", "我慚言偃絃歌化，君在周公禮樂中。", "三百三千煩指示，許誰蹊徑一源通。"]'),
('625f4bc3-fed2-46f3-bc51-60c4a7528bdd','殷仲堪讀書堂二首  其一','向子賁','宋','宋诗','song-poetry','','[]','雲藏山色水連空，樓閣參差一望中。',32,'全唐诗/poet.song.117000.json','["雲藏山色水連空，樓閣參差一望中。", "重作書臺繼前迹，幾回池上想遺風。"]'),
('cd9193d4-33ba-498c-aabd-ef2039b1ce20','殷仲堪讀書堂二首  其二','向子賁','宋','宋诗','song-poetry','','[]','山遶溪潭碧澗開，人言中有讀書堂。',32,'全唐诗/poet.song.117000.json','["山遶溪潭碧澗開，人言中有讀書堂。", "仲堪出處君休問，且對溪山酒一杯。"]'),
('2335da47-7989-4b78-ac46-24265b435f16','呈開善道謙禪師','釋吳十三','宋','宋诗','song-poetry','','[]','元來無縫罅，觸著便光輝。',24,'全唐诗/poet.song.117000.json','["元來無縫罅，觸著便光輝。", "既是千金寶，何須彈雀兒。"]'),
('995d26e0-3b2b-4a6b-b2ed-548f0d8d9281','句','曹泳','宋','宋诗','song-poetry','','[]','偏宜滴漏春朝雨，尤近裴公盛德堂。',16,'全唐诗/poet.song.117000.json','["偏宜滴漏春朝雨，尤近裴公盛德堂。"]'),
('8ce0af66-8246-4ec0-92ad-610c1aba28bd','送曹泳','厲德斯','宋','宋诗','song-poetry','','[]','斷尾雄雞不畏犧，憑依掇禍復何疑。',32,'全唐诗/poet.song.117000.json','["斷尾雄雞不畏犧，憑依掇禍復何疑。", "八千里路新州瘴，歸骨中原是幾時。"]'),
('eede2ef8-b001-416d-a2a3-0f0c88738471','觀古魚鳬城','孫松壽','宋','宋诗','song-poetry','','[]','野寺依修竹，魚鳬迹半存。',48,'全唐诗/poet.song.117000.json','["野寺依修竹，魚鳬迹半存。", "高城歸野壠，故國靄荒村。", "古意憑誰問，行人謾苦論。", "眼前興廢事，煙水又黄昏。"]'),
('a65775ad-3a32-4164-9a95-28de8caf78f5','過張白雲先生故居','孫松壽','宋','宋诗','song-poetry','','[]','世外煙霞未易期，可人平野淡秋曦。',64,'全唐诗/poet.song.117000.json','["世外煙霞未易期，可人平野淡秋曦。", "籃輿出郭夢差好，竹杖臨流意共遲。", "已覺此懷飛縹渺，不須明月問盈虧。", "仙翁騎鶴歸來否，舊隠林高綠更奇。"]'),
('8d2ca6f0-d3b8-48c2-8e3f-0c30d74d45c2','賦成都張氏蜀錦園  其一','孫松壽','宋','宋诗','song-poetry','','[]','池南池北蜀宮春，紅濕花枝壓錦城。',32,'全唐诗/poet.song.117000.json','["池南池北蜀宮春，紅濕花枝壓錦城。", "袖手縱觀花似笑，相看一脈話尤情。"]'),
('89e41751-b8be-4252-90e6-9c7c991b544c','賦成都張氏蜀錦園  其二','孫松壽','宋','宋诗','song-poetry','','[]','乾坤開關記王春，劍閣崢嶸拱帝城。',32,'全唐诗/poet.song.117000.json','["乾坤開關記王春，劍閣崢嶸拱帝城。", "不許此花歸閬苑，錦臺南畔古今情。"]'),
('8fcd5707-fa8f-4827-8a36-cad73424bd9e','賦成都碧雞坊李氏石君','孫松壽','宋','宋诗','song-poetry','','["\u592a\u6e56"]','造化小兒斲山骨，幾年流落蛟龍窟。',298,'全唐诗/poet.song.118000.json','["造化小兒斲山骨，幾年流落蛟龍窟。", "太湖一碧浸玻璃，瀾吞浪吐窮奔突。", "瑰奇未許困泥沙，漂出江臯空㟮屼。", "清寒偃蹇如高人，肯向蓬蒿念埋沒。", "曩聞上苑饒奇珍，千形萬狀高嶙峋。", "當年搜索困山海，氊包席裹車轔轔。", "規模豈但肖五嶽，氣象直欲凌三神。", "一朝胡馬窺城下，例隨矢石荒荆榛。", "憐君分落幽人手，不逐爾輩汙塵垢。", "首陽寂寞伯夷清，瀟湘冷落三閭瘦。", "李侯胸中飽雲夢，得君不用斯瓊玖。", "館之舊隠與周旋，竹士松賓三益友。", "相看一洗名利心，眉宇更清元德秀。", "君今幾世德未衰，霜寒玉立癯而壽。", "咄嗟世眼多嗜好，玩形忘理十八九。", "奇章所蓄森琅玕，名標甲乙空紛然。", "到溉奇礓高崒嵂，一擲徒爲負進錢。", "石君於汝非不厚，較其所得無何有，願公世濟此君爲不朽。"]'),
('b6589083-d1c9-4788-9efd-b242592cf265','賦張白雲先生故居溪上菊','孫松壽','宋','宋诗','song-poetry','','[]','金衣綠裳仙，不嗅春風餘。',48,'全唐诗/poet.song.118000.json','["金衣綠裳仙，不嗅春風餘。", "飄摇清江練，服佩玄圃珠。", "欲驂沖霄鸞，鞭起橫海魚。", "天遊浩無際，妙寄良可娛。"]'),
('f3ad9022-4e4c-4b84-9728-aa221722999d','賦蘧仙觀古楠','孫松壽','宋','宋诗','song-poetry','','[]','風雨縱橫八面看，巍然此柱欲擎天。',32,'全唐诗/poet.song.118000.json','["風雨縱橫八面看，巍然此柱欲擎天。", "壯心已與雲龍會，彈指消摩八百年。"]'),
('5b90ed06-aecd-4935-b2df-d50de3f38247','紀申提學高行','孫松壽','宋','宋诗','song-poetry','','[]','憶昔兒童飽梨栗，斑衣偃伏先君側。',384,'全唐诗/poet.song.118000.json','["憶昔兒童飽梨栗，斑衣偃伏先君側。", "每聞正色說我翁，口口奇奇長太息。", "先君墓草今芊芊，尚想遺言過庭日。", "恨無佳傳掬芳馨，洗我肝心百非僻。", "一朝幽鎸晃入手，刓忍如懷夜光璧。", "男兒大節要奇偉，一日成就天所錫。", "我翁當年鸞鶴雛，一別舊巢無處覓。", "桑弧射處掩蓬蒿，獨把窅窊飛俊翮。", "楊宗不絕僅如線，大義欲歸歸不得。", "凝香夜半禱靈空，願楊有子歸宮室。", "果然天助兩飛鴻，翁喜當興子雲宅。", "絳霄回首擬歸來，撫我恩深重嗟惜。", "棄官十載營旨甘，送死養生無一失。", "寸心安矣指白雲，百拜雙親淚濡席。", "茅簷雖陋生處所，此心不以萬鍾易。", "幾年夜淚濕衾裯，今作兒啼情自適。", "登堂悲喜動行人，里巷喧呼手加額。", "珠還合浦已無憾，老蚌沙泥忍遺逸。", "窮簷忽見相抱持，孺慕丹心始云畢。", "一子來歸詠白華，三家孝愛融春色。", "雍容去就良可觀，無乃扶持有神物。", "始知造化惜頹波，畀以難能令一出。", "玉堂丈人風教手，一日得之幾折屐。", "何不薦之陛下聖，蜀有孝子聲藉藉。"]'),
('9b5f6750-d053-4679-8e9e-51a633885a82','句','蕭肅','宋','宋诗','song-poetry','','[]','鐘聲出峽口，塔影落潭心。',12,'全唐诗/poet.song.118000.json','["鐘聲出峽口，塔影落潭心。"]'),
('f43e4452-a483-471e-866b-127e963ab9cd','偈二首  其一','釋元妙','宋','宋诗','song-poetry','','[]','黄昏雞報曉，半夜日頭明。',24,'全唐诗/poet.song.118000.json','["黄昏雞報曉，半夜日頭明。", "驚起雪獅子，瞠開紅眼睛。"]'),
('9b2e11c1-4af7-4438-a1a2-42d13f36f9e3','偈二首  其二','釋元妙','宋','宋诗','song-poetry','','[]','南泉肚裏飽齁齁，莊主雖饑解點頭。',32,'全唐诗/poet.song.118000.json','["南泉肚裏飽齁齁，莊主雖饑解點頭。", "侍者只聞歌樂響，不知洪飲在高樓。"]'),
('164841ff-2758-483b-8480-5873e64a374e','頌古二首  其一','釋元妙','宋','宋诗','song-poetry','','[]','萬卷詩書，一時頭角，纔跨宗門，便施謀略。',68,'全唐诗/poet.song.118000.json','["萬卷詩書，一時頭角，纔跨宗門，便施謀略。", "古歸宗，真老作。", "只顧滿彎弓，不知誰見雙雕落。", "絕毫絕釐，如山如岳。", "堂堂氣宇冠儒林，浩浩清風播寥廓。"]'),
('ab14e1cd-e6be-4dd7-a8be-86662b0135c8','頌古二首  其二','釋元妙','宋','宋诗','song-poetry','','[]','常侍舉筆，萬事皆吉。',40,'全唐诗/poet.song.118000.json','["常侍舉筆，萬事皆吉。", "直下承當，急急如律。", "米胡參官，忘前失後。", "且告貴人，爲我相救。"]'),
('e7c6cac4-d317-4c07-8af0-fe1466d4d920','句','姚小彭','宋','宋诗','song-poetry','','[]','山接衡湘多爽氣，湖如杭潁共佳名。',16,'全唐诗/poet.song.118000.json','["山接衡湘多爽氣，湖如杭潁共佳名。"]'),
('dbe6a9fd-2b3d-4e3c-b42f-df6d8e1812ff','羅浮','鄭康佐','宋','宋诗','song-poetry','','[]','泰華端培塿，羅浮霄漢鄰。',48,'全唐诗/poet.song.118000.json','["泰華端培塿，羅浮霄漢鄰。", "俯視雲烟飛，冠蓋摩星辰。", "凝神想至道，窈窕難具陳。", "未究訪安期，佇立空逡巡。"]'),
('3ee7a7af-92c1-48ca-91b0-e27e2cc00fbb','卓錫泉','鄭康佐','宋','宋诗','song-poetry','','[]','大士西方來，誅茆老幽麓。',48,'全唐诗/poet.song.118000.json','["大士西方來，誅茆老幽麓。", "振錫風雲上，飛泉湧山腹。", "一泓自清甘，千里田疇足。", "源深而流長，何必貴川瀆。"]'),
('7b1a76c6-83d4-4259-a1fc-e8d7d1aab014','蓬萊閣','鄭康佐','宋','宋诗','song-poetry','','[]','獨占林泉勝，金碧耀青冥。',48,'全唐诗/poet.song.118000.json','["獨占林泉勝，金碧耀青冥。", "憑闌俯八極，縹緲降玉京。", "羣仙日往還，簫韶聞九成。", "鸞鳳爲君導，恍然遊蓬瀛。"]'),
('a27a887e-bcc3-423a-b006-422b71ec641e','鐵橋','鄭康佐','宋','宋诗','song-poetry','','[]','青蜺跨兩山，龍鳳互撐拄。',48,'全唐诗/poet.song.118000.json','["青蜺跨兩山，龍鳳互撐拄。", "頡頏來雙鳬，孰云通步武。", "壺中杳靄閒，遐想神仙侶。", "夢錫九霞丹，翩翩遊紫府。"]'),
('b7025620-b274-49de-85dc-669ccb49a9d6','水簾洞','鄭康佐','宋','宋诗','song-poetry','','[]','仙人開碧戶，玉溜瀉潺淙。',48,'全唐诗/poet.song.118000.json','["仙人開碧戶，玉溜瀉潺淙。", "飛流散珠璣，灑落隨天風。", "三伏不知暑，有如水晶宮。", "平生邱壑性，歌嘯翠微中。"]'),
('f6288584-0719-4e8f-8d87-2b4f8838ddc9','石樓','鄭康佐','宋','宋诗','song-poetry','','[]','危橋橫碧漢，隠約山之巔。',48,'全唐诗/poet.song.118000.json','["危橋橫碧漢，隠約山之巔。", "下窺滄海大，宇宙相連延。", "天風吹寒水，恍惚遊飛仙。", "飄飄吹凌虛，還爲塵俗牽。"]'),
('e0bd1784-ffe3-4edb-81fe-622a1d8b6e9d','夜樂池','鄭康佐','宋','宋诗','song-poetry','','[]','清籟起虛壑，笙竽驚夜眠。',48,'全唐诗/poet.song.118000.json','["清籟起虛壑，笙竽驚夜眠。", "音調自諧暢，恍如奏鈞天。", "真仙聚臨賞，鸞鶴舞蹁躚。", "凌晨日杲杲，濯纓弄潺湲。"]'),
('a5dd4369-a9fb-46c0-9af2-8a80ea606a95','鄺仙騎牛石','鄭康佐','宋','宋诗','song-poetry','','[]','橫笛騎青牛，巖扉自開闢。',48,'全唐诗/poet.song.118000.json','["橫笛騎青牛，巖扉自開闢。", "倏然乘風馭，雲收煙滅迹。", "真人不可見，空遺舊泉石。", "我來獨徘徊，日暮千山碧。"]'),
('5bf0ed92-90a6-42f0-b4a5-affcb72845dc','葛仙祠','鄭康佐','宋','宋诗','song-poetry','','[]','乘雲朝太清，烟霞鎖故宅。',48,'全唐诗/poet.song.118000.json','["乘雲朝太清，烟霞鎖故宅。", "逍遥十洲上，遂與人寰隔。", "泉石獨泠泠，遺竈粲朱碧。", "欲追汗漫遊，安得生羽翮。"]'),
('bd3bd7f4-6742-4ff5-a97d-6f83df3aa07c','黄野人庵','鄭康佐','宋','宋诗','song-poetry','','[]','至人隠洞天，蒼苔滿澗石。',48,'全唐诗/poet.song.118000.json','["至人隠洞天，蒼苔滿澗石。", "長嘯響空巖，咫尺雲霧隔。", "白鶴未歸來，何以慰晨夕。", "流泉自涓涓，秋宵山月白。"]'),
('47ea8212-281b-4b60-9745-2e75d40ab124','白雲庵謁先君寺丞詩','鄭康佐','宋','宋诗','song-poetry','','[]','清癯野鶴姿，問道羽衣客。',48,'全唐诗/poet.song.118000.json','["清癯野鶴姿，問道羽衣客。", "白雲濯飛泉，青霞窺裂石。", "閒猿嘯清曉，藥鳥鳴日夕。", "幽人不可見，百拜訪遺跡。"]'),
('a12c76dc-6ac8-43b8-b2cb-a474dcad20ea','雍千秋有東巖詩信師古和之矣次其韻','侯賓','宋','宋诗','song-poetry','','[]','漥山插曾雲，古詩廕修柏。',144,'全唐诗/poet.song.118000.json','["漥山插曾雲，古詩廕修柏。", "琅玕繚疏垣，爲供窗戶碧。", "地靈輕俗駕，盡掃塵埃迹。", "一新堂殿容，共詫今勝昔。", "朅來厠嘉踐，深衣曳方舄。", "荒□障□風，積潤蘚侵壁。", "可人茶供甘，乳竇出寒液。", "□龕明石像，斷碑摸鐵畫。", "湍江激崩岸，道路幾更易。", "羣山碧參差，眼境多克獲。", "窮幽老不能，負我登山屐。", "狂歌擊唾壺，醉墨紛狼藉。"]'),
('47ce110e-fbe6-4789-b0b5-db9086192ed9','和元微之春遊韻寄洪景伯','李端民','宋','宋诗','song-poetry','','[]','東閣經年別，窮愁客路難。',72,'全唐诗/poet.song.118000.json','["東閣經年別，窮愁客路難。", "望塵驚岳峙，懷舊各雲散。", "茵醉恩逾厚，檣敧興未殘。", "馮唐嗟已老，范叔敢言寒。", "玉燭調魁柄，陽春在筆端。", "應憐掃門役，白首滯江干。"]'),
('91069d04-0643-4c62-96b6-51df20587d51','瑞巖夜聞聲有感','李端民','宋','宋诗','song-poetry','','[]','蒼宮環合碧崔嵬，風動空山隠轉雷。',64,'全唐诗/poet.song.118000.json','["蒼宮環合碧崔嵬，風動空山隠轉雷。", "逸響已隨天籟發，餘音猶和玉琴哀。", "夜闌誰辨龍蛇勢，歲久俱爲棟柱材。", "擬欲尋聲問盧老，耳根清浄了無猜。"]'),
('47413afb-ed2e-42dc-81ef-a48f60a273f4','題上方壁','李端民','宋','宋诗','song-poetry','','[]','寓居蕭寺便爲家，問舍求田事未涯。',64,'全唐诗/poet.song.118000.json','["寓居蕭寺便爲家，問舍求田事未涯。", "平昔孤蹤猶可表，少年豪氣不須誇。", "雪消野徑生春薺，風動荒林噪晚鴉。", "極目悠然千里思，祇將詩句傲煙霞。"]'),
('0bcab4bf-36f4-4c23-95fd-29d075240ec5','留題浄應寺','李端民','宋','宋诗','song-poetry','','[]','方牀藤枕夢蘧蘧，睡足高堂樂有餘。',32,'全唐诗/poet.song.118000.json','["方牀藤枕夢蘧蘧，睡足高堂樂有餘。", "茶乳泛甌香篆息，明窗重理讀殘書。"]'),
('6c8e0582-0945-467d-a0ba-7aa904a52366','儲福宮玉真公主像','胡叔豹','宋','宋诗','song-poetry','','[]','棄形如遺但養神，阿兄爛醉梨園春，人百撼之耳不聞。',48,'全唐诗/poet.song.118000.json','["棄形如遺但養神，阿兄爛醉梨園春，人百撼之耳不聞。", "何物女子乃獨醒，徑來窮山卧白雲，不見漁陽胡馬塵。"]'),
('09e71972-28e7-4448-9c2b-330aa8fe949a','句  其一','胡叔豹','宋','宋诗','song-poetry','','[]','宮徙瀆山方得地，閣藏宸翰不知年。',16,'全唐诗/poet.song.118000.json','["宮徙瀆山方得地，閣藏宸翰不知年。"]'),
('37437cd7-7c4a-448f-bb67-4be40b090ef5','句  其二','胡叔豹','宋','宋诗','song-poetry','','[]','先生只此在山中，莫道雲深不知處。',16,'全唐诗/poet.song.118000.json','["先生只此在山中，莫道雲深不知處。"]'),
('d39a7c9f-fe9a-4594-a0a9-383ff780104d','冬','吳曾','宋','宋诗','song-poetry','','[]','看了青燈夢不成，東風輥雪落寒聲。',32,'全唐诗/poet.song.118000.json','["看了青燈夢不成，東風輥雪落寒聲。", "半生客裏無窮恨，告訴梅花說到明。"]'),
('ff7e3b6e-625d-4222-aedb-61193f451d05','羅山','吳曾','宋','宋诗','song-poetry','','[]','兒時聞羅山，窟穴居神仙。',288,'全唐诗/poet.song.118000.json','["兒時聞羅山，窟穴居神仙。", "念念每欲往，終爲俗累牽。", "茲晨復何夕，風日媚晴暄。", "偶與二三子，徑來踐前言。", "崎嶇涉岡澗，峭蒨淩雲烟。", "崖斷或如瀉，坡平俄若川。", "有泉何自來，但覺聲涓涓。", "縈紆若蛇走，往注山腹田。", "徘徊一濯足，入袖風翩翩。", "俄登最高嶺，中觀屋數椽。", "嶙峋老石像，摩挲不記年。", "桃花破叢菅，一笑爲嫣然。", "石屏與翠壁，擁從相後先。", "物色恣觀覽，萬界滿眼前。", "適問同遊人，茲爲第幾天。", "不然何秀拔，不與衆峰連。", "長安在何許，無乃落日邊。", "十年苦搶攘，戰血腥戈鋋。", "誰知塵外客，一壑能自專。", "徜徉得此樂，疑已飄飄然。", "茲遊恐難再，遲留不能前。", "如何林間月，弄影明娟娟。", "催歸猶恨早，正恐陵谷遷。", "到家追悔甚，誓將世務捐。"]'),
('6efb229d-f00a-4453-9f7a-84e69c6e5006','南湖詩上晁侍郎','吳曾','宋','宋诗','song-poetry','','[]','已將政事繼龔黄，更與風光作主張。',32,'全唐诗/poet.song.118000.json','["已將政事繼龔黄，更與風光作主張。", "見說南湖桃與李，郡人今復比甘棠。"]'),
('3fd6c2b2-8122-465f-bc70-7fdccdff68e9','挽和靖先生詩三首  其一','呂稽中','宋','宋诗','song-poetry','','[]','往在伊川學，他時洙泗傳。',48,'全唐诗/poet.song.118000.json','["往在伊川學，他時洙泗傳。", "從來有高第，未覺喪前賢。", "繆列三千士，於今二十年。", "山頹與梁壞，淚盡會稽前。"]'),
('e7511d55-7e5b-4840-bc11-f4a47f2671fc','挽和靖先生詩三首  其二','呂稽中','宋','宋诗','song-poetry','','[]','四海尊師席，斯文特未衰。',48,'全唐诗/poet.song.118000.json','["四海尊師席，斯文特未衰。", "何其兩楹夢，遽使哲人萎。", "閬水從容意，稽山疾病時。", "勤勤付斯道，矢死奉成規。"]'),
('65c7a121-81bb-4e0d-91d2-bc584e0da08c','挽和靖先生詩三首  其三','呂稽中','宋','宋诗','song-poetry','','[]','垂老朝三聘，生平食一簞。',48,'全唐诗/poet.song.118000.json','["垂老朝三聘，生平食一簞。", "絕知斯道在，遺恨得時難。", "廟謹先師祀，書傳後代看。", "形容銘墓石，三發喟然嘆。"]'),
('93d1010e-1546-485f-b9dc-6a120bed598a','句  其一','孫道絢','宋','宋诗','song-poetry','','[]','別墅蒼烟縈古木，寒溪白浪捲輕沙。',16,'全唐诗/poet.song.118000.json','["別墅蒼烟縈古木，寒溪白浪捲輕沙。"]'),
('682ba3a8-ab4d-43b7-b093-b9a79f78f933','句  其二','孫道絢','宋','宋诗','song-poetry','','[]','大虛萬籟息，人散一簾斜。',12,'全唐诗/poet.song.118000.json','["大虛萬籟息，人散一簾斜。"]'),
('2729830f-d9b3-48d5-bd2c-9af1c97ca1e9','畎畝十首  其一','王十朋','宋','宋诗','song-poetry','','[]','畎畝有遺士，妄懷葵藿心。',48,'全唐诗/poet.song.118000.json','["畎畝有遺士，妄懷葵藿心。", "朝夕傾太陽，不耐氛穢侵。", "肝膽有古劍，願言决群陰。", "茲志尚鬰鬰，抱膝成悲吟。"]'),
('5a9e3a40-adb0-49dd-9de2-c253d710015e','畎畝十首  其二','王十朋','宋','宋诗','song-poetry','','[]','古道日云邈，古意誰復知。',48,'全唐诗/poet.song.118000.json','["古道日云邈，古意誰復知。", "陽春漠無和，流水空含悲。", "郢曲變新調，鄭聲入朱絲。", "喟然三嘆餘，默與羲皇期。"]'),
('d8d0ab74-afd7-4fd3-bbe4-b5c22e7afcaf','畎畝十首  其三','王十朋','宋','宋诗','song-poetry','','[]','讀書不知道，言語徒自工。',84,'全唐诗/poet.song.118000.json','["讀書不知道，言語徒自工。", "求道匪云遠，近在義命中。", "吾儒有仲尼，道德無比崇。", "傳參十八章，入道知其宗。", "後學昧極致，徒知授兒童。", "孰識孝與弟，理與神明通。", "爲臣不知此，事上焉能忠。"]'),
('2be96a0a-cb48-4483-893c-90115dadfe63','畎畝十首  其四','王十朋','宋','宋诗','song-poetry','','[]','仲尼作春秋，垂訓千萬年。',72,'全唐诗/poet.song.118000.json','["仲尼作春秋，垂訓千萬年。", "古者父母讎，義不共戴天。", "莊同父何在，乃與齊侯田。", "魯國無臣子，君親義茫然。", "齊紀不並立，諸兒得稱賢。", "善惡不可掩，筆削至今傳。"]'),
('71303f83-cd43-4906-a6e6-5641169387ce','畎畝十首  其五','王十朋','宋','宋诗','song-poetry','','[]','飛飛古帝魂，哀哀寄春怨。',48,'全唐诗/poet.song.118000.json','["飛飛古帝魂，哀哀寄春怨。", "異鄉節物新，故國人事變。", "訴亡誰肯憐，啼苦血空濺。", "雲安再拜人，傷哉不復見。"]'),
('2e3d4ba7-1ee9-4863-9f55-ff1b14c567e5','畎畝十首  其六','王十朋','宋','宋诗','song-poetry','','[]','彼微雙鶺鴒，飛飛同一原。',60,'全唐诗/poet.song.118000.json','["彼微雙鶺鴒，飛飛同一原。", "急難喻兄弟，義著周雅篇。", "周公代武王，大義今古傳。", "人孰無兄弟，急難斯見焉。", "願懷周公心，無媿詩人言。"]'),
('17907295-bc63-4e3c-8dde-b97cf39f3c53','畎畝十首  其七','王十朋','宋','宋诗','song-poetry','','[]','竹有君子節，青青貫四時。',96,'全唐诗/poet.song.118000.json','["竹有君子節，青青貫四時。", "桃李媚春光，千株弄妖姿。", "世眼悅繁豔，疇能賞幽奇。", "君看桃李蹊，蹄轂紛爭馳。", "君看竹林下，形影誰相隨。", "七賢久淪沒，高躅猶可追。", "吾家植千竿，風月足自怡。", "豈不競時好，聊爲歲寒期。"]'),
('91575653-c34c-434c-a9b5-7a8b7878e7c0','畎畝十首  其八','王十朋','宋','宋诗','song-poetry','','[]','兀兀窗下士，筆耕志良苦。',72,'全唐诗/poet.song.118000.json','["兀兀窗下士，筆耕志良苦。", "黄卷對聖賢，慷慨深自許。", "一朝出干祿，得失戰匈宇。", "曲意阿有司，諛言狥人主。", "貪榮無百年，貽謗有千古。", "丈夫宜自貴，清議重刀斧。"]'),
('fe5d2dd6-24b3-4604-869e-894f63faabf5','畎畝十首  其九','王十朋','宋','宋诗','song-poetry','','[]','我豈不欲仕，時命不吾與。',48,'全唐诗/poet.song.118000.json','["我豈不欲仕，時命不吾與。", "曷不枉尺求，權門正旁午。", "非道吾弗由，茲心已先許。", "願言安貧賤，順命爲出處。"]'),
('e90cd7f6-b1e6-4c44-ab5f-6c9e69dba809','畎畝十首  其一○','王十朋','宋','宋诗','song-poetry','','[]','儒冠誤身世，偃蹇二十年。',48,'全唐诗/poet.song.118000.json','["儒冠誤身世，偃蹇二十年。", "豈不懷明主，富貴乃在天。", "平生學忠孝，自致無由前。", "青燈照夜長，感激徒自憐。"]'),
('7ec14456-5a77-46ad-b0e9-eb6cb4e31cfa','觀國朝故事  其一','王十朋','宋','宋诗','song-poetry','','[]','昔在景德初，胡虜犯中原。',96,'全唐诗/poet.song.118000.json','["昔在景德初，胡虜犯中原。", "朝廷用萊公，决策幸澶淵。", "高瓊雖武夫，能發忠義言。", "詠詩退虜騎，用醜樞相顔。", "鑾輿至北城，斷橋示不還。", "一箭斃撻覽，夜半却腥羶。", "至仁不忍殺，和好垂百年。", "偉哉澶淵功，天子能用賢。"]'),
('7755dc43-0652-47a6-b225-746f8fbccc87','觀國朝故事  其二','王十朋','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','昔在康定初，元昊叛西陲。',120,'全唐诗/poet.song.118000.json','["昔在康定初，元昊叛西陲。", "朝廷起韓范，節制閫外師。", "二公人中龍，材畧超等夷。", "匈中百萬兵，對面千里機。", "不比大老子，而令虜能欺。", "深期復靈夏，重勒燕然碑。", "軍中果興謠，西賊心膽隳。", "逆節遂稱臣，戰士解甲歸。", "社稷安泰山，四海絕瘡痍。", "堂堂寧復有，爲作思賢詩。"]'),
('e0d2e806-1927-4620-b5ec-f2f6069a46d0','觀國朝故事  其三','王十朋','宋','宋诗','song-poetry','','[]','昔在元祐初，朝廷用老成。',156,'全唐诗/poet.song.118000.json','["昔在元祐初，朝廷用老成。", "元惡首竄殛，賢雋皆彙征。", "簾幃八年政，內外咸清明。", "四夷各自守，天下幾太平。", "紹聖黨論起，宵人壞典刑。", "二蔡唱繼述，曲學尊金陵。", "忠良投海島，黨籍編姓名。", "春秋亦獲罪，學者專三經。", "心術遂大壞，風俗從此傾。", "養成前日禍，中原厭羶腥。", "我欲著一書，善惡深勸懲。", "姦諛誅朽骨，潛德發幽馨。", "六賊未足罪，禍端首熙寧。"]'),
('705abc85-fce0-417b-8511-519a61d484bc','觀國朝故事  其四','王十朋','宋','宋诗','song-poetry','','[]','富公昔使虜，厲色爭獻納。',72,'全唐诗/poet.song.118000.json','["富公昔使虜，厲色爭獻納。", "臣節安敢虧，君恩以死答。", "煌煌中國尊，忍爲豺狼屈。", "堂堂漢使者，剛氣不可折。", "斯人嗟已亡，英風復誰接。", "銜命虜庭人，偷生真婢妾。"]'),
('724c8d08-ebad-434d-bf04-4de68a40cd1d','㶁㶁岸下水','王十朋','宋','宋诗','song-poetry','','[]','㶁㶁岸下水，汝流欲何之。',84,'全唐诗/poet.song.118000.json','["㶁㶁岸下水，汝流欲何之。", "但見日東注，寧有還源期。", "尼父川上嘆，逝者亦如斯。", "人生百年間，擾擾無已時。", "利名役初心，百歡無一追。", "待汝後知悔，桑榆景堪悲。", "感此盍悟彼，毋爲浪吁嘻。"]'),
('34dfc7ae-c7fe-45ac-a1a8-07bcf329f19f','宣和乙巳冬大雪次表叔賈元實韵','王十朋','宋','宋诗','song-poetry','','[]','天公昨夜屑瓊花，三尺深深曉更加。',64,'全唐诗/poet.song.118000.json','["天公昨夜屑瓊花，三尺深深曉更加。", "柳不待春先起絮，梅非因笛自飛華。", "牧羊大窖人何在，駐馬藍關路更賒。", "安得晴天開萬里，行人愁思渺無涯。"]'),
('336e5ec8-f9d1-4c60-8cbd-662869662693','傷時感懷  其一','王十朋','宋','宋诗','song-poetry','','[]','三萬六千成擲梭，歡娛常少愁常多。',64,'全唐诗/poet.song.118000.json','["三萬六千成擲梭，歡娛常少愁常多。", "干戈今日猶未定，書劍他年知若何。", "淡蕩三秋冷時節，蕭條萬里空山河。", "傷時眼淚滿襟血，更把少陵詩句哦。"]'),
('0b07441c-b8f1-4497-b5d5-e4ceb00ab99e','傷時感懷  其二','王十朋','宋','宋诗','song-poetry','','[]','帝鄉五載亂離中，億萬蒼生陷犬戎。',64,'全唐诗/poet.song.118000.json','["帝鄉五載亂離中，億萬蒼生陷犬戎。", "二聖遠征沙漠北，六龍遥渡浙江東。", "斬姦盍請朱雲劍，射虜宜貫李廣弓。", "借問秦庭誰慟哭，草茅無路獻孤忠。"]'),
('91f55eda-b643-4b54-9035-0e08e3cfcedd','駕幸溫州次僧宗覺韻','王十朋','宋','宋诗','song-poetry','','[]','聖主南巡駐六飛，邦人咫尺見天威。',64,'全唐诗/poet.song.118000.json','["聖主南巡駐六飛，邦人咫尺見天威。", "間關高帝尚鞍馬，謹厚漢光猶絳衣。", "北斗城池增王氣，東甌山水發清輝。", "佇看天仗還京闕，無復旄頭彗紫微。"]'),
('05b098dd-4ff6-45bc-9d85-915abc43ee1c','次韻謙仲見寄','王十朋','宋','宋诗','song-poetry','','[]','湖山藍黛青，湖水琉璃碧。',288,'全唐诗/poet.song.118000.json','["湖山藍黛青，湖水琉璃碧。", "我時湖邊游，山水正秋色。", "詩翁偶乘興，來作湖邊客。", "談鋒兩初交，意氣已相得。", "詩壇予與盟，文會公爲伯。", "豪詞肆滂沛，淡語入幽寂。", "心匠巧雕斵，物態窮搜覓。", "壯哉五言城，卓爾萬仞壁。", "初疑公腸胃，百怪所窟宅。", "吐氣干雲霄，宜欲鬭霹靂。", "妙奪解牛術，奏刀聲砉剨。", "我才寸莛微，洪鍾詎能擊。", "又如鳴蟋蟀，啾然和金石。", "未窺學藩籬，敢語討奧賾。", "繆爲馬慕韓，浪作赤效白。", "奬拔非所蒙，猖狂固宜責。", "新篇又拜嘉，開緘光豔射。", "藏之比明珠，長使夜照席。", "惜哉不遇時，豈爲臧倉隔。", "儒冠五十年，世路疲行役。", "操矛赴文場，戰藝輙敗北。", "書劍兩無成，泥塗困蹤跡。", "龍鍾似東野，窮愁攬懷臆。", "空吟三百篇，高視古無敵。"]'),
('5c801e02-9ad3-4d8f-b419-a097642c8348','送凌知監赴玉環次覺無象韵','王十朋','宋','宋诗','song-poetry','','[]','晨興趣行裝，秋色滿離席。',108,'全唐诗/poet.song.118000.json','["晨興趣行裝，秋色滿離席。", "悲風苦送聲，短晷頻移刻。", "蘭舟薄暮發，去去轉遐僻。", "極目望官所，沉沉煙靄積。", "清有濯纓水，白有潄齒石。", "悠然水石間，官情聊自適。", "朝焉游其南，暮焉戲其北。", "彼微山中鳥，亦將識公德。", "公無賦歸去，田園付人役。"]'),
('f947f3bf-da5f-41ce-8660-41f83e394776','答毛唐卿虞卿借昌黎集','王十朋','宋','宋诗','song-poetry','','[]','予少不知學古難，學古直欲學到韓。',208,'全唐诗/poet.song.118000.json','["予少不知學古難，學古直欲學到韓。", "柰何韓實不易學，怛覺晝夜心力殫。", "茫然故步亦已失，有類壽陵學邯鄲。", "雖然予心未肯已，尚欲勉强求其端。", "跬步不休效駑馬，千里未至空長嘆。", "羨君兄弟俱早慧，家學豈止傳柔溫。", "聖經賢傳飫已久，百家諸子皆蠹殘。", "學文要須學韓子，此外衆說徒曼曼。", "韓子皇皇慕仁義，力排佛老回狂瀾。", "三百年來道益貴，太山北斗世仰觀。", "我生于今望之遠，時時開卷相欣懽。", "豈惟廬陵惜舊本，我亦惜此祇自看。", "子今欲假敢違命，願子寶之同琅玕。"]'),
('f8ee5c52-4277-4de9-a33e-4ec41f75ac6c','辛亥九日侍家君同孫子淵子昭子尚登高于家之東山時菊花未開坐客皆以爲恨至十月望獨步東籬下見前日青枝已爛熳矣東坡云凉天佳月即中秋菊花開日乃重陽不以日月斷也於是命酒肴呼鄰里飲於叢畔云','王十朋','宋','宋诗','song-poetry','','[]','前日重陽日，與客同登翫。',132,'全唐诗/poet.song.118000.json','["前日重陽日，與客同登翫。", "有酒無菊花，把盃一長嘆。", "良辰苦易失，十月今又半。", "緬焉想前遊，獨到東籬畔。", "鮮鮮霜中菊，滿地金錢粲。", "我思東坡言，隣里乃相喚。", "斬新作重九，不以日月斷。", "人生貴適意，世俗豈能絆。", "遇酒即歡樂，取醉期爛熳。", "羲和馭白日，疾劇走丸彈。", "百年能幾何，不飲乃癡漢。"]'),
('aa332bb8-1cad-4f83-8eea-8995b9260e0c','次韻季仲默見寄','王十朋','宋','宋诗','song-poetry','','[]','予少擇交游，有友四五子。',144,'全唐诗/poet.song.118000.json','["予少擇交游，有友四五子。", "仲默姿不凡，好學喜觀史。", "寄我新詩章，我驚欲掩耳。", "昔日心未降，而今已降矣。", "我久事章句，滋味一盃水。", "平生况多愚，於己不自揣。", "林間等蟬噪，井底作蛙視。", "今焉見君詩，吾誠二蟲比。", "豈敢妬且熱，低頭拜不止。", "思欲和其音，兀坐輙忘起。", "沉吟竟不成，徒覺倦兩髀。", "從今焚筆硯，不復坐書几。"]'),
('f2d9884d-6ec0-4910-97d1-f9f484ab5dfa','題湖邊莊','王十朋','宋','宋诗','song-poetry','','[]','十里青山蔭碧湖，湖邊風物畫難如。',64,'全唐诗/poet.song.118000.json','["十里青山蔭碧湖，湖邊風物畫難如。", "夕陽茅舍客沽酒，明月小橋人釣魚。", "舊卜草莊臨水竹，來尋野叟問耕鋤。", "他年待掛衣冠後，乘興扁舟取次居。"]'),
('bf51861c-ada7-409c-b226-4fdbd74a2931','湖邊懷劉謙仲','王十朋','宋','宋诗','song-poetry','','[]','湖山如畫水如藍，杖屨湖邊酒半酣。',64,'全唐诗/poet.song.118000.json','["湖山如畫水如藍，杖屨湖邊酒半酣。", "往事蕭條誰共說，舊游零落我何堪。", "炎凉世態從他變，生死交情祇自諳。", "詩客有魂招不得，秋風依舊滿江南。"]'),
('266d04ff-52cb-4274-a0ac-609a2d29fa22','寄孫永之','王十朋','宋','宋诗','song-poetry','','[]','詠歌沂水舞雩風，氣壓當時冠與童。',64,'全唐诗/poet.song.118000.json','["詠歌沂水舞雩風，氣壓當時冠與童。", "人似賈生年更少，家傳孫綽賦尤工。", "孤羆傲兀深叢裏，一鶚軒昂衆鳥中。", "早取功名寄衣缽，古來相種出山東。"]'),
('72a1274e-3dab-47f8-ba3e-71524ba64e35','寄毛虞卿','王十朋','宋','宋诗','song-poetry','','[]','文會今年喜重尋，葭姿玉質又同林。',64,'全唐诗/poet.song.118000.json','["文會今年喜重尋，葭姿玉質又同林。", "弟兄並秀如君少，朋友相知獨我深。", "一別幾勞終夜夢，相逢更話百年心。", "長卿賦有凌雲志，却笑區區蚓竅吟。"]'),
('9b939298-c338-4568-8cc8-9fa95017d78c','次韵虞卿送別','王十朋','宋','宋诗','song-poetry','','[]','喜君直諒更多聞，共惜光陰寸與分。',64,'全唐诗/poet.song.118000.json','["喜君直諒更多聞，共惜光陰寸與分。", "螢照夜窗纔煖席，蟬吟秋樹又離群。", "尊前忍聽陽關曲，江上愁看日暮雲。", "別後誰能慰牢落，錦囊長带故人文。"]'),
('c41f054c-1d55-4330-ae68-6e0600842872','次韵劉方叔見寄','王十朋','宋','宋诗','song-poetry','','[]','交情貴久豈須頻，我輩尤宜率且真。',64,'全唐诗/poet.song.118000.json','["交情貴久豈須頻，我輩尤宜率且真。", "子政有孫誠益友，長卿何代乏詩人。", "論文初喜逢知己，言志深期共致身。", "箕斗相望正南北，潁川何夕聚荀陳。"]'),
('47c73200-5dd3-4ad3-b280-c8c9898cf3b8','寄方叔','王十朋','宋','宋诗','song-poetry','','[]','故人一別路漫漫，又覺春生到水村。',64,'全唐诗/poet.song.118000.json','["故人一別路漫漫，又覺春生到水村。", "魚躍雁飛空注目，柳開梅落自消魂。", "唱酬應有詩千首，談笑長懷酒一尊。", "正是剛腸九回處，子規聲斷月黄昏。"]'),
('e8e4c778-f012-48ab-a074-dbc40cb0b12b','潘岐哥','王十朋','宋','宋诗','song-poetry','','[]','君不見鳳之雛，驥之子，潘家岐哥無乃是。',147,'全唐诗/poet.song.118000.json','["君不見鳳之雛，驥之子，潘家岐哥無乃是。", "鶴溪仙子降英靈，雁蕩名山鍾秀美。", "顔色純明白玉璞，精神皎潔秋江水。", "胸中之氣已吞牛，開眼睛光如虎視。", "此兒奇絕非常兒，小子觀人蓋多矣。", "寧非漢代偷桃朔，別是唐家謫仙李。", "愚知先生百不憂，但患此兒名盛耳。", "先生才高爵未綰，頼渠力振家聲起。", "鹿巖他日築高門，車馬煌煌塞閭里。"]'),
('d0916928-5e13-46fa-9770-af985c35cbd0','贈余取新','王十朋','宋','宋诗','song-poetry','','[]','小邑那能敵大邦，與君角力固非雙。',64,'全唐诗/poet.song.118000.json','["小邑那能敵大邦，與君角力固非雙。", "氣驕欲縱偏師戰，勢屈翻求北面降。", "深懼操戈重入室，自慚閣筆久臨窗。", "定知紙價從今貴，余子詩名滿蜃江。"]'),
('d55c7c74-eb25-4a78-ae5b-673ac595d2c7','次韻昝監務早梅','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','群芳避路放梅開，奔走遊人滿砌苔。',64,'全唐诗/poet.song.118000.json','["群芳避路放梅開，奔走遊人滿砌苔。", "半樹溪邊衝雪破，一枝頭上带春回。", "月移瘦影供吟興，風薦幽香襲酒盃。", "剛被西湖都道盡，至今詩客句難裁。"]'),
('7c80f8a8-4436-4d4a-a495-9254cdb570ad','寄賈一節','王十朋','宋','宋诗','song-poetry','','[]','無奈窮冬易感傷，况添離別助凄凉。',64,'全唐诗/poet.song.118000.json','["無奈窮冬易感傷，况添離別助凄凉。", "五更月殘頻成夢，十里青山幾斷腸。", "短棹未乘晨雪去，尺書聊遣暮鴻將。", "少年勉力親燈火，要使家聲繼洛陽。"]'),
('cd5ae0bc-90a3-49a2-a666-620f4efc9bc9','孫子尚過明慶以詩見招未及往次韵','王十朋','宋','宋诗','song-poetry','','[]','剡溪未起子猷尋，空對溪山恨滿襟。',64,'全唐诗/poet.song.118000.json','["剡溪未起子猷尋，空對溪山恨滿襟。", "孤雁遠來天杳杳，故人相望雪深深。", "思君一日成三歲，寄我行書直萬金。", "惆悵今宵一尊酒，自邀明月伴孤斟。"]'),
('2fc1d7ac-add9-4664-aff3-ce49bd0cc8c2','送子尚如浙西','王十朋','宋','宋诗','song-poetry','','[]','嗟我窮居海之角，人物素殊鄒魯俗。',320,'全唐诗/poet.song.118000.json','["嗟我窮居海之角，人物素殊鄒魯俗。", "年雖及冠無交游，孤陋寡聞嗟獨學。", "閉門不出長太息，思得其人共磨琢。", "孫子往從西北來，頭角軒軒真一鶚。", "飄飄逸氣凌雲霄，凜凜高談吐鋒鍔。", "文辭翰墨兩奇絕，世上群兒徒碌碌。", "我昔風期一相遇，欣然握手論心腹。", "衡茅三度枉車軒，書劍連年共燈燭。", "論交自喜得房杜，言志端能效來郝。", "長篇短韵迭賡唱，明月清風共斟酌。", "囊無一錢身不憂，食止一簞貧自樂。", "有友如君復何憾，百不爲多一已足。", "今焉捨我將何之，遂使江鄉復蕭索。", "南國初寒旅雁來，吳江已冷丹楓落。", "惜君不盡與君別，兀坐無言情更惡。", "干戈未息行路難，胡馬今獨飲河洛。", "京國有家歸未得，錢塘此去仍棲託。", "會須徒步謁天子，慨然一吐胸中畧。", "請纓縛虜壯志士，庶使平時語無怍。", "相將煖律破寒梅，驛筒遠寄無辭數。"]'),
('b49f3e70-7371-4291-8547-af59bb5bb8af','懷子尚','王十朋','宋','宋诗','song-poetry','','[]','滿眼干戈行路難，故人千里駐征鞍。',64,'全唐诗/poet.song.118000.json','["滿眼干戈行路難，故人千里駐征鞍。", "幾勞終日馳魂夢，安得乘風插羽翰。", "水北山南春寂寂，天涯海角路漫漫。", "欲憑人寄新消息，手把梅枝仔細看。"]'),
('6dea6700-a8da-4fcd-a8cd-3e77ed4e1b6d','樂清僧寮有過客錢之翰題二絕有傷時之嘆因次其韵  其一','王十朋','宋','宋诗','song-poetry','','[]','終日傷心淚濺花，干戈滿眼恨無涯。',32,'全唐诗/poet.song.118000.json','["終日傷心淚濺花，干戈滿眼恨無涯。", "衣冠南渡如東晉，安得車書混一家。"]'),
('4ddb5878-c146-49ad-9a2b-63a115ab0abe','樂清僧寮有過客錢之翰題二絕有傷時之嘆因次其韵  其二','王十朋','宋','宋诗','song-poetry','','[]','功名誰復漢嫖姚，壯士逢時豈憚勞。',32,'全唐诗/poet.song.118000.json','["功名誰復漢嫖姚，壯士逢時豈憚勞。", "半夜飛來看寶劍，此身端許擲鴻毛。"]'),
('571cd628-9ca4-4aac-a8bf-03e207d3ea20','讀親征詔書二首  其一','王十朋','宋','宋诗','song-poetry','','[]','逆虜何時正典刑，久聞諸將擁彊兵。',64,'全唐诗/poet.song.118000.json','["逆虜何時正典刑，久聞諸將擁彊兵。", "中原未雪十年恥，聖主自勞千里征。", "楚國羣臣誰慟哭，杜陵野客自吞聲。", "君恩壓頂丘山重，命擲鴻毛未是輕。"]'),
('8202a050-a6cb-466e-8744-5d535b8b6f1e','讀親征詔書二首  其二','王十朋','宋','宋诗','song-poetry','','[]','諸將年來已極榮，回看煙閣欠功名。',64,'全唐诗/poet.song.118000.json','["諸將年來已極榮，回看煙閣欠功名。", "八年猶未平淮甸，一戰那能復帝京。", "畎畝忠臣自憂國，閭閻小子妄談兵。", "憑誰决得天河水，一洗乾坤萬里清。"]'),
('2be8e366-b754-4a82-85f0-c05dc6f0f601','次韵題曹大夫懷忠閣','王十朋','宋','宋诗','song-poetry','','[]','小閣誰懷畎畝情，遥瞻天日眼增明。',64,'全唐诗/poet.song.118000.json','["小閣誰懷畎畝情，遥瞻天日眼增明。", "平生憂國丹心在，一飯思君血淚橫。", "豊沛功臣真有種，并汾壯士素蜚聲。", "區區問舍求田者，應被元龍一笑輕。"]'),
('f45cc9ee-621e-49d6-aee5-5e5493986d08','聞韓帥世忠退保丹陽遠近憂懼州縣議結鄉兵以備不虞閭巷少年貫弓走馬若有得色感而有作','王十朋','宋','宋诗','song-poetry','','[]','逆虜縱橫未剪齊，王師退保浙江西。',64,'全唐诗/poet.song.118000.json','["逆虜縱橫未剪齊，王師退保浙江西。", "羽書日報猶未息，戎捷遠來何太稽。", "千里戰雲新鬼哭，滿天陰雨夜烏啼。", "臂弓腰箭誰家子，竟日鳴鞭躍馬蹄。"]'),
('5232e559-7b6b-46f0-8caa-3d2664be79b9','和劉方叔溪上一絕','王十朋','宋','宋诗','song-poetry','','[]','杖屨徘徊駐碧溪，遥看飛瀑下崔嵬。',32,'全唐诗/poet.song.118000.json','["杖屨徘徊駐碧溪，遥看飛瀑下崔嵬。", "乘槎欲訪吹簫客，煙草茫茫沒舊臺。"]'),
('12c8e0ed-8981-4f26-ae2c-d2cb1aecbcff','和方叔見贈二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','相對清談味有餘，始知勝讀十年書。',32,'全唐诗/poet.song.118000.json','["相對清談味有餘，始知勝讀十年書。", "塵襟不用頻揮麈，自有清風爲掃除。"]'),
('2da3c249-aaf7-4a51-8636-df9ca733201e','和方叔見贈二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','一舍蕭然學有餘，窗間遮眼盡文書。',32,'全唐诗/poet.song.118000.json','["一舍蕭然學有餘，窗間遮眼盡文書。", "已將事業盟燈火，萬事何煩酒破除。"]'),
('90653ba1-d5bd-4a6e-920f-c07003f9f78e','得陳商霖書','王十朋','宋','宋诗','song-poetry','','[]','山館無人慰索居，喜君交契有終初。',64,'全唐诗/poet.song.118000.json','["山館無人慰索居，喜君交契有終初。", "扁舟方起雪溪興，尺素又傳魚腹書。", "炊黍定尋前日約，題詩寧怨故人踈。", "好來相共親燈火，可惜青春度莫虛。"]'),
('29c62d7d-f012-4d47-811c-753f48af6ec1','昔與南浦劉謙仲大梁孫子尚游自劉死橫陽孫亦有浙西之役交舊零落爲之慨然感而有作','王十朋','宋','宋诗','song-poetry','','[]','劉翁泯泯已新鬼，孫子飄飄猶旅人。',64,'全唐诗/poet.song.118000.json','["劉翁泯泯已新鬼，孫子飄飄猶旅人。", "詩酒舊游誰在眼，江山回首自傷神。", "招魂擬向橫陽道，有夢長飛霅水濱。", "死者不生生者別，死生離別兩沾巾。"]'),
('0a1d5f9d-d47b-4200-b82a-6b78720975e9','次韻李刑曹病起書懷','王十朋','宋','宋诗','song-poetry','','[]','中原回首尚塵飛，書劍南來早識機。',64,'全唐诗/poet.song.118000.json','["中原回首尚塵飛，書劍南來早識機。", "方事高眠學安石，却愁多病似王徽。", "腸枯謾有書千卷，腰瘦難勝带十圍。", "志士未逢聊爾耳，古人何用泣牛衣。"]'),
('25813369-a063-49e5-8448-caf95bcd245b','又用前韻','王十朋','宋','宋诗','song-poetry','','[]','文園病思亂如飛，禪榻逍遥謾息機。',64,'全唐诗/poet.song.118000.json','["文園病思亂如飛，禪榻逍遥謾息機。", "漸喜珠絲封藥裹，未容鶴髮上簪徽。", "酒能伐性聊須止，碁恐勞神未敢圍。", "惟有詩懷禁不得，任他憔瘦不勝衣。"]'),
('d15c6c5e-56d5-4b88-afaa-9dae8a386e23','送曹大夫赴行在所','王十朋','宋','宋诗','song-poetry','','[]','西北連年殺氣高，群盜橫行如蝟毛。',96,'全唐诗/poet.song.118000.json','["西北連年殺氣高，群盜橫行如蝟毛。", "廉頗李牧不世出，吾皇側席心焦勞。", "汾陽自古多壯士，曹侯意氣千人豪。", "年今四十猶偃蹇，拊髀長歎淹龍韜。", "慨然揮袂謁行在，報國已淬腰間刀。", "登壇拜將預指日，看君舉手清風濤。"]'),
('e49b4fc7-f6e5-414c-a14b-1a608b51a8a9','送表叔賈元範赴省試','王十朋','宋','宋诗','song-poetry','','[]','河東先生才行高，昔游太學聯烝髦。',192,'全唐诗/poet.song.118000.json','["河東先生才行高，昔游太學聯烝髦。", "雄文偉論萬人敵，糠秕歆向奴劉曹。", "摶風自許九萬里，肯作斥鷃游蓬蒿。", "禮闈一戰果得雋，妙割不折庖丁刀。", "禮部無端抑韓子，至今士論猶嗷嗷。", "霜蹄暫蹶志益銳，不學郊島徒悲號。", "聖君圖治方側席，茲復下詔求賢豪。", "壯懷思雪會稽耻，廣場猛效蘭臯鏖。", "焚舟决勝在此舉，鄉閭屬望心焦勞。", "天庭射策决素藴，忠言爲國驅腥臊。", "區區一第溷君耳，要將事業窺伊臯。", "瓊林宴罷躍歸騎，薰風拂面吹恩袍。"]'),
('41aadf3a-e89f-48d6-81e9-77fbe60dd5b4','答季仲宜','王十朋','宋','宋诗','song-poetry','','[]','我昔從君伯氏游，短素長牋日唱酬。',96,'全唐诗/poet.song.118000.json','["我昔從君伯氏游，短素長牋日唱酬。", "凌雲健筆驅山丘，欲追李杜參曹劉。", "子今又復振風流，可人一氣真吾儔。", "明珠白璧蒙暗投，自揣無堪但增羞。", "君家棠棣才俱優，吾知徐公百不憂。", "更能勉力追前修，俯捨青紫何須求。"]'),
('b9b6aba7-6549-43af-b375-0d5d6eecf48e','夜聽雙瀑同劉方叔毛虞卿聯句','王十朋','宋','宋诗','song-poetry','','[]','夜靜雙瀑喧，遥聞疑雨來。',72,'全唐诗/poet.song.118000.json','["夜靜雙瀑喧，遥聞疑雨來。", "澗壑生清風，襟宇捐纖埃。", "飛鳴撼半空，暗想飄瓊瑰。", "前觀阻步屧，側耳成徘徊。", "蕭然山館間，此興何悠哉。", "子晉不復見，月白空蕭臺。"]'),
('1773adb2-dd43-4f4b-a911-9b60d3714f04','對月同方叔聯句','王十朋','宋','宋诗','song-poetry','','[]','與君坐階除，遥望海上月。',48,'全唐诗/poet.song.118000.json','["與君坐階除，遥望海上月。", "試舉太白盃，借問幾圓缺。", "人生易分散，動作隔年別。", "今宵對嬋娟，莫放酣歌絕。"]'),
('4a0496fd-5d2e-4777-838a-473654459269','游簫峯','王十朋','宋','宋诗','song-poetry','','[]','蠟屐穿雲去，山深喜路通。',48,'全唐诗/poet.song.118000.json','["蠟屐穿雲去，山深喜路通。", "人家煙色裏，古寺水聲中。", "金濺星猶在，丹成竈已空。", "吹簫人不見，臺下想仙風。"]'),
('f2b963dd-ef1b-4192-818c-2ed1b2e5c1ff','題雙瀑','王十朋','宋','宋诗','song-poetry','','[]','瀑水簫峯下，靈源不可尋。',48,'全唐诗/poet.song.118000.json','["瀑水簫峯下，靈源不可尋。", "倚天雙寶劍，點石萬星金。", "勢合鯨鯢鬭，聲聯虎豹吟。", "我來游勝境，洗耳聽清音。"]'),
('8a28bbcd-c181-46ea-8bf4-916bc89b57d6','送劉方叔兼簡全之','王十朋','宋','宋诗','song-poetry','','[]','相見無多日，依前又素居。',48,'全唐诗/poet.song.118000.json','["相見無多日，依前又素居。", "斷魂梅的皪，過眼柳蕭踈。", "疋馬來時路，征鴻別後書。", "君歸見溫叟，爲我問何如。"]'),
('3c7ad2c1-6212-42ac-b7bf-b00b5e42bf78','送陳商霖','王十朋','宋','宋诗','song-poetry','','[]','相逢猶未欵，作別太匆匆。',48,'全唐诗/poet.song.118000.json','["相逢猶未欵，作別太匆匆。", "日落江東莫，人歸冀北空。", "音塵應暫隔，談笑更誰同。", "回首簫峰外，明朝我亦東。"]'),
('3615b7db-24fc-4126-88c8-939dc55aeddc','晝卧書懷','王十朋','宋','宋诗','song-poetry','','[]','書齋終日無人過，閉戶便便事高卧。',64,'全唐诗/poet.song.118000.json','["書齋終日無人過，閉戶便便事高卧。", "炎蒸爍體汗流珠，蚊蚋費拍蠅勞驅。", "南窗清風可供客，一枕萬錢無計得。", "夢魂未到鄉無何，起來搔首空吟哦。"]'),
('79689948-ae08-459c-809a-e4be566d1572','用前韻贈劉全之','王十朋','宋','宋诗','song-poetry','','[]','一聲啼鳥簷間過，喚起幽人午窗卧。',64,'全唐诗/poet.song.118000.json','["一聲啼鳥簷間過，喚起幽人午窗卧。", "甕頭一滴價如珠，窮愁衮衮憑誰驅。", "溪畔相逢盡詩客，豪邁獨輸劉夢得。", "篇章自有神誰何，詎須元白參吟哦。"]'),
('e800353a-e752-46fe-8f09-32f2672a9f18','有客贈酒同舍終夕盡歡復用前韻','王十朋','宋','宋诗','song-poetry','','[]','濁醪不向牆頭過，吏部方思甕間卧。',64,'全唐诗/poet.song.118000.json','["濁醪不向牆頭過，吏部方思甕間卧。", "書齋得酒勝得珠，萬事盡向杯中驅。", "坐中俱是高陽客，一笑相逢寧易得。", "明朝酒醒奈愁何，勸君莫惜同吟哦。"]'),
('96306eee-8247-414d-b2bd-0dda83bdc7b2','復用前韻','王十朋','宋','宋诗','song-poetry','','[]','歲月侵尋等閑過，草廬尚作南陽卧。',64,'全唐诗/poet.song.118000.json','["歲月侵尋等閑過，草廬尚作南陽卧。", "報國未爲蛇吐珠，許身定與誰齊驅。", "謾比凌雲詞賦客，意氣飄飄真自得。", "金溪風月價幾何，要須買斷共吟哦。"]'),
('fd55e8ea-8a6a-4ed5-a997-38c4227b265d','戲酬毛虞卿見和','王十朋','宋','宋诗','song-poetry','','[]','杜門不願高軒過，聊學東山謝公卧。',64,'全唐诗/poet.song.118000.json','["杜門不願高軒過，聊學東山謝公卧。", "傷時淚泣鮫人珠，揮毫寫懣風雨驅。", "友生笑我爲狂客，齊楚未須論失得。", "他年功業定如何，醉中細把君詩哦。"]'),
('f047f1ae-b2c7-4ab2-a25b-207d3610f622','懷歸預別同舍','王十朋','宋','宋诗','song-poetry','','[]','長念雙親垂素髮，不奉甘旨今數月。',64,'全唐诗/poet.song.118000.json','["長念雙親垂素髮，不奉甘旨今數月。", "溪山雖好何如歸，吾心已逐秋雲飛。", "欲別良朋重嗚咽，催人啼鳥聲何切。", "明日琴書隨我東，何如尊酒重相逢。"]'),
('b97fba31-f041-439f-923e-60c8a7617bfa','寄僧覺無象','王十朋','宋','宋诗','song-poetry','','[]','我昔居鹿巖，時來潛澗游。',240,'全唐诗/poet.song.118000.json','["我昔居鹿巖，時來潛澗游。", "西坡訪覺老，終日爲遲留。", "高談窮古今，滿坐風生秋。", "令我名利心，一聽渾欲休。", "論詩出古律，有唱無不酬。", "篇章溢縑素，錦綉爛然浮。", "此老豈易得，當於前輩求。", "吾生限太晚，見師已白頭。", "儒釋道不同，相從苦無由。", "三年游金溪，兀坐顔常愀。", "出門無游從，獨賦臨清流。", "金溪可無僧，孰是西坡儔。", "深房鎖花木，妙供羅珍羞。", "益作潛澗思，剛腸如轉輈。", "魂夢不自禁，夜夜飛山陬。", "前日遇諸塗，一笑忘百憂。", "相視未及語，歸袖風颼颼。", "別來能幾時，不覺歲月遒。", "聞師結蓮社，旦莫事真修。", "我狂似靈運，此志那能投。"]'),
('ccf17496-0bbd-4dd1-999b-6a60ed981aa9','秋日山林即事次叔父寶印師韻  其一','王十朋','宋','宋诗','song-poetry','','[]','蕭蕭蘋末生秋聲，登臨遐想蘭臺英。',96,'全唐诗/poet.song.118000.json','["蕭蕭蘋末生秋聲，登臨遐想蘭臺英。", "天高氣清水碧色，明月相映光如瓊。", "脫葉翩翻下深樾，蓮社高人詩興發。", "講外吟餘心更閑，白雲滿袖眠禪窟。", "竹徑通幽人不來，鳥鳴山靜獨徘徊。", "應笑世間名利客，一生擾擾徒悲哀。"]'),
('16554c3b-d795-4008-a9d5-6484f42c64c0','秋日山林即事次叔父寶印師韻  其二','王十朋','宋','宋诗','song-poetry','','[]','清凉滌煩襟，塵慮脫心境。',72,'全唐诗/poet.song.118000.json','["清凉滌煩襟，塵慮脫心境。", "山城過踈雨，水國生新景。", "蟲鳴月滿林，雁度雲橫嶺。", "感物夜九起，謀身日三省。", "平生功名心，鬰鬰猶未逞。", "深美白雲人，身閑時自永。"]'),
('7b21a299-1eb7-4c47-a293-0d31b05bd890','和懷孫子尚二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','澤國蕭蕭晚吹凉，東籬黄菊爲誰香。',32,'全唐诗/poet.song.118000.json','["澤國蕭蕭晚吹凉，東籬黄菊爲誰香。", "故人一別路千里，夜雨何時更對床。"]'),
('ee36945a-5bcb-4aa0-b726-109f19c125e5','和懷孫子尚二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','記得年時訪我游，壁間文字數行留。',32,'全唐诗/poet.song.118000.json','["記得年時訪我游，壁間文字數行留。", "溪山風月依然好，不對芳尊又一秋。"]'),
('e9f8578a-6f1d-4fb1-b644-32cd26d7e9ff','季令生日','王十朋','宋','宋诗','song-poetry','','[]','佳氣光芒藹劍池，慶門呈瑞應熊羆。',64,'全唐诗/poet.song.118000.json','["佳氣光芒藹劍池，慶門呈瑞應熊羆。", "人間秋色平分際，天上冰輪欲滿時。", "何處楚丘占季子，自應無忌似牢之。", "姮娥預把蟾宮桂，歲歲飄香薦壽巵。"]'),
('ade064d0-43be-4104-96b8-1e1e4e3a9bfa','徐丞生日','王十朋','宋','宋诗','song-poetry','','[]','日月俱陽節物新，先期誰應菊花辰。',64,'全唐诗/poet.song.118000.json','["日月俱陽節物新，先期誰應菊花辰。", "未於崧嶽生賢佐，且向柯山出異人。", "月吐霜天鍾氣象，江涵秋水聚精神。", "華堂獻壽人多少，盡是明朝落帽賓。"]'),
('e6f46f1d-8efc-4e99-aa09-14d65d44e1aa','思友','王十朋','宋','宋诗','song-poetry','','[]','夜雨暗點滴，窗風冷掀翻。',48,'全唐诗/poet.song.118000.json','["夜雨暗點滴，窗風冷掀翻。", "藜牀卧幽獨，好夢俄驚殘。", "故人在何處，遠隔烟水村。", "欹枕不復見，傷心涕汍瀾。"]'),
('45143e56-1a89-4589-a894-0e95d5a37d92','縣學落成百韻','王十朋','宋','宋诗','song-poetry','','[]','炎正中微後，皇家再造年。',288,'全唐诗/poet.song.118000.json','["炎正中微後，皇家再造年。", "斯文天未喪，吾道聖相傳。", "黼扆端周冕，巖廊拱舜絃。", "宸章麗朝日，奎畫煥中天。", "賈馬朝丹闕，皇夔捧御筵。", "雲龍慶相遇，星鳳快爭先。", "金馬袍披錦，戎亭帳褫氊。", "崇儒符漢武，復古慕周宣。", "方議成均制，仍增博士員。", "佇觀旂茷茷，行賁帛戔戔。", "詞賦揚群彥，賢良策萬全。", "圜橋漢億萬，鼓篋魯三千。", "狂客休歌鳳，騷人肯釣鯿。", "文風暢蠻貊，士氣壓腥羶。", "王化誠無外，吾邦素自偏。", "魚鹽人競習，刀筆世相沿。", "甘學樊遲稼，紛求許汜田。", "揶揄戲縫掖，膜唄奉真詮。", "未振寒鄉陋，那經殺氣纏。", "閭閻森白刃，庠序燎寒煙。", "斷簡嗟何考，青衿痛自憐。", "詩存傷瓠葉，禮廢憶豚肩。", "磬碎交州石，弓焚矍相弦。", "水流空渙渙，草碧自芊芊。"]'),
('d147f2c0-7a95-432d-b782-e2f9344639d0','送劉方叔季文游鴈山','王十朋','宋','宋诗','song-poetry','','[]','二客騷腸不耐秋，飄然蠟屐去尋幽。',64,'全唐诗/poet.song.118000.json','["二客騷腸不耐秋，飄然蠟屐去尋幽。", "蕩中若要窮青眼，巖下先須問白頭。", "詩社不容添異姓，名山應豈遇清流。", "會須乘興天台去，澗水桃花訪舊游。"]'),
('2d785317-ccc0-4c89-a3f5-17cf4b08ea4f','游西岑遇雨','王十朋','宋','宋诗','song-poetry','','[]','西岑風物秋更嘉，杖藜出郭歡無涯。',128,'全唐诗/poet.song.118000.json','["西岑風物秋更嘉，杖藜出郭歡無涯。", "深村有酒隔烟渚，共乘小艇穿蘆花。", "羅裙綽約越溪女，茅舍迫窄吳儂家。", "牀頭新釀喜正熟，千金倒甕傾流霞。", "天公妬我一日樂，俄然雨脚來如麻。", "醉歸扶路泥沒股，冠巾不整頭鬖髿。", "人生貴在適意耳，安能局縮身如蝸。", "杖頭有錢即相覓，明日更泛仙源槎。"]'),
('872bec6c-3b54-4094-ad3e-99e83a5c9a8f','幽居三詠 脩竹','王十朋','宋','宋诗','song-poetry','','[]','我得家傳好此君，剩栽干挺拂青雲。',64,'全唐诗/poet.song.118000.json','["我得家傳好此君，剩栽干挺拂青雲。", "塵埃不掃自然去，風月有餘誰可分。", "萬籜蒼龍春後見，滿軒鳴玉夜深聞。", "時時助我毫端興，宜與江山共策勳。"]'),
('830e53d7-7f73-4b61-8c59-93d876141925','幽居三詠 黄楊','王十朋','宋','宋诗','song-poetry','','[]','兵火回頭二十年，吾家此樹實青氊。',64,'全唐诗/poet.song.118000.json','["兵火回頭二十年，吾家此樹實青氊。", "兒時尚及見封植，亂後那知獨保全。", "雖荷生成能蓊鬰，不輕剪拂豈團圓。", "主翁不忍加斤斧，舊物於人最可憐。"]'),
('97c9255f-4461-401f-baa9-5feecaad60e6','幽居三詠 丁香花','王十朋','宋','宋诗','song-poetry','','[]','玄冬萬木落如掃，苦恨江梅開不早。',128,'全唐诗/poet.song.118000.json','["玄冬萬木落如掃，苦恨江梅開不早。", "誰言菊後便無花，更有丁香慰枯槁。", "雨膏碧葉剪琉璃，風薦幽葩噴龍腦。", "小軒深院夜凄清，月白霜寒天色好。", "素面含情宋玉愁，仙肌带濕真妃澡。", "何人爲取藥中名，端爲花能除病惱。", "我時獨步瓊枝邊，相向無言意傾倒。", "臨風三嗅更徘徊，研墨爲花加品藻。"]'),
('b59d72cd-12e1-44b5-ae3d-88508cbd2709','鄭丞生日  其一','王十朋','宋','宋诗','song-poetry','','[]','九日人間氣象新，鄭公家誕少康成。',64,'全唐诗/poet.song.118000.json','["九日人間氣象新，鄭公家誕少康成。", "玉山肌骨侵人瑩，秋水精神照坐明。", "奕世簪纓真烜赫，沖天頭角正崢嶸。", "願公此日身長健，醉把茱萸泛壽觥。"]'),
('a72b8e0a-b9b8-4709-97a4-b226817ea50d','鄭丞生日  其二','王十朋','宋','宋诗','song-poetry','','[]','賢關當日厠英游，意氣軒軒壓輩流。',64,'全唐诗/poet.song.118000.json','["賢關當日厠英游，意氣軒軒壓輩流。", "心授廣文真翰墨，家傳北海舊春秋。", "棠陰惠愛留三邑，蓮幕聲名重一州。", "賓客盈門望推轂，藍田松竹可能留。"]'),
('38f17ac6-c40b-4e39-90d0-1d3a07913078','縣學別同舍','王十朋','宋','宋诗','song-poetry','','[]','蕭瑟秋聲起桂枝，登臨誰賦送將歸。',64,'全唐诗/poet.song.118000.json','["蕭瑟秋聲起桂枝，登臨誰賦送將歸。", "伴人燈火情猶在，過眼烟雲事已非。", "記取虀鹽同冷落，忍教襟袂遽分違。", "明朝一笑江山隔，望斷日邊鴻雁飛。"]'),
('c562330a-b27b-4d2e-8c64-ab2f0ad87327','次韻曾尉易任青田留別','王十朋','宋','宋诗','song-poetry','','[]','梅仙樂教意尤勤，絳帳煎膏至夜分。',64,'全唐诗/poet.song.118000.json','["梅仙樂教意尤勤，絳帳煎膏至夜分。", "心學盡傳隋董薛，詞章高壓漢卿雲。", "誰知有力能攘我，不許諸生久借君。", "駟馬重來定何日，好看雙挂散清芬。"]'),
('b2ce01d1-c88b-43d8-8865-c826b6b2bdf0','淫雨','王十朋','宋','宋诗','song-poetry','','[]','春雨無端苦浸淫，滿天飛霧日光沉。',64,'全唐诗/poet.song.118000.json','["春雨無端苦浸淫，滿天飛霧日光沉。", "出門蒸潤濡衣重，歸路泥塗沒股深。", "欲與陽烏開烈豔，試呼風伯掃煩陰。", "明朝會見佳天氣，只恐春歸無處尋。"]'),
('3091df5d-e789-4168-b2b8-9817f506bca1','仰先生挽詞','王十朋','宋','宋诗','song-poetry','','[]','諸生衮衮登科第，造物苦公深可憐。',64,'全唐诗/poet.song.118000.json','["諸生衮衮登科第，造物苦公深可憐。", "身到蟾宮都幾日，名書鬼錄已經年。", "數同子厚無如命，才似韓公合在天。", "慎水諸生哭相向，築場無計媿前賢。"]'),
('05113605-ce46-4394-a6da-e32cd2e842d8','寄潘先生','王十朋','宋','宋诗','song-poetry','','[]','蕭踈鬢髮老安仁，才出人頭未免貧。',64,'全唐诗/poet.song.118000.json','["蕭踈鬢髮老安仁，才出人頭未免貧。", "書劍一生長骯髒，虀鹽到處只酸辛。", "招提夜永眠無室，絳帳春寒坐乏茵。", "莫怪闇梨不具眼，先生未見宰官身。"]'),
('afc35447-c577-46df-859e-a150f64f93d5','次韻潘先生莫春感懷見寄','王十朋','宋','宋诗','song-poetry','','[]','緬想長安覺夜長，先生投老困文場。',64,'全唐诗/poet.song.118000.json','["緬想長安覺夜長，先生投老困文場。", "幾吟白雪眠蕭寺，誰薦凌雲達未央。", "鼠目麞頭多富貴，兔葵燕麥自悲傷。", "感春情思如雲亂，排悶題詩寄草堂。"]'),
('6fc2974f-cbce-4f9f-b341-2543bda30717','至樂齋讀書','王十朋','宋','宋诗','song-poetry','','[]','權門跡不到，顔巷自安貧。',48,'全唐诗/poet.song.118000.json','["權門跡不到，顔巷自安貧。", "獨與聖賢對，更於燈火親。", "夜觀常及子，晝諷直從寅。", "莫恨成名晚，詩書不負人。"]'),
('0ced6661-800e-451d-84d3-d4b115fa6e60','用前韻酬昌齡弟','王十朋','宋','宋诗','song-poetry','','[]','原憲曾非病，陳平豈久貧。',48,'全唐诗/poet.song.118000.json','["原憲曾非病，陳平豈久貧。", "路遥騏驥困，原近鶺鴒親。", "窗几坐窮夕，更籌聽報寅。", "田園勞爾輩，媿是素餐人。"]'),
('2f8c072e-3610-49cb-8426-57b54c1a5488','懷孫子尚','王十朋','宋','宋诗','song-poetry','','[]','孫郎何事久無書，又見青春柳拂渠。',64,'全唐诗/poet.song.118000.json','["孫郎何事久無書，又見青春柳拂渠。", "千里阻山仍阻水，三年無鴈亦無魚。", "弟兄官况寧多好，囊橐年來莫久虛。", "海角天涯兩形影，別時長記涕漣如。"]'),
('7f8315e0-6f5b-41b1-a1f5-e459bd021646','懷姜渭叟兼簡謝守中用前韻','王十朋','宋','宋诗','song-poetry','','[]','姜郎何事久無書，令君青春最憶渠。',64,'全唐诗/poet.song.118000.json','["姜郎何事久無書，令君青春最憶渠。", "別後又孤詩與酒，怪來都斷雁并魚。", "守株身世俱非巧，畫餠聲名總是虛。", "隔壁惠連無恙否，池塘春草句何如。"]'),
('573cf5c7-fc8b-4243-9d2d-a6c49956faa4','懷劉方叔兼簡全之用前韻','王十朋','宋','宋诗','song-poetry','','[]','劉郎何事久無書，夢裏頻頻却見渠。',64,'全唐诗/poet.song.118000.json','["劉郎何事久無書，夢裏頻頻却見渠。", "往事真同塞翁馬，此身何異蠹書魚。", "嚴親白髮皆如許，吾輩青春度莫虛。", "意氣飄飄羨溫叟，凌雲詞賦壓相如。"]'),
('9bebb640-e9d9-406a-bcd3-665d8f5c91bd','述懷','王十朋','宋','宋诗','song-poetry','','[]','吾年三十百無堪，世事如麻總未諳。',64,'全唐诗/poet.song.118000.json','["吾年三十百無堪，世事如麻總未諳。", "楊子家貧那嗜酒，盧仝丁白更添男。", "回頭場屋心幾折，混迹泥塗分固甘。", "頼有東臯遺業在，剩栽桑柘教妻蠶。"]'),
('197bc397-1a70-4424-8fe9-908154feaccd','夜雨述懷','王十朋','宋','宋诗','song-poetry','','[]','夜深風雨撼庭芭，喚起新愁似亂麻。',64,'全唐诗/poet.song.118000.json','["夜深風雨撼庭芭，喚起新愁似亂麻。", "夢覺尚疑身是蝶，病蘇方悟影非蛇。", "澆腸竹葉頻生翬，照眼銀缸自結花。", "我在故鄉非逆旅，不煩杜宇喚歸家。"]'),
('fb4592b3-3aea-400a-9bc6-1bca27edc15f','送元範赴省','王十朋','宋','宋诗','song-poetry','','[]','清峭霜天振羽翰，共觀一鶚氣軒軒。',64,'全唐诗/poet.song.118000.json','["清峭霜天振羽翰，共觀一鶚氣軒軒。", "願將拄腹書千卷，盡作憂時策萬言。", "請繫單于同太傅，不阿人主異公孫。", "龍頭素是君家物，又見傳呼賈狀元。"]'),
('002036fa-2ea0-443b-8225-2fc08cab78e0','送劉政孫','王十朋','宋','宋诗','song-poetry','','[]','蚤歲聲蜚舍法中，漕臺前日始收功。',64,'全唐诗/poet.song.118000.json','["蚤歲聲蜚舍法中，漕臺前日始收功。", "辛勤半世虀鹽學，慷慨平生畎畝忠。", "作佛肯居靈運後，登仙更與阮郎同。", "瓊林宴罷游天祿，太一然藜定照公。"]'),
('a50b706e-63b8-4eb2-9b5d-800e6633d7dc','送劉全之','王十朋','宋','宋诗','song-poetry','','[]','綵衣堂上別慈顔，匹馬揚鞭指帝關。',64,'全唐诗/poet.song.118000.json','["綵衣堂上別慈顔，匹馬揚鞭指帝關。", "千里清風生腋下，十分黄氣滿眉間。", "手探春信尋梅去，袖带天香折桂還。", "定向蓬萊燕仙侶，爲言子晉在江山。"]'),
('d54f9d18-412e-48d8-be06-707782cd4a10','前詩送三鄉文行雖各獻芹然非所以勉子大夫茂明大對之意更爲古詩一章','王十朋','宋','宋诗','song-poetry','','[]','逆胡殘喘仍跳梁，中興事業猶渺茫。',259,'全唐诗/poet.song.118000.json','["逆胡殘喘仍跳梁，中興事業猶渺茫。", "當今取士異平日，非爲故事開科場。", "廟堂方諱口打賊，翻抵正論爲猖狂。", "紛紛兒輩苟富貴，妄引申伯深阿王。", "公孫老儒亦曲學，不敢正色言堯湯。", "徒令天下慷慨士，肝膽一劍生光芒。", "前年胡公以言逐，言今已驗官未復。", "近日徑山緣賦詩，裹頭衣白投荒服。", "忠良自此多結舌，道路相看徒以目。", "誰能言事如靖康，陳東已死歐陽戮。", "國家養士恩至渥，千戈不廢菁莪育。", "諸公報國當如何，莫把剛腸慕粱肉。", "丈夫一第何足道，幸勿以此存懷抱。", "賈生當獻太息流涕痛哭書，更施三表五餌請爲屬國繫單于。", "大劉小劉展盡畎畝惓惓忠，弘恭石顯輩視之當與奴僕同。"]'),
('7807c313-0c36-4c11-9632-0681335a3574','詠柳','王十朋','宋','宋诗','song-poetry','','[]','東君於此最鍾情，粧點村村入畫屏。',64,'全唐诗/poet.song.118000.json','["東君於此最鍾情，粧點村村入畫屏。", "向我無言眉自展，與人非故眼猶青。", "縈牽別恨絲千尺，斷送春光絮一亭。", "葉底黄鸝音更好，隔溪烟雨醉時聽。"]'),
('c3c15d45-eed9-4416-9190-f56ddb9f008d','次韻潘先生寒食有感  其一','王十朋','宋','宋诗','song-poetry','','[]','花媚韶光柳弄煙，簫聲處處賣餳天。',32,'全唐诗/poet.song.118000.json','["花媚韶光柳弄煙，簫聲處處賣餳天。", "誰知子厚懷桑梓，北望長號又一年。"]'),
('99bd5b67-4b4a-4aec-9171-4dafeb6e7a97','次韻潘先生寒食有感  其二','王十朋','宋','宋诗','song-poetry','','[]','無頼楊花趁暖風，旅中節物與愁逢。',32,'全唐诗/poet.song.118000.json','["無頼楊花趁暖風，旅中節物與愁逢。", "一聲杜宇啼春怨，知在花梢第幾重。"]'),
('2b47c5c5-5ed5-46b8-a463-8e85a4187320','次韻潘先生寒食有感  其三','王十朋','宋','宋诗','song-poetry','','[]','人間寒食幾經年，甲子誰能記後先。',32,'全唐诗/poet.song.118000.json','["人間寒食幾經年，甲子誰能記後先。", "且盡一杯藍尾酒，莫將身事惱生前。"]'),
('54965d38-3b6f-4e94-9e80-afcda6938a0c','悼僧德芬  其一','王十朋','宋','宋诗','song-poetry','','[]','身著方袍十一年，緇林頭角稍軒軒。',64,'全唐诗/poet.song.118000.json','["身著方袍十一年，緇林頭角稍軒軒。", "參禪早悟前三旨，學道思歸不二門。", "花落絮飛浮世盡，風清月白片心存。", "異時我作高僧傳，爲記嚴公有此孫。"]'),
('3e4e991f-dfd1-4030-804f-125be2a7f909','悼僧德芬  其二','王十朋','宋','宋诗','song-poetry','','[]','妙齡蕭灑脫塵籠，高揖禪林話苦空。',64,'全唐诗/poet.song.118000.json','["妙齡蕭灑脫塵籠，高揖禪林話苦空。", "萬水千山新道眼，一瓶二缽舊家風。", "圓鏡肇論能知趣，筆法詩章稍自工。", "圓澤精魂定何所，想隨流水到天童。"]'),
('cd767cf3-821b-4a2f-b028-d5a288524a64','悼禪法師','王十朋','宋','宋诗','song-poetry','','[]','閣中高隠歲華深，龜鶴精神老不侵。',64,'全唐诗/poet.song.118000.json','["閣中高隠歲華深，龜鶴精神老不侵。", "寶劍妙傳驅鬼術，靈丹長有濟人心。", "彌明石鼎方聯句，弘景袈裟遽掩衾。", "借問青牛何處去，九天雲路杳難尋。"]'),
('c5d0b5fc-dbd8-4038-bdfc-9ffb61ca966e','毛虞卿見過','王十朋','宋','宋诗','song-poetry','','[]','故人訪吾廬，况是清和節。',144,'全唐诗/poet.song.118000.json','["故人訪吾廬，况是清和節。", "高槐綠成陰，芳草碧未歇。", "携手山間行，清興浩然發。", "呼童具鷄黍，濁酒醅初潑。", "貧居媿荒凉，野蔌草羅列。", "盤實飣梅豆，蔬餐薦薇蕨。", "主禮雖甚微，客色未嘗觖。", "醉翁山水意，不爲壺觴設。", "蟹眼煎新汲，雀舌烹春擷。", "澆君文字腸，掉我清談舌。", "人生會面難，歲月易飄忽。", "君姑爲我留，怱怱莫言別。"]'),
('c4b69469-fb54-4fcd-81f4-6945ccdc3627','讀孫子尚舊所寄書','王十朋','宋','宋诗','song-poetry','','[]','故人之書不易得，片紙隻字皆可惜。',240,'全唐诗/poet.song.118000.json','["故人之書不易得，片紙隻字皆可惜。", "收拾永爲巾笥藏，縱得千金不願易。", "開緘展轉時一讀，讀未能終淚橫臆。", "之人門地盛衣冠，萬里家居帝王宅。", "干戈繚繞飄吾鄉，傾蓋論交似疇昔。", "我年初冠君猶少，握手游從忝聯璧。", "金溪風月供醉吟，君唱我酬常即席。", "君詩句句清且新，高壓曹劉倒元白。", "我才短淺何足論，彊伴寧容小生敵。", "追風駿足橫海鱗，暫困鹽車與汙澤。", "掉頭一去不可尋，南北茫茫烟水隔。", "往年雁字時復傳，近日詩筒杳難覓。", "眼中不見故人面，紙上空懷故人迹。", "人生會合能幾回，一別八年同瞬息。", "我去無由君不來，尊酒相逢更何夕。"]'),
('09ef33a1-50db-47ec-a803-55bd3f642fb7','宋彥才挽詞','王十朋','宋','宋诗','song-poetry','','[]','德著吾鄉月旦評，丘園蕭散傲虛名。',64,'全唐诗/poet.song.118000.json','["德著吾鄉月旦評，丘園蕭散傲虛名。", "袍雖不奪詩尤好，秋不曾悲賦自清。", "早掛儒冠知有命，晚憑貝葉悟無生。", "人間月落天池後，定向維摩頂上行。"]'),
('8246f53a-b344-4a00-acee-6867e89245f5','宋孺人挽詞','王十朋','宋','宋诗','song-poetry','','[]','晚歲歸來奉伯鸞，力將勤儉濟艱難。',64,'全唐诗/poet.song.118000.json','["晚歲歸來奉伯鸞，力將勤儉濟艱難。", "鹿車共挽甘從鮑，熊膽親調欲慕韓。", "鏡裏玉容猶未老，夢中銀漏忽驚殘。", "通家賤子非房杜，長記登門酒盡歡。"]'),
('d4cebef2-13d2-4905-a9c2-3ecd6ee0024b','先君子去世五十日孤某入四友室睹平生遺迹哀號痛哭絕而復蘇既而書四十字以寄罔極之思','王十朋','宋','宋诗','song-poetry','','[]','先子神何在，人亡迹尚存。',48,'全唐诗/poet.song.118000.json','["先子神何在，人亡迹尚存。", "業餘經史案，趣寄聖賢尊。", "榻冷寧欹枕，堂虛已蓋棺。", "晨昏徒泣血，無路報深恩。"]'),
('31387fd8-fd16-4c36-802a-5da59a7ac309','李府君挽詞','王十朋','宋','宋诗','song-poetry','','[]','利塗名路兩崎嶔，甘向田園事陸沉。',64,'全唐诗/poet.song.118000.json','["利塗名路兩崎嶔，甘向田園事陸沉。", "一頃膏腴生計足，四時香火佛緣深。", "築門東海于公意，教子燕山竇老心。", "銜涕爲公銘隠德，不緣諛墓欲黄金。"]'),
('e9f8d374-e90e-4e3f-b2bf-a4e06126bdfd','陳景公挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','冠玉堂堂骨相奇，起家消息露蓍龜。',64,'全唐诗/poet.song.118000.json','["冠玉堂堂骨相奇，起家消息露蓍龜。", "齒牙不妄千金諾，度量難窺萬頃陂。", "車轍過門多長者，箕裘傳業有佳兒。", "西園新卜松楸地，記得公顔向此怡。"]'),
('9153a2e1-88ca-4b21-b6ee-e072a68b24f0','陳景公挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','先子於公分頗深，晚年出處恨商參。',64,'全唐诗/poet.song.118000.json','["先子於公分頗深，晚年出處恨商參。", "雖脩北海通家好，未遂香山會老心。", "盡道吉人俱未艾，誰知凶訃遽相尋。", "三年落盡思親淚，今日登門又滿襟。"]'),
('ed9345e5-088d-4da9-81e8-0e6f5f7c491d','次韻萬喬年李唐英二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','七賢林下共忘機，更有新詩爲發揮。',32,'全唐诗/poet.song.118000.json','["七賢林下共忘機，更有新詩爲發揮。", "竹葉一尊添逸興，薰風吹散臉紅微。"]'),
('4a5be96b-846e-4185-85b3-86409251c0bf','次韻萬喬年李唐英二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','黌舍炎炎畏日長，竹亭取次納新凉。',32,'全唐诗/poet.song.118000.json','["黌舍炎炎畏日長，竹亭取次納新凉。", "文章風月須兼美，莫使時人恨海棠。"]'),
('25002830-9a25-4b08-9298-7051b67b0b51','送章生端武','王十朋','宋','宋诗','song-poetry','','[]','麟經絕筆今幾年，學者異說何紛然。',128,'全唐诗/poet.song.118000.json','["麟經絕筆今幾年，學者異說何紛然。", "操矛入室務相伐，誰能浚井得美泉。", "梅溪野人獨好古，遺經獨抱期心傳。", "從予講論有趙陸，得趣往往忘蹄筌。", "章生妙齡固可畏，聖經賢傳思窮研。", "贏糧遠來若有意，席未及暖俄言還。", "豈厭先生紙上語，奧境不見徒留連。", "春秋明日遂東矣，情鍾我輩徒拳拳。"]'),
('796dec25-11e2-44fc-82fd-81c1d7e0943c','送羅生少陸','王十朋','宋','宋诗','song-poetry','','[]','羅生黄山來，從我梅溪游。',144,'全唐诗/poet.song.118000.json','["羅生黄山來，從我梅溪游。", "齒髮最年少，學問能自修。", "短檠照深夜，細字書蠅頭。", "大業心欲潛，遺編力旁搜。", "新文有佳趣，日進殊未休。", "吾愧河汾翁，子學常與收。", "行將拭老眼，萬里看驊騮。", "一葉下庭臯，大火當西流。", "遥望河陽雲，俄登李膺舟。", "交朋重惜別，挽袖終不留。", "吾腸百鍊剛，亦作繭緒抽。", "籍也不吾叛，尋盟定高秋。"]'),
('f18e9783-93e3-4e0c-a2c1-072df60211bf','送茹生履','王十朋','宋','宋诗','song-poetry','','[]','燈火勤勞覺瘦生，望雲心斷涕從橫。',32,'全唐诗/poet.song.118000.json','["燈火勤勞覺瘦生，望雲心斷涕從橫。", "賢關春信無多日，手折梅花贈子行。"]'),
('fed1c376-400e-4cdb-87ce-551ff810a5c2','乙丑冬罷會呈諸友','王十朋','宋','宋诗','song-poetry','','[]','繆意開家塾，微才愧斗筲。',48,'全唐诗/poet.song.118000.json','["繆意開家塾，微才愧斗筲。", "雖逃有若叱，寧兌孝先嘲。", "尚頼知心友，能全耐久交。", "殷勤惜別意，終日在梅梢。"]'),
('4a4032e7-ef33-463d-a4f4-afb9d7c44c27','江上遇風二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','薄暮登舟海颶生，短蓬欹側浪崢嶸。',32,'全唐诗/poet.song.118000.json','["薄暮登舟海颶生，短蓬欹側浪崢嶸。", "江神正好憐行客，莫待他時却世情。"]'),
('141dfc61-c5f5-4d22-ac60-f7fa949abd2d','江上遇風二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','弭棹乾門浪未平，同舟太半已山行。',32,'全唐诗/poet.song.118000.json','["弭棹乾門浪未平，同舟太半已山行。", "自慙不是婁師德，免葬江魚頼友生。"]'),
('df34113b-1aa6-4ee4-873a-cd12f4c99c4f','宿黄巖妙智院','王十朋','宋','宋诗','song-poetry','','[]','問訊開山始，于今二百年。',48,'全唐诗/poet.song.118000.json','["問訊開山始，于今二百年。", "徑幽微見竹，社廢尚遺蓮。", "觀頌思元老，游庵憶舊禪。", "怱怱一宿客，未盡滌塵緣。"]'),
('dd26f361-9b3e-484f-9db1-c6f896a70415','過黄巖','王十朋','宋','宋诗','song-poetry','','[]','三日離家客，悠然覺路長。',48,'全唐诗/poet.song.118000.json','["三日離家客，悠然覺路長。", "梅花十里眼，竹葉一杯腸。", "詩思貪佳境，眉頭憶故鄉。", "江山看未足，回首隔滄浪。"]'),
('512ae159-67b5-4712-8a5a-aa7528eb4e2f','宿慶善寺','王十朋','宋','宋诗','song-poetry','','[]','剛被篙工誤，遲留一日裝。',48,'全唐诗/poet.song.118000.json','["剛被篙工誤，遲留一日裝。", "川塗隔浩渺，燈火亂昏黄。", "呼僕回行李，尋僧宿上方。", "山前十里雪，夜入夢魂香。"]'),
('e7f13b13-22c8-4d22-ba1d-f530fa954c5e','過天台','王十朋','宋','宋诗','song-poetry','','[]','目逆神仙路，丹成未暇躋。',48,'全唐诗/poet.song.118000.json','["目逆神仙路，丹成未暇躋。", "雪深封佛壠，雲暗鎖桃溪。", "流水無還有，亂山高復低。", "欲尋劉阮洞，歸路恐成迷。"]'),
('1e5b0683-70a2-4891-883e-7f0f9f353e67','過新昌','王十朋','宋','宋诗','song-poetry','','[]','杖屨登關嶺，山行無住時。',48,'全唐诗/poet.song.118000.json','["杖屨登關嶺，山行無住時。", "客情渾在眼，鄉思苦關眉。", "石現金仙像，谿蟠阮肇祠。", "越山都幾點，收拾上新詩。"]'),
('d1fadf04-fc48-47f1-8db7-2d7527f384dc','觀石佛','王十朋','宋','宋诗','song-poetry','','[]','土木塗金巧逼真，總隨浮幻化埃塵。',32,'全唐诗/poet.song.118000.json','["土木塗金巧逼真，總隨浮幻化埃塵。", "何人著意鎸山骨，長現金剛不壞身。"]'),
('42223647-8208-4c4e-9e8c-5b7d8b6a855e','戴溪亭','王十朋','宋','宋诗','song-poetry','','[]','高士逃名隠此溪，憑欄遐想獨徘徊。',32,'全唐诗/poet.song.118000.json','["高士逃名隠此溪，憑欄遐想獨徘徊。", "不知吾祖乘舟後，得得誰從雪裏來。"]'),
('cb7db347-e73b-454b-9e4f-1581e95b8ba4','曹娥廟','王十朋','宋','宋诗','song-poetry','','[]','慟哭無尋處，投江竟得屍。',48,'全唐诗/poet.song.118000.json','["慟哭無尋處，投江竟得屍。", "風高烈女傳，名重外孫碑。", "荒草沒孤冢，洪濤舂古祠。", "懷沙爲誰死，翻媿是男兒。"]'),
('5f62b111-33a2-4b2a-b4f8-81b1e6d49e10','宿驛奧','王十朋','宋','宋诗','song-poetry','','[]','未是他鄉客，思家已斷魂。',24,'全唐诗/poet.song.118000.json','["未是他鄉客，思家已斷魂。", "明朝春色好，宿處近花村。"]'),
('bb6d2f3d-aa42-4d4f-ac25-efbfaf06c3a8','題靈峰三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','家在梅溪水竹間，穿雲蠟屐可曾閑。',32,'全唐诗/poet.song.118000.json','["家在梅溪水竹間，穿雲蠟屐可曾閑。", "雁山新入春游眼，却笑平生未見山。"]'),
('1d166b0d-0b84-407b-ae3f-ee1b29dde3d2','題靈峰三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','洞中大士半千身，住世端能了世因。',32,'全唐诗/poet.song.118000.json','["洞中大士半千身，住世端能了世因。", "應笑玉簫峰下客，馬蹄長踐利名塵。"]'),
('7da41fb6-11be-4206-856b-446526a5ca4d','題靈峰三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','三宿靈峰不爲禪，茶甌隨分結僧緣。',32,'全唐诗/poet.song.118000.json','["三宿靈峰不爲禪，茶甌隨分結僧緣。", "明朝杖屨丹丘去，带得烟霞過海船。"]'),
('b581d4de-9e97-4a07-92b4-78b804ef7f0b','出雁山','王十朋','宋','宋诗','song-poetry','','[]','三宿山中始出山，出山心尚在山間。',32,'全唐诗/poet.song.118000.json','["三宿山中始出山，出山心尚在山間。", "浮名奪我林泉趣，不及高僧一味閑。"]'),
('0449b94b-1319-4253-a02a-ea9ba54402ce','關嶺遇雪','王十朋','宋','宋诗','song-poetry','','[]','路近剡溪春雪深，此行有媿子猷尋。',32,'全唐诗/poet.song.118000.json','["路近剡溪春雪深，此行有媿子猷尋。", "驅馳千里爭蝸角，孤負扁舟自在心。"]'),
('a2e510b9-c85f-471c-957e-50ea1b311726','過鑑湖  其一','王十朋','宋','宋诗','song-poetry','','[]','誰把青銅鑄鑑湖，湖光冷浸越王都。',32,'全唐诗/poet.song.118000.json','["誰把青銅鑄鑑湖，湖光冷浸越王都。", "東風二月西游客，買得扁舟入畫圖。"]'),
('74756eb4-364d-4b8e-bdc6-3e3324372368','過鑑湖  其二','王十朋','宋','宋诗','song-poetry','','[]','春水如天浪未生，扁舟真在鑑中行。',32,'全唐诗/poet.song.118000.json','["春水如天浪未生，扁舟真在鑑中行。", "漁人不問君王覓，占得湖光亦自榮。"]'),
('aafeb3a9-bb3c-4206-9ded-d9f19e133c2e','月夜獨酌','王十朋','宋','宋诗','song-poetry','','[]','月色撩人不忍眠，杖頭獨掛百青錢。',32,'全唐诗/poet.song.118000.json','["月色撩人不忍眠，杖頭獨掛百青錢。", "一杯竹葉那能醉，澆起鄉心更黯然。"]'),
('a11a171e-e04b-43ca-8511-257e9d8ddeb6','太學寄夢齡昌齡弟','王十朋','宋','宋诗','song-poetry','','[]','東望家山幾斷魂，白雲飛盡路漫漫。',64,'全唐诗/poet.song.118000.json','["東望家山幾斷魂，白雲飛盡路漫漫。", "須知太學虀鹽味，不似親闈菽水歡。", "事業未應孤鐵硯，弟兄猶喜盡儒冠。", "行飛直待秋風便，好作排空雁字看。"]'),
('39da9404-2e98-49c5-8243-483600e778ed','丁卯秋赴鹿鳴宴次太守趙殿撰韻','王十朋','宋','宋诗','song-poetry','','[]','食苹開燕副招求，夢草詩成寵士流。',64,'全唐诗/poet.song.118000.json','["食苹開燕副招求，夢草詩成寵士流。", "要得異才聯虎榜，亦容下客盜狐裘。", "早脩慧業欽靈運，妄贊元經媿子游。", "刺史笑談風滿席，定應吹拂到瀛洲。"]'),
('b81249f0-dc50-4556-b282-0e4f47b9a44e','赴省治裝有感','王十朋','宋','宋诗','song-poetry','','[]','記得離家柳未黄，歸來三徑菊花香。',32,'全唐诗/poet.song.118000.json','["記得離家柳未黄，歸來三徑菊花香。", "一年强半身爲客，席未遑安又趣裝。"]'),
('46ee8dd9-acb5-4b4e-a7f8-35495c89bcdd','再過雁山三絕 大龍湫','王十朋','宋','宋诗','song-poetry','','[]','龍大那容在此湫，銀河得得爲飛流。',32,'全唐诗/poet.song.118000.json','["龍大那容在此湫，銀河得得爲飛流。", "好乘風雨昂頭角，直到天池最上頭。"]'),
('93d966f4-8296-4ab9-82f5-5b39e0d74b10','再過雁山三絕 天柱峯','王十朋','宋','宋诗','song-poetry','','[]','女蝸石爛若爲脩，四海咸懷杞國憂。',32,'全唐诗/poet.song.118000.json','["女蝸石爛若爲脩，四海咸懷杞國憂。", "誰識山中真柱石，擎天功業勝伊周。"]'),
('d991289f-3c7f-474b-94c1-11ff6a136065','再過雁山三絕 天聰洞','王十朋','宋','宋诗','song-poetry','','[]','重華疑到此山中，鑿石疏巖達四聰。',32,'全唐诗/poet.song.118000.json','["重華疑到此山中，鑿石疏巖達四聰。", "端爲草茅憂世士，不教無路獻孤忠。"]'),
('23f214ed-fee9-46ff-aaf8-78b312f4b55c','思歸','王十朋','宋','宋诗','song-poetry','','[]','窗外西風竹數竿，秋聲終夜趣歸鞍。',32,'全唐诗/poet.song.118000.json','["窗外西風竹數竿，秋聲終夜趣歸鞍。", "吾廬此去八百里，歸到家時天未寒。"]'),
('964c468f-9e44-45cc-b1d0-81d17b2ffe08','別太學同舍','王十朋','宋','宋诗','song-poetry','','[]','二年客賢關，傾蓋皆故人。',96,'全唐诗/poet.song.118000.json','["二年客賢關，傾蓋皆故人。", "况我同舍郎，何異手足親。", "虀鹽共牢落，燈火同悲辛。", "坐覺歲月忘，所頼朋友仁。", "西風起天末，淅瀝吹江蘋。", "思歸適所願，惜別還霑巾。", "祖席歌驪駒，別腸轉車輪。", "離索恐孤陋，重來約新春。"]'),
('06ed9b2a-1803-45f6-8815-70bddee48d54','戊辰閏八月歸臨安觀舊題脩竹黄楊丁香慨然有感復書三絕于後  其一','王十朋','宋','宋诗','song-poetry','','[]','吾家風物富檀欒，最愛青青耐歲寒。',32,'全唐诗/poet.song.118000.json','["吾家風物富檀欒，最愛青青耐歲寒。", "千里歸來面蒼玉，不煩時復報平安。"]'),
('5387daf9-71b3-41db-a9e4-769ae653d4c9','戊辰閏八月歸臨安觀舊題脩竹黄楊丁香慨然有感復書三絕于後  其二','王十朋','宋','宋诗','song-poetry','','[]','同日種松今合抱，後來栽柳已參天。',32,'全唐诗/poet.song.118000.json','["同日種松今合抱，後來栽柳已參天。", "笑看軒外黄楊樹，我亦如君厄閏年。"]'),
('91a86a82-46d8-44ee-bba7-54ec0f0ed093','戊辰閏八月歸臨安觀舊題脩竹黄楊丁香慨然有感復書三絕于後  其三','王十朋','宋','宋诗','song-poetry','','[]','蕙蘭憔悴菊萎秋，葉底藏春已數頭。',32,'全唐诗/poet.song.118000.json','["蕙蘭憔悴菊萎秋，葉底藏春已數頭。", "詩客不知花韻別，却言空結雨中愁。"]'),
('baa7111d-5472-4997-b657-98d046a9354a','次韻寶印叔題止庵三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','鑿石依山作小庵，花香入座月侵簷。',32,'全唐诗/poet.song.118000.json','["鑿石依山作小庵，花香入座月侵簷。", "雖然眼界無多地，解使人天競聳瞻。"]'),
('24b0cea7-e33f-45a1-9f4d-4d6db5db9ea2','次韻寶印叔題止庵三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','容膝茅庵不妄開，欲令人悟止由來。',32,'全唐诗/poet.song.118000.json','["容膝茅庵不妄開，欲令人悟止由來。", "箇中妙意知誰解，多作休休莫莫猜。"]'),
('220d54ae-c206-4e53-aca8-94bab8727a74','次韻寶印叔題止庵三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','晚學無由識道真，前賢未許繼芳塵。',32,'全唐诗/poet.song.118000.json','["晚學無由識道真，前賢未許繼芳塵。", "道從何進從何止，敢叩無爲絕學人。"]'),
('34c87959-4e8d-40d5-8465-6e7c7db33268','翁府君挽詞','王十朋','宋','宋诗','song-poetry','','[]','場屋收功不在身，蘭馨玉潤總奇人。',64,'全唐诗/poet.song.118000.json','["場屋收功不在身，蘭馨玉潤總奇人。", "過庭詩禮家風變，坦腹門闌喜氣新。", "華屋産芝雖美瑞，白頭生齒誤青春。", "籃輿方起南游興，無奈今年歲在辰。"]'),
('f0af7eb7-b454-49e8-a9d8-eb303b12e27c','十月十九日雷二十一日雪','王十朋','宋','宋诗','song-poetry','','[]','前日始驚雷失令，今朝忽見雪漫天。',32,'全唐诗/poet.song.118000.json','["前日始驚雷失令，今朝忽見雪漫天。", "寒窗夜擁黄紬坐，閑讀春秋隠九年。"]'),
('d4b27ec3-078e-4f7d-8e46-37a49e7c1c50','次韻表叔余叔成示兒','王十朋','宋','宋诗','song-poetry','','[]','父子乃天性，鍾情誰不然。',168,'全唐诗/poet.song.118000.json','["父子乃天性，鍾情誰不然。", "教之以義方，先賢有名言。", "日嚴在所尚，私念宜舍旃。", "君子不自教，遣隨師友肩。", "青紫乃餘事，要當知聖賢。", "居家務孝弟，立行防悔愆。", "窮當慕顔回，達勿爲公孫。", "庶幾幼所學，終身可行焉。", "不見下邳丈，秀發從妙年。", "束書入賢關，日與英雋聯。", "忽作何蕃歸，甘旨奉晨昏。", "丘園事高尚，腹笥常便便。", "過庭有奇兒，詩禮得家傳。", "勉哉尊所聞，慎勿學鄉原。"]'),
('4a5fcaa4-e518-4865-8073-d5bb51618884','表叔陳景韶挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','問舍求田事，元龍意本輕。',48,'全唐诗/poet.song.118000.json','["問舍求田事，元龍意本輕。", "功名孤壯志，詩酒送平生。", "李密傷爲弟，劉牢喜有甥。", "詩書已三世，二子盍升卿。"]'),
('4d408c6a-e10c-4124-8691-a6a602d22460','表叔陳景韶挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','先友嗟無幾，公今亦古人。',48,'全唐诗/poet.song.118000.json','["先友嗟無幾，公今亦古人。", "平門散車轍，蕃榻鎖埃塵。", "甚媿常公厚，深知管子貧。", "平生談笑地，感激淚沾巾。"]'),
('0432e50f-7d3c-48c5-bef9-3c6b01c24c49','詠述師葡萄','王十朋','宋','宋诗','song-poetry','','[]','柱杖拈餘戯插泥，草龍珠帳掛簷西。',32,'全唐诗/poet.song.118000.json','["柱杖拈餘戯插泥，草龍珠帳掛簷西。", "荔枝體物差勝棗，畢竟俱非善品題。"]'),
('89dc4e20-49b6-49b4-85df-5b2a26b2516e','十一月七日東山省墳因思先子昔年題壁有山光水色兩依依之句，舊屋已壞墨迹不留山水依然感歎不已因成一絕','王十朋','宋','宋诗','song-poetry','','[]','松楸一見一傷心，亭院凄凉慘樹陰。',32,'全唐诗/poet.song.118000.json','["松楸一見一傷心，亭院凄凉慘樹陰。", "記得先君舊題壁，水光山色恨難禁。"]'),
('5f0f1ba7-9802-43fa-8dd5-c3b8fdcac2f1','寄萬大年','王十朋','宋','宋诗','song-poetry','','[]','九萬程遥共退飛，江南竹葉後先歸。',64,'全唐诗/poet.song.118000.json','["九萬程遥共退飛，江南竹葉後先歸。", "儒冠到底輸紈袴，關吏還應笑布衣。", "雖欠姓名聯桂籍，不妨歡笑奉親闈。", "殷勤尊酒論文約，却恨還鄉與願違。"]'),
('2dbd7d80-b6a4-4eb4-86c5-a5d447b9d7fb','萬季梁和詩留別再用前韻','王十朋','宋','宋诗','song-poetry','','[]','三年燕雁不同飛，一笑相逢慰遠歸。',64,'全唐诗/poet.song.118000.json','["三年燕雁不同飛，一笑相逢慰遠歸。", "搜我肺腸茶著令，飲君文字酒淋衣。", "詩方唱和如仙館，人遽飄零似省闈。", "畢竟此心元不別，祇應形影暫相違。"]'),
('cb7028ee-a33d-4b28-a615-d8165d5140b4','將過萬橋用前韵寄大年先之','王十朋','宋','宋诗','song-poetry','','[]','三年在阜不鳴飛，側翅俱從舊路歸。',64,'全唐诗/poet.song.118000.json','["三年在阜不鳴飛，側翅俱從舊路歸。", "師德量寬真耐事，沈郎詩瘦不勝衣。", "都緣有職供甘旨，可是無心戀闕闈。", "酒發葡萄螯斫雪，定知此願不吾違。"]'),
('2ab0926a-7806-4906-aae5-eac84f02cde6','種蘭有感','王十朋','宋','宋诗','song-poetry','','[]','芝友産岩壑，無人花自芳。',48,'全唐诗/poet.song.118000.json','["芝友産岩壑，無人花自芳。", "苗分鄭七穆，秀發謝諸郎。", "世競憐春色，人誰賞國香。", "自全幽靜操，不采亦何傷。"]'),
('7e42e2f6-be5b-4e74-a29d-d1f99ee265e6','再用前韵','王十朋','宋','宋诗','song-poetry','','[]','誰櫂深林秀，遥分奕葉芳。',48,'全唐诗/poet.song.118000.json','["誰櫂深林秀，遥分奕葉芳。", "秉殊溱上客，握擬殿中郎。", "眼凈見幽韻，心清聞遠香。", "當門不及種，踐履恐成傷。"]'),
('277dc7da-a68b-4ecd-97ff-e0df27127a8a','三月晦日與同舍送春於梅溪因誦賈閬仙詩云三月更當三十日，風光別我苦吟身共君今夜不須睡未到曉鍾猶是春時有二十八人遂以齒序分韻','王十朋','宋','宋诗','song-poetry','','[]','記得來時手自探，預知今日思難堪。',64,'全唐诗/poet.song.118000.json','["記得來時手自探，預知今日思難堪。", "樹頭綠暗鶑如訴，地上紅多蝶尚貪。", "此夜鍾聲那忍聽，明朝酒盞可能酣。", "却因送別還驚我，老境如蠶已食三。"]'),
('3b9b30d6-b241-469d-b8ca-6bafad348166','爲麥祈實','王十朋','宋','宋诗','song-poetry','','[]','陽律臨姑洗，宸心念歲饑。',72,'全唐诗/poet.song.118000.json','["陽律臨姑洗，宸心念歲饑。", "時羞方廟獻，麥實爲民祈。", "日煖輕花吐，風和翠浪微。", "敢言因鮪薦，願勿作蛾飛。", "會續來牟頌，寧聞告糴譏。", "崆峒今歲熟，登薦定無違。"]'),
('3a9f0831-671b-471f-85a0-102b6efffbf9','次韻萬先之讀莊子','王十朋','宋','宋诗','song-poetry','','[]','莊生蔽於天，先儒已能言。',60,'全唐诗/poet.song.118000.json','["莊生蔽於天，先儒已能言。", "六經有真味，奚用食馬肝。", "王何佐其高，遺害今猶存。", "夫君高明士，寄趣名理間。", "恐蹈賢者過，因詩與君論。"]'),
('39758193-26e5-4716-8e0b-2c3e659e3543','己巳梅溪同舍三十人其九人者游從之舊也酌別之夕獨五人在焉謝子與能猶在予館而四人者且去矣遂各以其姓賦詩送之 周仲翔','王十朋','宋','宋诗','song-poetry','','[]','梅溪闢家塾，辱與英俊游。',48,'全唐诗/poet.song.118000.json','["梅溪闢家塾，辱與英俊游。", "回首五年舊，子獨終始周。", "善交固耐久，厚德堪鎮浮。", "異時行所藴，無媿祖絳侯。"]'),
('29c33462-6760-4e41-9cb2-eb994ecf23f2','己巳梅溪同舍三十人其九人者游從之舊也酌別之夕獨五人在焉謝子與能猶在予館而四人者且去矣遂各以其姓賦詩送之 李大鼎','王十朋','宋','宋诗','song-poetry','','[]','賢哉予外兄，厚德著鄉里。',48,'全唐诗/poet.song.118000.json','["賢哉予外兄，厚德著鄉里。", "積善有天報，鍾秀在吾子。", "學問如馳馬，著鞭殊未已。", "西游不負盟，早早戒行李。"]'),
('19397e16-d9f1-4943-a96f-ad1b1f3144c1','己巳梅溪同舍三十人其九人者游從之舊也酌別之夕獨五人在焉謝子與能猶在予館而四人者且去矣遂各以其姓賦詩送之 許輝先','王十朋','宋','宋诗','song-poetry','','[]','子昔從予游，方讀紙上語。',48,'全唐诗/poet.song.118000.json','["子昔從予游，方讀紙上語。", "磨礱出圭角，翦拂就規矩。", "不爲中道廢，當振大嶽許。", "行將拭老眼，看子驚人舉。"]'),
('992be508-8ccd-473e-a7e5-1c3217b82b23','己巳梅溪同舍三十人其九人者游從之舊也酌別之夕獨五人在焉謝子與能猶在予館而四人者且去矣遂各以其姓賦詩送之 謝鵬','王十朋','宋','宋诗','song-poetry','','[]','之子方妙齡，耻爲聾俗化。',48,'全唐诗/poet.song.118000.json','["之子方妙齡，耻爲聾俗化。", "三年游梅溪，燈火讀深夜。", "男兒四方志，萬里思高跨。", "願如芝與蘭，毋媿古諸謝。"]'),
('09ac9322-487a-4865-91c1-ee1a2fde9430','別宋孝先','王十朋','宋','宋诗','song-poetry','','[]','楚臺風騷客，遥遥有奇孫。',168,'全唐诗/poet.song.118000.json','["楚臺風騷客，遥遥有奇孫。", "去歲始識面，未遑叩淵源。", "但見眉宇間，一點陽春溫。", "琴書忽來游，文字獲細論。", "經術有根蒂，詞章富波瀾。", "時時戯翰墨，動輒千萬言。", "子固予所畏，語蒙子推尊。", "予嘗語所學，文當氣爲先。", "氣治古可到，何止科第間。", "子賢且樂善，服膺每拳拳。", "臨行出新詩，殷勤記諸篇。", "好學見雅志，予言未應然。", "惜哉有離別，後會何夤緣。", "男兒各自勉，事業無窮年。"]'),
('7af64169-0c22-4e11-ac79-ec460e342b90','送黄巖三友','王十朋','宋','宋诗','song-poetry','','[]','聚散本常理，未應輕感傷。',48,'全唐诗/poet.song.118000.json','["聚散本常理，未應輕感傷。", "祇因三益友，故斷九回腸。", "子少才俱美，予窮老更忙。", "相將亦行客，後會恐參商。"]'),
('894363c0-d4f6-4edd-ac4d-61887efd3d88','又各贈一絕 余如晦','王十朋','宋','宋诗','song-poetry','','[]','遥遥華胄自由余，識量深沉豈淺夫。',32,'全唐诗/poet.song.118000.json','["遥遥華胄自由余，識量深沉豈淺夫。", "半載從游殊半面，臨行一語可能無。"]'),
('de80c65f-9def-4f15-b801-c1b1d8e05547','又各贈一絕 鄭遜志','王十朋','宋','宋诗','song-poetry','','[]','燈火相親臭味同，來何太晚去匆匆。',32,'全唐诗/poet.song.118000.json','["燈火相親臭味同，來何太晚去匆匆。", "未曾箴我膏肓失，堪嘆康成道已東。"]'),
('03119c0b-1b09-4a1a-9087-51098db0e6e4','又各贈一絕 施良臣','王十朋','宋','宋诗','song-poetry','','[]','學傳士丐舊家聲，詩法肩吾句已成。',32,'全唐诗/poet.song.118000.json','["學傳士丐舊家聲，詩法肩吾句已成。", "尊酒論文兩經歲，却因送別倍鍾情。"]'),
('fa07cf24-6fd6-45da-9bb0-a90d545bbb78','別余諧','王十朋','宋','宋诗','song-poetry','','[]','我昔自總角，識君先大夫。',48,'全唐诗/poet.song.118000.json','["我昔自總角，識君先大夫。", "閨門脩子職，鄉里號名儒。", "仁者偶不壽，善人宜有孤。", "肯堂能自勉，泉下慰榛蕪。"]'),
('9b32d43e-6c9e-4901-b612-ac87bcabf139','別余壁','王十朋','宋','宋诗','song-poetry','','[]','之子有家學，妙齡殊衆兒。',48,'全唐诗/poet.song.118000.json','["之子有家學，妙齡殊衆兒。", "參乎宜語孝，鯉也早聞詩。", "謾習雕蟲技，終絺吐鳳詞。", "五車書讀盡，定有起家期。"]'),
('9322d9db-f389-4073-91d6-e95666b0c07e','別周濬','王十朋','宋','宋诗','song-poetry','','[]','莫恨知書失太遲，妙齡聰子本非奇。',32,'全唐诗/poet.song.118000.json','["莫恨知書失太遲，妙齡聰子本非奇。", "好因椎魯加鞭策，會見火然泉達時。"]'),
('1cc751ec-c725-4643-9a34-75e5556fe84a','後七夕二夜同夢齡宿湖邊莊  其一','王十朋','宋','宋诗','song-poetry','','[]','無用乾坤一腐儒，年來蹤跡轉崎嶇。',32,'全唐诗/poet.song.118000.json','["無用乾坤一腐儒，年來蹤跡轉崎嶇。", "身名未就耕桑廢，何日投閑老此湖。"]'),
('030f10e5-8995-40d6-8237-c62596f0e2bd','後七夕二夜同夢齡宿湖邊莊  其二','王十朋','宋','宋诗','song-poetry','','[]','弟兄身事各茫然，頼有先人二頃田。',32,'全唐诗/poet.song.118000.json','["弟兄身事各茫然，頼有先人二頃田。", "他日青山映黄髮，長如今夜對牀眠。"]'),
('a100a954-6b4f-4406-abe2-a82867f91ca2','次夜予宿湖南夢齡猶在別業再和前韻寄之  其一','王十朋','宋','宋诗','song-poetry','','[]','家世衣冠誤襲儒，年幾四十尚嶔嶇。',32,'全唐诗/poet.song.118000.json','["家世衣冠誤襲儒，年幾四十尚嶔嶇。", "營營世事何時了，乞取湖邊作鑑湖。"]'),
('a0c5a167-6ad5-4f2d-904a-5926034053b8','次夜予宿湖南夢齡猶在別業再和前韻寄之  其二','王十朋','宋','宋诗','song-poetry','','[]','一襟秋色已凄然，雲水初空眼界田。',32,'全唐诗/poet.song.118000.json','["一襟秋色已凄然，雲水初空眼界田。", "那更蕭蕭風雨夜，弟兄分影隔湖眠。"]'),
('fc7502e9-08c1-4970-b4a3-831def690c88','宿靈山院','王十朋','宋','宋诗','song-poetry','','[]','靈山未是別鄉山，回首吾廬咫尺間。',32,'全唐诗/poet.song.118000.json','["靈山未是別鄉山，回首吾廬咫尺間。", "明日出山家漸遠，鄉心從此上愁顔。"]'),
('02e98e34-5df4-491a-8d8f-5f11bd69e2ec','登姚奧嶺望家山有感','王十朋','宋','宋诗','song-poetry','','[]','已作一宿客，漸爲千里人。',24,'全唐诗/poet.song.118000.json','["已作一宿客，漸爲千里人。", "吾親白雲下，回首一沾巾。"]'),
('0a654bc4-525a-411c-aee4-04cfadee7659','與萬先之登丹芳嶺路人有手持桂花者戲覓之概然相贈且言欲施此花久矣又言花名秋香一名十里香遂與先之分之記以一絕','王十朋','宋','宋诗','song-poetry','','[]','携手丹梯語話長，不知身到碧雲鄉。',32,'全唐诗/poet.song.118000.json','["携手丹梯語話長，不知身到碧雲鄉。", "行人相見如相識，贈得巖花十里香。"]'),
('02a68075-e76a-402f-b54d-5948272688a1','題石梁','王十朋','宋','宋诗','song-poetry','','[]','蕩中天柱見已久，山外石梁今始觀。',32,'全唐诗/poet.song.118000.json','["蕩中天柱見已久，山外石梁今始觀。", "尊者力能回造化，會須移向柱頭安。"]'),
('d0520346-ca7a-4b16-b580-4c3e1447a990','過雁山','王十朋','宋','宋诗','song-poetry','','[]','清秋天氣過山中，征雁行人路不同。',32,'全唐诗/poet.song.118000.json','["清秋天氣過山中，征雁行人路不同。", "從此又勞千里翼，傳書來往浙西東。"]'),
('7c98570e-41ef-4255-a1a9-b0d06ca99bb6','次先之過雁山韵','王十朋','宋','宋诗','song-poetry','','[]','雲山繚繞幾千重，撩我秋來逸興濃。',32,'全唐诗/poet.song.118000.json','["雲山繚繞幾千重，撩我秋來逸興濃。", "欲向靈巖移卓筆，與君同掃萬人鋒。"]'),
('d1f08afc-e4ec-45c7-b30f-34728c35df50','張施二生自黄巖拏舟送別于台城贈以二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','不放離人獨解舟，片帆相逐到丹丘。',32,'全唐诗/poet.song.118000.json','["不放離人獨解舟，片帆相逐到丹丘。", "客情鄉思從今日，更有思君一段愁。"]'),
('3dd46dbc-286f-4bb7-82a1-e33b5eaa7392','張施二生自黄巖拏舟送別于台城贈以二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','行役那堪八月時，腸非宋玉也應悲。',32,'全唐诗/poet.song.118000.json','["行役那堪八月時，腸非宋玉也應悲。", "煩君爲寄梅溪信，少慰吾親別後思。"]'),
('442c1ac4-2450-4e9d-b19c-c04500438fca','過仙人渡','王十朋','宋','宋诗','song-poetry','','[]','此去神仙路不迷，直從洞口到桃溪。',32,'全唐诗/poet.song.118000.json','["此去神仙路不迷，直從洞口到桃溪。", "仙人心境無名利，笑我頻年渡此溪。"]'),
('0d0a4e98-022d-407d-81a3-a9bc1b9fa285','過百度嶺','王十朋','宋','宋诗','song-poetry','','[]','乘舟剛怕兩難惡，度嶺俄驚百步高。',32,'全唐诗/poet.song.118000.json','["乘舟剛怕兩難惡，度嶺俄驚百步高。", "僮僕相看話良苦，縱教輕擔亦疲勞。"]'),
('91cd67c3-c4f2-42d2-bf65-0557bae6d4c0','關嶺旅邸觀林同季野去秋題壁','王十朋','宋','宋诗','song-poetry','','[]','去歲還家秋正杪，今年行役暑初殘。',32,'全唐诗/poet.song.118000.json','["去歲還家秋正杪，今年行役暑初殘。", "同行壁上留題處，特下籃輿子細看。"]'),
('017a8c74-979e-4a50-9f71-b09835bff962','望天台赤城山感而有作','王十朋','宋','宋诗','song-poetry','','[]','神仙境界無戰爭，奚用漆此巍巍城。',224,'全唐诗/poet.song.118000.json','["神仙境界無戰爭，奚用漆此巍巍城。", "吾聞秦皇昔多慾，富貴已極貪長生。", "蓬萊方丈欲親到，車轍馬迹無時停。", "萬騎南巡適吳越，天台咫尺行將登。", "仙山不容肉眼見，天爲設險藏神靈。", "山中采藥使未返，鮑魚向已沙丘腥。", "秦爲防胡築紫塞，連年不恤生靈害。", "天亦防秦甚防胡，赤城高峙烟霞外。", "神仙要非求可得，祖龍可笑徒勞役。", "當時劉阮本無心，花笑水迎山自闢。", "我向丹丘數往來，羣仙杖舄未容陪。", "揮毫欲續孫公賦，愧無擲地金聲才。", "目極蒼崖千萬丈，世無仙骨那能上。", "直須內外兩丹成，駕鶴驂鸞如指掌。"]'),
('4b11249e-9ff4-415f-bbed-4de957554681','柘溪道傍有班竹百餘挺蕭洒可愛與先之賞翫移時因念鄉間無是種約異日移其根予戲誦君看江上千竿竹不是男兒淚點班之句遂發一笑既而作數語解異世婦人之嘲且志不必移根也','王十朋','宋','宋诗','song-poetry','','[]','男兒有淚不染竹，當作包胥賈生哭。',64,'全唐诗/poet.song.118000.json','["男兒有淚不染竹，當作包胥賈生哭。", "湘源遺種雖可愛，節目尚餘兒女態。", "誰能千里移此根，出門又恐添啼痕。", "不如還家種慈竹，不厭千竿萬竿綠。"]'),
('81df16be-112d-499d-98ae-4d91815cc3b1','代婦人答','王十朋','宋','宋诗','song-poetry','','[]','君勿題詩訾湘竹，君勿笑他兒女哭。',64,'全唐诗/poet.song.118000.json','["君勿題詩訾湘竹，君勿笑他兒女哭。", "人爲鍾情故生愛，夫婦相思乃常態。", "爲君飄蕩太無根，兩臉盡是思君痕。", "安得相依似雙竹，長保千秋萬秋綠。"]'),
('918cce5b-a3dd-47b0-a998-ab277ebf8a98','題劉阮祠用過仙人渡韵','王十朋','宋','宋诗','song-poetry','','[]','澗水桃花路易迷，不同人世下成蹊。',32,'全唐诗/poet.song.118000.json','["澗水桃花路易迷，不同人世下成蹊。", "自從重入山中去，烟雨深深鎖舊溪。"]'),
('35fbea42-825c-4544-9a40-7975f0e35282','至剡溪寄夢齡昌齡','王十朋','宋','宋诗','song-poetry','','[]','歉歲爲行客，清秋別故園。',48,'全唐诗/poet.song.118000.json','["歉歲爲行客，清秋別故園。", "自從離雁蕩，長是念鴒原。", "世路疲來往，親闈廢凊溫。", "緘書付歸僕，銷盡旅中魂。"]'),
('ba4a6204-d92c-45a2-a6ea-eea981afa279','剡溪舟中有感','王十朋','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','又作游吳客，重登入越船。',48,'全唐诗/poet.song.118000.json','["又作游吳客，重登入越船。", "西風桑葉岸，細雨菊花天。", "旅思秋偏惡，鄉心夜不眠。", "錢塘江上月，行見十分圓。"]'),
('c33e5137-102f-40ee-a053-c7a2940e4138','前中秋一日舟過山陰晚稻方熟忽動鄉思呈先之','王十朋','宋','宋诗','song-poetry','','[]','西風吹白蘋，游子千里征。',96,'全唐诗/poet.song.118000.json','["西風吹白蘋，游子千里征。", "扁舟入鑑湖，水月相涵明。", "山陰晚稻熟，萬頃黄雲平。", "憑湖屬遠目，動我鄉曲情。", "豈不有一飽，胡爲苦營營。", "五年倦來往，爭此蝸角名。", "未知得失間，奚辱亦奚榮。", "何當畢所願，同歸及春耕。"]'),
('db0e40ed-3819-4421-977d-d1e9178c3f67','夜泊蕭山酒醒夢覺月色滿船感而有作','王十朋','宋','宋诗','song-poetry','','[]','候屆星虛午夜凉，更堪停棹水中央。',64,'全唐诗/poet.song.118000.json','["候屆星虛午夜凉，更堪停棹水中央。", "短蓬破處漏明月，歸夢斷時思故鄉。", "客裏未忘詩酒趣，老來厭逐利名場。", "明朝又向錢塘去，十里西風桂子香。"]'),
('e3cc0b20-b3c9-4829-abad-a287cf5bb303','十月二十八日母氏劬勞之日也哀痛中書二十八字','王十朋','宋','宋诗','song-poetry','','[]','縣弧謾喜生良月，看鏡堪嗟已二毛。',32,'全唐诗/poet.song.118000.json','["縣弧謾喜生良月，看鏡堪嗟已二毛。", "不見雙親空泣血，此生無計報劬勞。"]'),
('09a9da97-98c4-4ed3-afdb-071eac71d9d5','次韻昌齡游白石二詩 東際','王十朋','宋','宋诗','song-poetry','','[]','飛流噴沫下烟嵐，肯使名同盜與貪。',64,'全唐诗/poet.song.118000.json','["飛流噴沫下烟嵐，肯使名同盜與貪。", "莫訝來時多汩汩，定知止處却潭潭。", "遥通雁蕩靈湫兩，巍壓龍門巨浪三。", "好景不煩摩詰畫，盡歸詩客句中含。"]'),
('6c396fe9-0646-434e-965f-40cf8f2764b2','次韻昌齡游白石二詩 道岩','王十朋','宋','宋诗','song-poetry','','[]','未窮脚力上層霄，想象名山興亦高。',64,'全唐诗/poet.song.118000.json','["未窮脚力上層霄，想象名山興亦高。", "物外游人身插羽，洞中仙客體生毛。", "利名奔走嗟吾老，杖屨徜徉羨子豪。", "鳬舄共游端有日，預期木葉下亭臯。"]'),
('84daa430-a20f-427f-ac26-1901e703f339','再和二首  其一','王十朋','宋','宋诗','song-poetry','','[]','佛國飛來百尺嵐，要將法水洗嗔貪。',64,'全唐诗/poet.song.118000.json','["佛國飛來百尺嵐，要將法水洗嗔貪。", "仙人錯認蓬萊島，騷客羞談钴鉧潭。", "觀盡豈須窮莫四，悟來初不異前三。", "莫將七際觀東際，法界三千際際含。"]'),
('243c7023-2db4-4f69-b7fa-ffbc60c9cca6','再和二首  其二','王十朋','宋','宋诗','song-poetry','','[]','少和丹就已登霄，巖與仙風兩並高。',64,'全唐诗/poet.song.118000.json','["少和丹就已登霄，巖與仙風兩並高。", "甚欲此身參鶴馭，尚嫌多事類牛毛。", "雲間雞犬年猶永，世上英雄意謾豪。", "堪羨北山山下客，不緣射雉亦如臯。"]'),
('aae72a4d-c51f-43a4-a707-dedacd2833b2','贈萬序','王十朋','宋','宋诗','song-poetry','','[]','弦誦先閭里，東平典則存。',48,'全唐诗/poet.song.118000.json','["弦誦先閭里，東平典則存。", "殘膏沾後學，餘慶在重孫。", "事業年方少，功名志可吞。", "時人貪擇臠，慎勿爲財婚。"]'),
('db562bba-c06f-4b3c-b218-c61199ec037d','過萬橋哭潘先生','王十朋','宋','宋诗','song-poetry','','[]','投老西游志不成，死生貧賤見交情。',32,'全唐诗/poet.song.118000.json','["投老西游志不成，死生貧賤見交情。", "江頭昨夜潮聲怒，却爲先生氣不平。"]'),
('1ce9b628-e82d-4c9a-a66f-f56d2e31cdfc','夏伯虎贈雙鯉','王十朋','宋','宋诗','song-poetry','','[]','知我山間久食蔬，遥分七十二鱗魚。',32,'全唐诗/poet.song.118000.json','["知我山間久食蔬，遥分七十二鱗魚。", "不妨時遣長鬚至，要得頻看尺素書。"]'),
('9a4b619e-b9e2-4af6-ba25-6cfccf5e7cec','貧家連歲蠶荒今年尤甚，妻孥有號寒之患每欲以酒自寬酒惡竟不能醉拙於生事殊可笑也表弟萬大年家蠶熟酒醇有足樂者因思舊詩有剩栽桑柘教妻蠶句遂和以寄之','王十朋','宋','宋诗','song-poetry','','[]','年踰四十尚何堪，愈老生涯愈不諳。',64,'全唐诗/poet.song.118000.json','["年踰四十尚何堪，愈老生涯愈不諳。", "何以代耕猶未仕，初無可樂誤爲男。", "號寒兒訝桑條沃，飲酒賓嫌蜜汁甘。", "堪羨通家萬公子，細君善釀更能蠶。"]'),
('938fd4b7-25e6-4f50-9f58-708885feeca0','大年和詩再用韻','王十朋','宋','宋诗','song-poetry','','[]','年少如君種種堪，文場世事兩俱諳。',64,'全唐诗/poet.song.118000.json','["年少如君種種堪，文場世事兩俱諳。", "何憂晁錯不高第，未怕杜陵無好男。", "况有田園足耕養，好窮水陸奉肥甘。", "更須猛割閨房愛，來與荀卿共賦蠶。"]'),
('c73bb686-9a0c-4383-b762-7c8bf93fa1ae','李梗和詩復用前韵','王十朋','宋','宋诗','song-poetry','','[]','維摩老病思何堪，藥性從今却漸諳。',64,'全唐诗/poet.song.118000.json','["維摩老病思何堪，藥性從今却漸諳。", "掩卷正思眠丈室，論文俄喜遇奇男。", "共嗟世路羊腸險，剛怕人情鼠口甘。", "聳壑昂霄君未晚，吾衰已是食三蠶。"]'),
('6601255a-2560-48cd-9822-20efc4244a57','用前韻寄周光宗','王十朋','宋','宋诗','song-poetry','','[]','炎凉世態可能堪，肺腑唯蒙長者諳。',64,'全唐诗/poet.song.118000.json','["炎凉世態可能堪，肺腑唯蒙長者諳。", "耐久敢忘三世好，同庚况有兩家男。", "我嗟風樹徒悲苦，君奉庭闈備旨甘。", "他日相看兩黄髮，願爲隣舍話田蠶。"]'),
('c5e50f36-bc46-4026-a3ac-98d102a76afc','送李梗','王十朋','宋','宋诗','song-poetry','','[]','梅始花時送子歸，梅黄雨細又分離。',64,'全唐诗/poet.song.118000.json','["梅始花時送子歸，梅黄雨細又分離。", "不堪旅食見飛燕，那更催歸聞子規。", "太白讀書容有趣，少卿惜別可無詩。", "霜臺清峭家風在，努力功名少壯時。"]'),
('3c59ba60-95d6-4d7e-bedf-d4afe9948ed9','壬申中秋交朋解散不期而會者鄭生遜志夏生伯虎因小飲玩月二子各以詩贈依韻酬之  其一','王十朋','宋','宋诗','song-poetry','','[]','鄭生襟宇絕纖埃，夏子心希好學回。',64,'全唐诗/poet.song.118000.json','["鄭生襟宇絕纖埃，夏子心希好學回。", "誰遣吾人來破願，可能良夜不銜杯。", "從來月罕中秋見，那更尊無俗子陪。", "遥指桂枝因賀客，文星近歲屬溫台。"]'),
('7826fbd2-b62e-47b9-80b4-e34e242c9608','壬申中秋交朋解散不期而會者鄭生遜志夏生伯虎因小飲玩月二子各以詩贈依韻酬之  其二','王十朋','宋','宋诗','song-poetry','','[]','猶勝太白號三人，又免韓公誚聚蚊。',64,'全唐诗/poet.song.118000.json','["猶勝太白號三人，又免韓公誚聚蚊。", "薄有壺觴非獨酌，共將文字作清醺。", "天高雲散懸金餠，風峭溪凉皺縠文。", "却恨鍾情未能遣，愁腸終夜轉車輪。"]'),
('58cbc6ea-edd6-46f0-aa10-9e24e9621316','書小成室','王十朋','宋','宋诗','song-poetry','','[]','萬言杯水北窗裏，慷慨悲歌五夜長。',64,'全唐诗/poet.song.118000.json','["萬言杯水北窗裏，慷慨悲歌五夜長。", "骨肉未知蘇季子，鄉閭誰敬馬賓王。", "爲人心盡同毛穎，與世交疏類孔方。", "晦迹溪山可無恨，蕭然一室任凄凉。"]'),
('48e61117-9938-4c93-a573-9f7a12ebb009','哭孟丙  其一','王十朋','宋','宋诗','song-poetry','','[]','三歲甜酸學語兒，能來壁下看題詩。',32,'全唐诗/poet.song.118000.json','["三歲甜酸學語兒，能來壁下看題詩。", "當時戯發十年問，添我無窮今日悲。"]'),
('b9c47f84-5c5e-42fa-b021-90edc916fa23','哭孟丙  其二','王十朋','宋','宋诗','song-poetry','','[]','蕭瑟楊雄宅一區，不堪老境失童烏。',32,'全唐诗/poet.song.118000.json','["蕭瑟楊雄宅一區，不堪老境失童烏。", "數莖鬚似經霜葉，爲汝鍾情一夜枯。"]'),
('37388d5f-e112-48ea-a2c1-fa279e673ffb','哭孟丙  其三','王十朋','宋','宋诗','song-poetry','','[]','簾外飛飛燕哺雛，道傍兒戯聚游魚。',32,'全唐诗/poet.song.118000.json','["簾外飛飛燕哺雛，道傍兒戯聚游魚。", "老人含淚坐書几，不見吾兒已月餘。"]'),
('e3045264-a62c-4e2e-ba28-261c85be0e5f','哭孟丙  其四','王十朋','宋','宋诗','song-poetry','','[]','偃蹇衰翁四十餘，梅花溪上結茅廬。',32,'全唐诗/poet.song.118000.json','["偃蹇衰翁四十餘，梅花溪上結茅廬。", "窗明几凈還如舊，不見兒來覓紙書。"]'),
('16eec21c-dc4b-46bb-afb3-6cdeb74f23c6','哭孟丙  其五','王十朋','宋','宋诗','song-poetry','','[]','偶作吾兒真夢寐，暫來人世誤婁羅。',32,'全唐诗/poet.song.118000.json','["偶作吾兒真夢寐，暫來人世誤婁羅。", "雖然修短由天命，致汝無辜我罪多。"]'),
('18f211f7-e2e4-4d49-a464-814bce9af745','哭孟丙  其六','王十朋','宋','宋诗','song-poetry','','[]','七年嬌姹慰衰翁，回首追思一夢中。',32,'全唐诗/poet.song.118000.json','["七年嬌姹慰衰翁，回首追思一夢中。", "與汝夙緣如未斷，重來當似顧非熊。"]'),
('a3e4c5b2-4810-4aeb-bf8b-1e6dc3ff5d67','家童拾栗因念亡兒作數語以寫鍾情之悲','王十朋','宋','宋诗','song-poetry','','[]','去年覓栗嫌汝癡，責汝曾賦淵明詩。',64,'全唐诗/poet.song.118000.json','["去年覓栗嫌汝癡，責汝曾賦淵明詩。", "今年栗熟不汝見，凄然白骨埋荒陂。", "西風簌簌黄葉飛，家僮拾栗門前歸。", "汝兄汝妹爭來取，汝父傷心淚如雨。"]'),
('1cfc5eff-1a97-4baa-8993-c0ffc06388ef','林知常惠白酒六尊仍示酒法作十韻謝之','王十朋','宋','宋诗','song-poetry','','[]','老去生涯付盃酒，種秫辛勤三百畝。',160,'全唐诗/poet.song.118000.json','["老去生涯付盃酒，種秫辛勤三百畝。", "東臯遺法嗟失傳，蜜汁虀漿不通口。", "邇來軟飽經月無，豈有清歡對朋友。", "百錢强就村媼醉，終夜蔬腸作雷吼。", "先生祇把文字耕，妙意能施杜康手。", "憐我新愁餘萬斛，那更澆腸無五斗。", "分惠青州六從事，秘法兼蒙傳肘後。", "便同北海歌不空，免似東坡歎烏有。", "嗟予偃蹇老更饕，感激故人情意厚。", "會須續遣白衣來，籬畔黄花欲重九。"]'),
('5723c81b-c9a2-431d-8c8c-71773abc69cd','九日飲酒會趣堂者十九人老者與焉既醒念不可以無詩因用贈林知常韻示諸友','王十朋','宋','宋诗','song-poetry','','[]','我似楊雄貧嗜酒，筆作耕犁紙爲畝。',160,'全唐诗/poet.song.118000.json','["我似楊雄貧嗜酒，筆作耕犁紙爲畝。", "辛勤耕植三十年，往往糟醨罕濡口。", "今年九日甕盎空，誰饌先生荷諸友。", "衰顔迎醉生嫩紅，饞腹隨餐失饑吼。", "菊花不上老人頭，酒盞聊傳此時手。", "文字飲韓嘉數子，禮法拘髠惟一斗。", "衰翁興盡輒先歸，不待盃盤狼籍後。", "坐客高歌驚四隣，吾鄉已在無何有。", "明朝黄花亦不惡，俗眼無端自疏厚。", "酒醒聊記坐中人，有似平原凡十九。"]'),
('364df028-9dac-4d69-beb8-76b05c250304','陳元佐和詩贈以前韻','王十朋','宋','宋诗','song-poetry','','[]','無功懶仕由堪酒，故向東臯事田畝。',160,'全唐诗/poet.song.118000.json','["無功懶仕由堪酒，故向東臯事田畝。", "自慚耕稼非老農，歲入何曾給糊口。", "通功易事媿無術，謾闢書齋會鄉友。", "出技慙如鼯鼠窮，說法强爲師子吼。", "交游漸覺不在眼，老拙自知當縮手。", "陳生慷慨真可人，文似良金膽如斗。", "論交何止十年前，耐久遥期十年後。", "把酒殷勤問黄菊，十年故舊寧多有。", "士窮要使節義敦，不見韓公稱子厚。", "北窗捉筆書惡詩，醉中戯贈陳三九。"]'),
('3f639520-270d-4933-969c-d3fe6830c5d9','周仲翔和詩贈以前韻','王十朋','宋','宋诗','song-poetry','','[]','與子十年同把酒，貧賤未能離隴畝。',160,'全唐诗/poet.song.118000.json','["與子十年同把酒，貧賤未能離隴畝。", "今年依舊對黄花，會意何由笑開口。", "老來鍾愛有三兒，邇歲從師得吾友。", "祝螟方擬爲蠃飛，舐犢俄驚作牛吼。", "幼兒已作一覺夢，大匠徒施兩年手。", "乙子沉痾頼營牧，再生豈止由南斗。", "嗟予屯厄世所棄，急難誰肯相先後。", "論交最喜子善終，報德深慚我無有。", "猶憐甲乙二孺子，莫景於渠意加厚。", "煩君爲我嚴誨之，毋惜鞭笞九十九。"]'),
('b75a327a-8b42-4eb9-a4c0-fd1a78f67d5c','陳獻可宋孝先萬孝傑夏伯虎和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','準擬重陽會詩酒，手種菊花凡數畝。',160,'全唐诗/poet.song.118000.json','["準擬重陽會詩酒，手種菊花凡數畝。", "佳節相逢俱可人，一一篇章堪適口。", "揚庭醖籍更清新，晉宋間人顔謝友。", "舜卿詞源浩萬斛，下筆驚人風雨吼。", "季梁蕭洒詩如人，飄然自是風騷手。", "用之年少富文墨，日出珠璣不論斗。", "誠叔思深希仲逸，齊驅未識誰先後。", "老朽那能敵年少，胸中空洞嗟無有。", "張我三軍得數子，造物遺予非不厚。", "明年秋戰豈無人，雲夢定須吞八九。"]'),
('61c15af3-ee06-42c4-9582-22f87bbe9d95','九日把酒十九人和詩者數人而已今已後期不復追索許以來年九日還用前韻發一笑','王十朋','宋','宋诗','song-poetry','','[]','勸君須飲文字酒，勸君耕耨心中畝。',160,'全唐诗/poet.song.118000.json','["勸君須飲文字酒，勸君耕耨心中畝。", "飲非文字猶聚蚊，心田不耕棘生口。", "登高佳節豈易得，况此相逢皆勝友。", "談傾坐上冰玉清，興生筆下波濤吼。", "我亦逢場聊戯劇，韻語殊非三昧手。", "試投瓦礫已成堆，辱報驪珠未盈斗。", "和之者寡豈陽春，高才料耻居王後。", "嗟我窮愁無以遣，酒債詩篇行處有。", "與茲飲會類平原，逃我詩盟幾高厚。", "如今並許隔年還，直須日月逢重九。"]'),
('d83ece03-30a9-41a5-9428-a074850db53d','宋孝先示讀自寬集復用前韻','王十朋','宋','宋诗','song-poetry','','[]','淵明酷愛尊中酒，季子貧無負郭畝。',160,'全唐诗/poet.song.118000.json','["淵明酷愛尊中酒，季子貧無負郭畝。", "我生薄與二子同，俯仰人間亦緣口。", "一室蕭然僅容膝，毛穎陶泓自相友。", "會心終日雌聲讀，排悶有時粗氣吼。", "感秋詩集名自寬，雕琢更慙非妙手。", "篇章不工如子固，聲名敢望星之斗。", "宋生輙作過情語，十韻殷勤爲跋後。", "譽之韓柳誰敢當，意古語奇吾豈有。", "何如操矛時入室，鍼我膏肓乃相厚。", "床頭周易深且神，毋惜徃來論六九。"]'),
('e5ec19c5-8334-4d69-8e34-6321b0097694','再用前韻述懷并簡諸友','王十朋','宋','宋诗','song-poetry','','[]','太白徉狂喜盃酒，元龍豪氣恥求畝。',160,'全唐诗/poet.song.118000.json','["太白徉狂喜盃酒，元龍豪氣恥求畝。", "揮毫爛吐風月篇，濟世高談覇王口。", "古人可作誰與歸，白也吾師登可友。", "萬言窗下盃水冷，百尺樓頭鼻聲吼。", "丈夫未遇聊爾耳，肯向權門思炙手。", "凈掃一室安吾貧，晝閲詩書夜星斗。", "休論生天與作佛，靈運甘居丈人後。", "吾儕慎分慕富貴，鳴鼓定須攻冉有。", "但願相從文字樂，交情合向窮中厚。", "倚看前席坐間人，平步登瀛參二九。"]'),
('2d3e5095-9840-4d80-b04c-4005daaa2941','鄭遜志胡叔成謝鵬劉敦信萬廓鄔一唯和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','前日中秋一壺酒，交朋解散歸南畝。',160,'全唐诗/poet.song.118000.json','["前日中秋一壺酒，交朋解散歸南畝。", "把盃邀月止三人，中有客來從谷口。", "首登詩壇出險語，張我孤軍真畏友。", "重陽佳句更奇絕，西風猛向松關吼。", "中庸伯始遥遥胄，穎然作賦吟詩手。", "謝客篇章似春草，分得家傳才一斗。", "句法天然自圓熟，長慶詩豪今有後。", "妙齡能作老成語，必大奇兒亦希有。", "鄔郡太守司馬孫，文與其人兩溫厚。", "我與數子無薰蕕，文字相從十常九。"]'),
('bb393692-f01c-44f7-90d0-5720feb365cb','九日會飲予爲唱首自和凡數篇皆因事敘情爾未作重九詩也今再和一篇每句用事而不見姓名末聯外餘皆略存對偶必有能和之者','王十朋','宋','宋诗','song-poetry','','[]','獨坐東籬嘆無酒，種秫西疇謾盈畝。',160,'全唐诗/poet.song.118000.json','["獨坐東籬嘆無酒，種秫西疇謾盈畝。", "菊花叢畔來白衣，桑落杯中付饞口。", "汝南風俗有故事，龍山宴集多佳友。", "靜聞彭澤三徑香，遥想藍田雙澗吼。", "順時習射馬嘶風，隨俗登山囊繫手。", "慈恩塔冷舊衣冠，戯馬臺空古刁斗。", "三嗅馨香感槩中，細看茱萸酩酊後。", "應制賦詩人孰在，坐湖聯句今還有。", "明朝見花心已別，此日登高意宜後。", "日月並應節物嘉，獨恨今年無閏九。"]'),
('723b8daf-0b49-4295-96bf-02956d0b5ed3','九日寄昌齡弟  其一','王十朋','宋','宋诗','song-poetry','','[]','憶昔逢重九，登臨不憚遥。',24,'全唐诗/poet.song.118000.json','["憶昔逢重九，登臨不憚遥。", "弟兄同把酒，行樂興飄飄。"]'),
('488b5288-ff34-4cb6-81f4-ad28bdb5374b','九日寄昌齡弟  其二','王十朋','宋','宋诗','song-poetry','','[]','去歲重九日，吾親窀穸期。',24,'全唐诗/poet.song.118000.json','["去歲重九日，吾親窀穸期。", "東籬自黄菊，淚眼可曾知。"]'),
('99847774-dab0-4975-9373-ef07e9fd60a9','九日寄昌齡弟  其三','王十朋','宋','宋诗','song-poetry','','[]','此日黄花酒，深期酌弟兄。',24,'全唐诗/poet.song.118000.json','["此日黄花酒，深期酌弟兄。", "誰知有離別，西望不勝情。"]'),
('99b20c97-0b8a-48af-9cf0-3d87a810cd2a','九日寄昌齡弟  其四','王十朋','宋','宋诗','song-poetry','','[]','我有茱萸沜，遥同輞川底。',24,'全唐诗/poet.song.118000.json','["我有茱萸沜，遥同輞川底。", "登高少一人，又是王家弟。"]'),
('d410b136-3380-4967-84e3-c1ab6eab0056','九日寄昌齡弟  其五','王十朋','宋','宋诗','song-poetry','','[]','嘉節苦難遇，故山隨俗登。',24,'全唐诗/poet.song.118000.json','["嘉節苦難遇，故山隨俗登。", "未能如鄭谷，一榻對高僧。"]'),
('747a814d-34c3-47dd-ae56-7cd1b8ee5505','九日寄昌齡弟  其六','王十朋','宋','宋诗','song-poetry','','[]','白石登山客，新詩句必豪。',24,'全唐诗/poet.song.118000.json','["白石登山客，新詩句必豪。", "寧容杜陵老，獨步玉山高。"]'),
('b16d8a67-649d-46bf-a6fb-49f3df7504af','九日寄昌齡弟  其七','王十朋','宋','宋诗','song-poetry','','[]','我思鴈蕩游，欲與鴈行去。',24,'全唐诗/poet.song.118000.json','["我思鴈蕩游，欲與鴈行去。", "羽翼本天生，誰令分兩處。"]'),
('1b2cf5df-5073-4cdd-9739-4ff06afd16ea','九日寄昌齡弟  其八','王十朋','宋','宋诗','song-poetry','','[]','樂事苦無多，良辰豈長見。',24,'全唐诗/poet.song.118000.json','["樂事苦無多，良辰豈長見。", "明年綴席時，要使茱萸徧。"]'),
('16c106eb-d484-44a8-b82c-47cce36d6403','九日寄昌齡弟  其九','王十朋','宋','宋诗','song-poetry','','[]','庭前有晚菊，青蘂未堪插。',24,'全唐诗/poet.song.118000.json','["庭前有晚菊，青蘂未堪插。", "開日即重陽，歸來酒同呷。"]'),
('55bc1f83-4128-4626-9da0-010f8ac3dd9c','九日寄昌齡弟  其一○','王十朋','宋','宋诗','song-poetry','','[]','載酒觴黄菊，登山臂紫茱。',24,'全唐诗/poet.song.118000.json','["載酒觴黄菊，登山臂紫茱。", "重修汝南事，災厄自今無。"]'),
('3eb63cfc-1f1f-4510-8044-393eace3110e','九日寄昌齡弟  其一一','王十朋','宋','宋诗','song-poetry','','[]','老去悲秋甚，興來聊自娛。',24,'全唐诗/poet.song.118000.json','["老去悲秋甚，興來聊自娛。", "明年知健否，子細看茱萸。"]'),
('7cbbcb7e-a54f-4a18-897d-4896f9bdf76e','九日寄昌齡弟  其一二','王十朋','宋','宋诗','song-poetry','','[]','窮途嗟我衰，中歲傷兒夭。',24,'全唐诗/poet.song.118000.json','["窮途嗟我衰，中歲傷兒夭。", "兄弟止三人，尊前豈宜少。"]'),
('3ae7ba5a-c3af-4cb5-8c93-8f8bdaa01ff6','九日寄昌齡弟  其一三','王十朋','宋','宋诗','song-poetry','','[]','嗅菊謾勞三，賜安得萸一。',24,'全唐诗/poet.song.118000.json','["嗅菊謾勞三，賜安得萸一。", "聊分故園枝，不負重陽日。"]'),
('775a3835-8cec-49e3-ac7f-a9455ba71cd5','九日寄昌齡弟  其一四','王十朋','宋','宋诗','song-poetry','','[]','節物豈不好，吾家何太貪。',24,'全唐诗/poet.song.118000.json','["節物豈不好，吾家何太貪。", "一尊聊爾寄，重意媿先人。"]'),
('22cd189d-39d7-4545-83d8-deffd0e448ff','萬叔永誕日在孟秋，乃以重九開燕俟佳節也予不獲與稱觴之列作詩以賀','王十朋','宋','宋诗','song-poetry','','[]','種德尤勝竇十郎，靈椿未老桂先芳。',64,'全唐诗/poet.song.118000.json','["種德尤勝竇十郎，靈椿未老桂先芳。", "一門此去無疑大，五福他年未易量。", "鳳穴生雛梧正碧，龍山開宴菊初黄。", "吾鄉此會從來少，恨不登堂舉壽觴。"]'),
('94ded0f7-3091-4f73-a7da-14f8940f690a','九月十二夜獨步梅溪翫月人迹悄然秋色滿眼微風不動巖桂自香初不勞思偶得四句蓋心境中靜時語也歸小成室對短燈檠索紙書之','王十朋','宋','宋诗','song-poetry','','[]','獨步溪頭夜初寂，掃空塵念心清凉。',32,'全唐诗/poet.song.118000.json','["獨步溪頭夜初寂，掃空塵念心清凉。", "月明眼底見秋色，境靜鼻根聞桂香。"]'),
('31bc603e-bac8-4de1-91e7-2d5763deb310','前日寓邑偶值乍寒陳劉二生濟我以衣童生濟我以衾既別爲二詩以贈 贈陳元佐劉士宗','王十朋','宋','宋诗','song-poetry','','[]','肌體生鱗鬚颯毛，衰年怯冷欲兒號。',64,'全唐诗/poet.song.118000.json','["肌體生鱗鬚颯毛，衰年怯冷欲兒號。", "無人來綻韓公襖，有友能施范叔袍。", "入手乍驚儒袖闊，披身尤喜義襟高。", "書生忍凍誰相顧，共弊輕裘頼我曹。"]'),
('b4edb1fb-e649-405f-9073-b593370c0384','前日寓邑偶值乍寒陳劉二生濟我以衣童生濟我以衾既別爲二詩以贈 贈童偉侃','王十朋','宋','宋诗','song-poetry','','[]','凜冽霜風夜薄人，誰能煖我曲勾身。',64,'全唐诗/poet.song.118000.json','["凜冽霜風夜薄人，誰能煖我曲勾身。", "寒欺三幅范衾陋，睡美一宵姜被新。", "體粟不愁生旅舍，鼻雷想見撼比隣。", "夢回却念君兄弟，苫塊無眠痛慕親。"]'),
('49e462f7-22df-4b2f-b1c3-4e39b525d229','萬先之生兩男作洗兒歌賀之','王十朋','宋','宋诗','song-poetry','','[]','君不見徐卿二子生絕奇，熊羆入夢非同時。',262,'全唐诗/poet.song.118000.json','["君不見徐卿二子生絕奇，熊羆入夢非同時。", "徒煩孔子與釋氏，兩回抱送麒麟兒。", "又不見昔日梁嬴亦雙乳，生止一男仍一女。", "過期畢竟非其人，未免終身亦妾圉。", "鬰葱佳氣充門閭，龍穴盛事從來無。", "蓂階良月吐三莢，蚌腹甲夜生雙珠。", "相對抱持翁嫗喜，眉目分明巧相似。", "慈顔戯語綵衣郎，汝子他年勝我子。", "郎君拜舞笑答翁，翁生六兒年豈同。", "何如今日一巵酒，手抱兩孫頭未童。", "二雛慶誕相先後，未省如何分長幼。", "商家尚質周尚文，喚取何休細推究。", "慶門蘭玉行滿庭，伯仲叔季雙命名。", "他時四乳類周士，森森八桂同敷榮。", "我忝通家同筆硯，聞君得子歡無間。", "殷勤爲作洗兒歌，覓取金錢三百萬。"]'),
('8213a611-11c7-440d-aa42-31e577341337','黄府君挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','不雜商山綺與園，生涯占得小桃源。',32,'全唐诗/poet.song.118000.json','["不雜商山綺與園，生涯占得小桃源。", "平生隠德知多少，跨竈詵詵已六孫。"]'),
('50372d29-8d30-4c7b-911f-779ae1d90ccf','黄府君挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','紛然紾臂已成風，一爨誰能再世同。',32,'全唐诗/poet.song.118000.json','["紛然紾臂已成風，一爨誰能再世同。", "野史他年書逸事，定須記此富家翁。"]'),
('e41558ba-3554-4ca9-a2d9-44a91dd772eb','黄府君挽詞  其三','王十朋','宋','宋诗','song-poetry','','[]','揚州別駕知名士，肝膽崔嵬百鍊剛。',32,'全唐诗/poet.song.118000.json','["揚州別駕知名士，肝膽崔嵬百鍊剛。", "誰謂公家有蘭玉，解令高選繼東床。"]'),
('376d5986-0109-44fa-bd25-69ff4fd496ba','黄府君挽詞  其四','王十朋','宋','宋诗','song-poetry','','[]','齒髮如公自古稀，定應含笑九原歸。',32,'全唐诗/poet.song.118000.json','["齒髮如公自古稀，定應含笑九原歸。", "春風白石巖前路，忍見楊花作雪飛。"]'),
('17b7e947-6b14-43c8-bb46-93b63cfa10de','予自乙丑冬如臨安赴補逮今凡五往矣是行也痛慈親之不見傷幼兒之蚤死登途泫然因成是詩','王十朋','宋','宋诗','song-poetry','','[]','八歲五行役，茲行最感傷。',48,'全唐诗/poet.song.118000.json','["八歲五行役，茲行最感傷。", "思親啼血淚，憶子斷剛腸。", "游遠有遺恨，鍾情難遽忘。", "離家兩夜夢，長遶白巖旁。"]'),
('04a82955-2c62-4f6b-8c6b-2ed2a77fc8b7','初擬過雁山既而取道烏石寄夢齡昌齡','王十朋','宋','宋诗','song-poetry','','[]','不度丹芳七七盤，非緣杖屨厭間關。',32,'全唐诗/poet.song.118000.json','["不度丹芳七七盤，非緣杖屨厭間關。", "要留來歲高風便，兄弟成行過此山。"]'),
('20c37a59-272a-4db7-88f2-7a61f6728a57','過白溪','王十朋','宋','宋诗','song-poetry','','[]','朝離黄塘憩烏石，莫宿青江過白溪。',32,'全唐诗/poet.song.118000.json','["朝離黄塘憩烏石，莫宿青江過白溪。", "嶺上回頭觀赤水，山川五色望中迷。"]'),
('fc11b9cf-5d11-4c66-9433-da59dcd58460','過盤山宿旅邸','王十朋','宋','宋诗','song-poetry','','[]','一嶺迢迢十里賒，行人半日踏烟霞。',32,'全唐诗/poet.song.118000.json','["一嶺迢迢十里賒，行人半日踏烟霞。", "青山遮莫盤千匝，歸夢何曾不到家。"]'),
('d40c04c4-3661-4788-aa9f-ae334418cfb0','登皇華亭','王十朋','宋','宋诗','song-poetry','','[]','不是四方銜命士，偶來亭上賦皇華。',32,'全唐诗/poet.song.118000.json','["不是四方銜命士，偶來亭上賦皇華。", "凭欄回首三百里，烟水茫茫思故家。"]'),
('cfa154bf-9916-41e7-9836-88a8ed502935','宿浮橋','王十朋','宋','宋诗','song-poetry','','[]','落日丹丘下，西江十里西。',48,'全唐诗/poet.song.118000.json','["落日丹丘下，西江十里西。", "浮橋通古道，逆旅傍清溪。", "夜靜水聲細，曉陰山色迷。", "吾鄉在何處，天遠白雲低。"]'),
('0cd335a8-9839-4c7b-b883-412dffcaad0c','與鄭時敏登樓把酒書二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','十里青山接郡城，危樓四望眼添明。',32,'全唐诗/poet.song.118000.json','["十里青山接郡城，危樓四望眼添明。", "海冥天闊鄉心切，更聽飛飛鴻雁聲。"]'),
('c22887ba-bd0e-4969-b81a-5487edebd142','與鄭時敏登樓把酒書二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','登樓能賦非王粲，沽酒忘形有鄭虔。',32,'全唐诗/poet.song.118000.json','["登樓能賦非王粲，沽酒忘形有鄭虔。", "千里相從文字飲，不辭費盡杖頭錢。"]'),
('1edb2a6d-02a4-456b-9f7a-0fd356510e51','途中見早梅','王十朋','宋','宋诗','song-poetry','','[]','山行初逢建子月，始見寒梅第一枝。',88,'全唐诗/poet.song.118000.json','["山行初逢建子月，始見寒梅第一枝。", "遥想吾廬亦如此，誰能千里贈相思。", "梅花發後思家切，竹間水際出橫枝。", "暗香踈影和新月，自是離情禁不得，觸物那堪此時節。", "春前臘後定歸來，要看溪上千株雪。"]'),
('e56a4318-77d7-4295-9ab6-935e43cbb51f','乙丑冬西游觀南明石像作詩一絕至壬申十月四日復往觀焉和前韻并書于佛閣','王十朋','宋','宋诗','song-poetry','','[]','兒戯團沙欲象真，誰將願力歷三塵。',32,'全唐诗/poet.song.118000.json','["兒戯團沙欲象真，誰將願力歷三塵。", "八年來徃簫峰客，兩度來瞻百尺身。"]'),
('ebb7fb83-47ff-4b74-8519-7961ae5492b9','西征','王十朋','宋','宋诗','song-poetry','','[]','紹興建元二十二，良月壬午時丁未。',384,'全唐诗/poet.song.118000.json','["紹興建元二十二，良月壬午時丁未。", "王家辭弟游帝都，出門滿眼思親淚。", "鶺鴒送我過原隰，朋友携尊宿蕭寺。", "朝離黄塘惜分別，莫宿青山嗟獨自。", "初心滿擬游雁山，行止非人輒乖異。", "黄巖留連越三宿，故舊過從日沈醉。", "鄭生伴我千里行，近世人無此風義。", "皇華亭上一回首，陡覺眉頭起鄉思。", "西江十里浮橋邊，把酒登樓吟擁鼻。", "山行初逢建子月，入眼梅花已春意。", "前觀三渡覺非舊，下視兩灘真可畏。", "渡頭仙人還笑我，髭鬚如棘猶名利。", "欲入天台觀石橋，行來匆匆未能遂。", "途中邂逅張老丞，十五年前樂清尉。", "自嗟吾非沈謝輩，面目從來苦難記。", "飛泉枕上夢成魔，達旦思家何曾睡。", "細雨濛濛入關嶺，旅邸重尋舊題字。", "雨脚微收過天姥，洗出峯巒疊蒼翠。", "劉阮祠荒土猶赤，溪山真是神仙地。", "道旁石現小金仙，傳舍荒凉誰廢置。", "柘溪竹染兒女痕，石嶺松含棟梁器。", "路入南明觀石佛，樓閣岧嶤更深邃。", "八年行役兩來游，巖上題詩記前事。", "乘興剡溪尋故人，久別相逢雜悲喜。"]'),
('6467b0b7-17f6-4c5e-ab4b-4c6f38501275','癸酉三月二十五日至剡溪旅舍觀曹夢良題壁有撩我思家第一篇之句僕離家半月亦未嘗作詩因次其韻','王十朋','宋','宋诗','song-poetry','','[]','客舍那堪聞杜鵑，夢魂驚斷竟無眠。',32,'全唐诗/poet.song.118000.json','["客舍那堪聞杜鵑，夢魂驚斷竟無眠。", "定知此境撩鄉思，我亦曾非第二篇。"]'),
('8ad2567b-1788-43c0-9bbd-34707e53dfec','剡之市人以崇奉東嶽爲名設盜跖以戲先聖所不忍觀因書一絕','王十朋','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','里巷無端戲大儒，恨無司馬爲行誅。',32,'全唐诗/poet.song.118000.json','["里巷無端戲大儒，恨無司馬爲行誅。", "不知陳蔡當時厄，還似如今嵊縣無。"]'),
('52d5e8fe-6661-4356-a41d-a30f8f71100d','周德遠植瑞香於窗前戲成一絕','王十朋','宋','宋诗','song-poetry','','[]','主人貪睡爲貪香，花植窗前意味長。',32,'全唐诗/poet.song.118000.json','["主人貪睡爲貪香，花植窗前意味長。", "見說有時魂夢裏，化爲蝴蝶遶花旁。"]'),
('547215f0-fc07-4ae4-9396-a178d6cb91d9','游明心院','王十朋','宋','宋诗','song-poetry','','[]','精舍傍脩嶺，道心隨眼明。',48,'全唐诗/poet.song.118000.json','["精舍傍脩嶺，道心隨眼明。", "泉餘偃公迹，山接剡溪城。", "無雨竹亦凈，有風松更清。", "誰名上方閣，撩我欲歸情。"]'),
('3a4b2d77-d38d-45f6-a3d8-6a9ecec310b2','游圓超院登挾溪亭次盧公韻','王十朋','宋','宋诗','song-poetry','','[]','路入剡山腰，風生玉川腋。',120,'全唐诗/poet.song.118000.json','["路入剡山腰，風生玉川腋。", "孤亭物外高，雙溪眼中碧。", "山僧作亭知幾春，賞音端怕逢詩人。", "自從妙語發丘壑，遂使絕境多蹄輪。", "我來首訪維摩詰，問訊雙溪自何出。", "發源應與婺溪同，賦物慙無沈郎筆。", "凭欄欲洗名利塵，入眼翻驚客恨新。", "山城重重水如带，可能挽住思鄉人。"]'),
('3b4740ef-8f63-4d54-9e8e-712335cd9d6e','寄夢齡昌齡弟','王十朋','宋','宋诗','song-poetry','','[]','老去生涯集百憂，一身萍泛剡溪頭。',64,'全唐诗/poet.song.118000.json','["老去生涯集百憂，一身萍泛剡溪頭。", "釣魚溫水同侯喜，旅食新豐類馬周。", "長鋏有時思海味，短檠終夜照離愁。", "也知四海皆兄弟，能似天生羽翼不。"]'),
('680ad8dd-38b2-4d71-89e7-05d6f4405338','高和叔生日','王十朋','宋','宋诗','song-poetry','','[]','高標綽有魯王風，天爲勳門慶誕公。',64,'全唐诗/poet.song.118000.json','["高標綽有魯王風，天爲勳門慶誕公。", "揮麈笑談傾坐上，傳家韜畧藴匈中。", "暫從剡水高人隠，行繼澶淵蓋世功。", "長願紅顔似今日，壽尊鯨吸百川空。"]'),
('b454b8db-43d9-4362-b2db-c4206fffe578','天子始絺','王十朋','宋','宋诗','song-poetry','','[]','盛德方居火，天王始服絺。',72,'全唐诗/poet.song.118000.json','["盛德方居火，天王始服絺。", "薰風生殿早，畏日到官遲。", "瑩雪羅初疊，含風葛乍披。", "汗寧濡玉體，暑不近天肌。", "表飾遵尼父，恩榮彼拾遺。", "中宮同儉德，無媿葛覃詩。"]'),
('6d0909b6-0100-4436-b100-a407a9a15dd3','淵源堂十二詩 淵源堂','王十朋','宋','宋诗','song-poetry','','[]','像貌崇賢聖，名言訓子孫。',24,'全唐诗/poet.song.118000.json','["像貌崇賢聖，名言訓子孫。", "日親師與友，力學探淵源。"]'),
