('c5e2d908-69bb-4c87-a6cf-675110b01bea','剡溪雜詠 挾溪亭','王十朋','宋','宋诗','song-poetry','','[]','遠水從台婺，同歸古嵊州。',24,'全唐诗/poet.song.118000.json','["遠水從台婺，同歸古嵊州。", "巍亭壓山頂，千古挾雙流。"]'),
('f25843f5-864b-4c5a-88bd-5d5739c463f4','剡溪雜詠 龍宮碑','王十朋','宋','宋诗','song-poetry','','[]','曾到龍宮寺，拂塵觀古碑。',24,'全唐诗/poet.song.118000.json','["曾到龍宮寺，拂塵觀古碑。", "何時無短李，肉眼可能知。"]'),
('ea24592d-8f3b-45e3-9701-b684c79b1c5e','剡溪雜詠 戴顒墓','王十朋','宋','宋诗','song-poetry','','[]','曠野冢纍纍，子孫猶不知。',24,'全唐诗/poet.song.118000.json','["曠野冢纍纍，子孫猶不知。", "千年戴顒墓，三字道旁碑。"]'),
('7c2b952a-3e01-4198-b345-d0758e36a3d6','剡溪雜詠 阮仙翁宅','王十朋','宋','宋诗','song-poetry','','[]','再入山中去，烟霞鎖翠微。',24,'全唐诗/poet.song.118000.json','["再入山中去，烟霞鎖翠微。", "故鄉遺宅在，何日更來歸。"]'),
('b0d2b3a1-b703-4b70-b2d4-c6ba4932b343','剡溪雜詠 戴溪亭','王十朋','宋','宋诗','song-poetry','','[]','剡水照人碧，剡山隨眼青。',24,'全唐诗/poet.song.118000.json','["剡水照人碧，剡山隨眼青。", "我來非雪興，慚上戴溪亭。"]'),
('fecac769-d7d5-4a6c-a6df-39c25a8abf04','剡溪雜詠 偃公泉','王十朋','宋','宋诗','song-poetry','','[]','泉自何時有，得名從偃公。',24,'全唐诗/poet.song.118000.json','["泉自何時有，得名從偃公。", "誰能繼張陸，爲載水經中。"]'),
('281b491c-f3d0-4718-9e73-971062824185','書院掛額展筵雅會也戲集諸堂軒齋名作詩','王十朋','宋','宋诗','song-poetry','','[]','黌館名初掛，銀鈎勢欲翻。',96,'全唐诗/poet.song.118000.json','["黌館名初掛，銀鈎勢欲翻。", "人才藴秀異，學業扣淵源。", "俊彥方群集，文章可細論。", "輝聲邁前輩，擢秀藹諸孫。", "心友居蘭室，天香滿桂軒。", "茲爲學者富，難與俗流言。", "恢義高風倡，同襟舊好敦。", "池中神鯉足，一一上龍門。"]'),
('c7340b19-d550-4ede-a03b-998b224e2407','別周德遠諸友','王十朋','宋','宋诗','song-poetry','','[]','山城過踈雨，客館生新秋。',96,'全唐诗/poet.song.118000.json','["山城過踈雨，客館生新秋。", "鄉心雜病思，浩蕩不可留。", "憶昨初來時，園花弄春柔。", "俯仰節物變，木杪風颼颼。", "旅食百日餘，故人情已周。", "論文有深味，惜別添牢愁。", "槐花物色老，琴書散交游。", "暖律回南枝，相期泛仙舟。"]'),
('559bb0c1-727f-40e0-b706-ea67120f58a2','宿石佛','王十朋','宋','宋诗','song-poetry','','[]','脩徑入幽壑，梵宮摩碧霄。',48,'全唐诗/poet.song.118000.json','["脩徑入幽壑，梵宮摩碧霄。", "仰頭驚突兀，跬步怯岧嶤。", "寶相石間湧，鍾聲雲外飄。", "明朝路南北，身世各塵囂。"]'),
('4913794a-1489-4eea-a177-d5696a1a61ce','白若遇水以小舟從石門渡勢危甚因書數語示圖南文卿時八月二日也','王十朋','宋','宋诗','song-poetry','','[]','歸途阻秋潦，溪漲不可涉。',192,'全唐诗/poet.song.118000.json','["歸途阻秋潦，溪漲不可涉。", "迂從石門渡，未見心已怯。", "壯哉龍伯宮，幽據雁山脇。", "巖如峙城壁，南北本相接。", "衆流欲朝宗，天爲開岌嶪。", "泓澄潭百尺，臲卼舟一葉。", "吾生何自輕，內顧無可挾。", "所頼二友生，千里同負笈。", "忠信儻可仗，免作飛鳶跕。", "來歸從剡溪，山水頗涉獵。", "石齧天台舟，浪拍臨海楫。", "可曾如此境，令我魂震懾。", "連年作行客，川塗但取捷。", "不因風雨暴，誰𣊟遠步屧。", "茲渡雖云惡，觀覽意亦愜。", "謾賦石門篇，添入剡游篋。"]'),
('1941c71d-5041-4cc9-8d1a-3d9a4abd3696','孟甲生日','王十朋','宋','宋诗','song-poetry','','[]','記汝初生際，燈花達旦然。',48,'全唐诗/poet.song.118000.json','["記汝初生際，燈花達旦然。", "門闌增喜慶，翁嫗最矜憐。", "已過周天歲，行臨志學年。", "勉修愚魯質，詩禮稱家傳。"]'),
('7e861c67-d3b1-44ee-a3aa-a32b93401944','孟甲孟乙好蓄古錢因示以詩','王十朋','宋','宋诗','song-poetry','','[]','世人多好錢，今汝獨好古。',120,'全唐诗/poet.song.118000.json','["世人多好錢，今汝獨好古。", "書中閲平準，壁上按圖譜。", "廣拾漢五銖，遠及周九府。", "惜哉生我家，此物罕曾覩。", "百中時得一，喜笑見眉宇。", "所蓄雖不多，其志頗可取。", "閭閻富家子，繞床堆阿堵。", "一字不識丁，碌碌何足數。", "更宜移此力，典墳讀三五。", "縱未到聖賢，定可過乃父。"]'),
('7661bfc1-5dac-424b-a4d2-5d48b400f08d','周光宗贈蠣房報以溪蒓','王十朋','宋','宋诗','song-poetry','','[]','珠嶼蠣房魁海錯，左原蒓線冠溪毛。',64,'全唐诗/poet.song.118000.json','["珠嶼蠣房魁海錯，左原蒓線冠溪毛。", "韓公南食可曾見，張翰東歸徒自高。", "鼎俎珍庖輸肉食，江湖佳味屬吾曹。", "有無相易通家事，僮僕往來毋憚勞。"]'),
('7c70f6bb-acb6-4e0f-adb8-1896502e05dc','劉府君挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','歆向詵然萃一門，過庭詩禮盡公恩。',64,'全唐诗/poet.song.118000.json','["歆向詵然萃一門，過庭詩禮盡公恩。", "奇兒不負義方教，舊治至今遺愛存。", "心境欲明憑貝葉，壽藏預卜傍祇園。", "髯郎行燭青藜杖，定見榮光達九泉。"]'),
('8b62491f-6c5a-4b9b-948c-6f54a76b728d','劉府君挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','賤子無天釁早鍾，記觀先友涕亡從。',64,'全唐诗/poet.song.118000.json','["賤子無天釁早鍾，記觀先友涕亡從。", "士林方喜榮三桂，丞舍俄驚慘二松。", "剡水凄凉回棹速，丹丘慟哭過車凶。", "發揚門戶勝他族，深羨公家有蔡邕。"]'),
('de4def60-abc8-45b6-807b-25d6442fe874','賈府君挽詞','王十朋','宋','宋诗','song-poetry','','[]','鹿巖重見鹿門翁，襟宇渾然太古風。',64,'全唐诗/poet.song.118000.json','["鹿巖重見鹿門翁，襟宇渾然太古風。", "負郭良田全種德，起家難弟已收功。", "花間麟冢經年就，木杪龜趺指日豐。", "門婿自慚非李漢，鄙文何足狀韓公。"]'),
('b9580714-c381-4d27-aafc-a149812b357b','陳夫人挽詞','王十朋','宋','宋诗','song-poetry','','[]','偉節聲名蓋一時，夫人淑德最相宜。',64,'全唐诗/poet.song.118000.json','["偉節聲名蓋一時，夫人淑德最相宜。", "便甘布素從高隠，不惜花鈿拯衆饑。", "萱草未乾堂下土，楊花已應夢中詩。", "如今多少王孫餓，進食哀憐復有誰。"]'),
('b2a40dc3-0c45-473a-8876-958afca9752d','納凉偶成','王十朋','宋','宋诗','song-poetry','','[]','架松却煩暑，梳竹來清風。',48,'全唐诗/poet.song.118000.json','["架松却煩暑，梳竹來清風。", "頑然七尺軀，寄此微凉中。", "高枕傲有道，深杯醉無功。", "山林有餘樂，此興誰吾同。"]'),
('5ff9860f-9cc4-4818-b8bb-b97846975c28','悼演述二老僧','王十朋','宋','宋诗','song-poetry','','[]','疊石峯前二老僧，相逢一笑見真情。',64,'全唐诗/poet.song.118000.json','["疊石峯前二老僧，相逢一笑見真情。", "社中對酒日初永，林下圍碁秋始清。", "尚擬維摩眠丈室，遽驚圓澤厭浮生。", "通幽亭冷西樓古，過客傷心涕淚橫。"]'),
('272d046e-c5b5-4715-ba8f-2316434bbb17','黄楊','王十朋','宋','宋诗','song-poetry','','[]','嘉彼黄楊，鬰焉其蒼。',80,'全唐诗/poet.song.118000.json','["嘉彼黄楊，鬰焉其蒼。", "匪甕而圓，匪蓋而張。", "百幹同根，森如弟昆。", "千枝其子，萬葉其孫。", "惟此黄楊，先子所植。", "草木有義，先子之德。", "願言我家，兄弟子孫。", "如此嘉樹，永爲義門。"]'),
('66d2d60b-c4e7-4795-a2b0-1379c057c3f0','林下十二子詩 竹子脩','王十朋','宋','宋诗','song-poetry','','[]','萬木蕭踈怯歲寒，子脩相見喜平安。',32,'全唐诗/poet.song.118000.json','["萬木蕭踈怯歲寒，子脩相見喜平安。", "世間寧有揚州鶴，休訝平生肉食難。"]'),
('918d14c5-587c-4cd0-a66d-63a909f48c54','林下十二子詩 井子深','王十朋','宋','宋诗','song-poetry','','[]','席量泓泓井子深，客來車轄總能沉。',32,'全唐诗/poet.song.118000.json','["席量泓泓井子深，客來車轄總能沉。", "定須再築新亭覆，不負先君好事心。"]'),
('e316e7b1-474e-4add-8cef-a607e803bb0a','林下十二子詩 梅子先','王十朋','宋','宋诗','song-poetry','','[]','竹外溪頭手自栽，群芳推讓子先開。',32,'全唐诗/poet.song.118000.json','["竹外溪頭手自栽，群芳推讓子先開。", "好將正味調金鼎，莫似櫻桃太不才。"]'),
('17346b91-e2c3-4427-a54e-af89145948d7','林下十二子詩 桂子蒼','王十朋','宋','宋诗','song-poetry','','[]','學仙深愧似吳郎，頼有吾廬兩子蒼。',32,'全唐诗/poet.song.118000.json','["學仙深愧似吳郎，頼有吾廬兩子蒼。", "疑是廣寒宮裏種，一秋三度送天香。"]'),
('0b47720b-f4dc-49f0-8b76-efd7a12da452','林下十二子詩 蘭子芳','王十朋','宋','宋诗','song-poetry','','[]','國香入鼻忽揚揚，知是光風泛子芳。',32,'全唐诗/poet.song.118000.json','["國香入鼻忽揚揚，知是光風泛子芳。", "林下自全幽靜操，縱無人採亦何傷。"]'),
('5203e04b-e3e7-4a1d-85c0-f37cefb8637d','林下十二子詩 昌陽子仙','王十朋','宋','宋诗','song-poetry','','[]','天上星郎字子仙，結根拳石傍清泉。',32,'全唐诗/poet.song.118000.json','["天上星郎字子仙，結根拳石傍清泉。", "豨苓方入醫師手，誰識仙姿解引年。"]'),
('3c474aeb-8801-4cde-b100-b367e8083e9e','林下十二子詩 黄子嘉','王十朋','宋','宋诗','song-poetry','','[]','保綠軒前黄子嘉，非松非柏亦非花。',32,'全唐诗/poet.song.118000.json','["保綠軒前黄子嘉，非松非柏亦非花。", "故應喚作思人樹，數十年前閲我家。"]'),
('4459fa88-348b-4eec-974f-2633b0f2e9d6','林下十二子詩 丁子素','王十朋','宋','宋诗','song-poetry','','[]','雨底含愁雪裏芳，琉璃葉映小何郎。',32,'全唐诗/poet.song.118000.json','["雨底含愁雪裏芳，琉璃葉映小何郎。", "世人競重熏籠錦，子素何曾怯瑞香。"]'),
('9312fe91-5a90-4309-bf84-631f1834cb7f','林下十二子詩 柳子春','王十朋','宋','宋诗','song-poetry','','[]','夾道青青柳子春，自從栽植幾番新。',32,'全唐诗/poet.song.118000.json','["夾道青青柳子春，自從栽植幾番新。", "如今已作參天樹，應笑衰遲老主人。"]'),
('67b2ed1b-6e0b-48f3-ac28-2d9bfc80e9b4','林下十二子詩 槐子夏','王十朋','宋','宋诗','song-poetry','','[]','方苦炎炎畏日長，欣蒙子夏惠清凉。',32,'全唐诗/poet.song.118000.json','["方苦炎炎畏日長，欣蒙子夏惠清凉。", "三槐雅是王家物，爲榜新亭擬舊堂。"]'),
('b5beef42-724d-42ed-abd0-22823012529f','林下十二子詩 菊子秀','王十朋','宋','宋诗','song-poetry','','[]','子秀霜中色更嘉，金錢粲粲滿庭階。',32,'全唐诗/poet.song.118000.json','["子秀霜中色更嘉，金錢粲粲滿庭階。", "淵明異日開三徑，端仗茲花慰老懷。"]'),
('942f9686-1006-44a1-a048-7f9be9698747','林下十二子詩 王子野','王十朋','宋','宋诗','song-poetry','','[]','場屋虛名且罷休，歸來聊效晉人游。',32,'全唐诗/poet.song.118000.json','["場屋虛名且罷休，歸來聊效晉人游。", "林間諸子總非俗，肯與野人爲友不。"]'),
('9bbc120e-f167-4d7a-a005-c79def6137cf','昌齡闢圃植花索詩於老者戲作數語兼簡夢齡','王十朋','宋','宋诗','song-poetry','','[]','東園小小花木稀，西園廓廓規模奇。',64,'全唐诗/poet.song.118000.json','["東園小小花木稀，西園廓廓規模奇。", "西園主人但置酒，東園老人甘賦詩。", "朝游西園飲千斛，莫向東園吟百幅。", "更約南園好事人，酒盞詩篇日相續。"]'),
('77b03b89-933a-4baf-b554-457b5a46a2b2','西園新闢昌齡索詩予以其未開尊也戲作數語既飲復用前韻','王十朋','宋','宋诗','song-poetry','','[]','阿連好事由來稀，開軒闢圃幽更奇。',64,'全唐诗/poet.song.118000.json','["阿連好事由來稀，開軒闢圃幽更奇。", "峯巒羅列富遐覽，氣象收拾歸新詩。", "百挺琅玕花數斛，宛似輞川圖一幅。", "朝莫過從有弟兄，長願歌聲無斷續。"]'),
('069bb4f2-2a33-4db3-8df7-b995d61b96cf','予與二弟連日賦詩飲酒詩成命二子書之亦居家之一樂也復用前韻','王十朋','宋','宋诗','song-poetry','','[]','不愁地闢車馬稀，自喜兄弟俱好奇。',64,'全唐诗/poet.song.118000.json','["不愁地闢車馬稀，自喜兄弟俱好奇。", "阿連舉觴勸我酒，阿買研墨書翁詩。", "長泛鄭生船百斛，日賦鄴侯三四幅。", "何用身封萬戶侯，但願青箱有人續。"]');
